    #[test]
    fn lessons_prompt_injection_is_capped_under_budget_with_elision_note() {
        // sdet-u1gap17-lessons-cap-render-untested / Gap 17 / spec 07 line 36: the lessons
        // half of this unit's charter had ZERO render coverage, which is exactly why a dead
        // recovery note shipped past all three tiers. This pins the whole rendered contract:
        // the header, freshest-first recency, the byte cap firing on a pile of chunky
        // lessons, and ONE visible elision note naming the elided count and the honest
        // `rigger peers <file>` recovery (now backed by sidecar::lessons_for). The store
        // keeps the full history - only the prompt slice narrows.
        let seed = vec!["conductor.rs".to_string()];
        // K chunky lessons, oldest (l000) first; recency grows with i, so l{K-1} is newest.
        const K: usize = 200;
        let lessons: Vec<(String, String)> = (0..K)
            .map(|i| {
                (
                    format!("l{i:03}"),
                    format!("LESSON_MARKER_{i} {}", "w".repeat(2400)),
                )
            })
            .collect();
        let borrowed: Vec<(&str, String)> = lessons
            .iter()
            .map(|(id, s)| (id.as_str(), s.clone()))
            .collect();
        let out = render_capped_lessons(&borrowed, &seed);

        // The section renders under its own header.
        assert!(
            out.contains("Lessons already learned about these files"),
            "the lessons section must render its header; output was:\n{}",
            &out[..out.len().min(400)]
        );
        // Uncapped, the lessons section alone would be ~500KB; the cap holds it under its
        // per-section budget (plus slack for the header and the elision note line).
        assert!(
            out.len() < LESSONS_BUDGET_BYTES + 2 * 1024,
            "capped lessons section must stay under its byte budget; len={}",
            out.len()
        );
        // Freshest-first: the newest survives verbatim, the oldest is elided (kept in store).
        assert!(
            out.contains("LESSON_MARKER_199 "),
            "the newest lesson must be kept verbatim"
        );
        assert!(
            !out.contains("LESSON_MARKER_0 "),
            "the oldest lesson must be elided from the prompt (it stays in the store)"
        );
        // The trim is VISIBLE: one elision note naming the elided count and the honest
        // `rigger peers <file>` recovery command.
        let verbatim = (0..K)
            .filter(|i| out.contains(&format!("LESSON_MARKER_{i} ")))
            .count();
        assert!(
            verbatim >= 1,
            "at least one lesson must still render verbatim; got {verbatim}"
        );
        let elided = K - verbatim;
        assert!(
            out.contains(&format!("+{elided} older lesson")),
            "the elision note must name the elided lesson count ({elided})"
        );
        assert!(
            out.contains("rigger peers conductor.rs"),
            "the elision note must name the `rigger peers <file>` recovery command \
             (backed by sidecar::lessons_for so it is not a dead promise)"
        );
    }

    #[test]
    fn the_verbatim_count_cap_binds_on_many_small_lessons() {
        // sdet-u1gap17-lessons-cap-render-untested (N arm): with many TINY lessons the byte
        // budget never binds, so this isolates the recent-N arm - exactly LESSONS_VERBATIM_N
        // are kept, asserted against that FIXED count so a regression ballooning
        // LESSONS_VERBATIM_N (bytes never bind) renders all of them and fails. Also pins the
        // freshest-first ordering: the newest lesson outranks an older one in the slice.
        let seed = vec!["conductor.rs".to_string()];
        let total = LESSONS_VERBATIM_N + 8;
        let lessons: Vec<(String, String)> = (0..total)
            .map(|i| (format!("small{i:03}"), format!("tiny lesson {i}")))
            .collect();
        let borrowed: Vec<(&str, String)> = lessons
            .iter()
            .map(|(id, s)| (id.as_str(), s.clone()))
            .collect();
        let out = render_capped_lessons(&borrowed, &seed);
        let kept = (0..total)
            .filter(|i| out.contains(&format!("small{i:03}:")))
            .count();
        assert_eq!(
            kept, LESSONS_VERBATIM_N,
            "exactly N tiny lessons must be kept verbatim (the count cap binds, not bytes); \
             output was:\n{out}"
        );
        // Freshest-first: the newest (highest index) survives, the oldest (small000) elides.
        assert!(
            out.contains(&format!("small{:03}:", total - 1)),
            "the newest lesson must survive the N cap; output was:\n{out}"
        );
        assert!(
            !out.contains("small000:"),
            "the oldest lesson must be elided by the N cap; output was:\n{out}"
        );
        assert!(
            out.contains(&format!("+{} older lesson", total - LESSONS_VERBATIM_N)),
            "the elision note must name the count the N cap trims; output was:\n{out}"
        );
    }

    // Build a lessons subgraph where each lesson carries its OWN `about` scope (not the
    // uniform seed), applied in order so position grows (older first), then render the
    // capped-lessons section for `seed`. Lets a test vary blast-radius RELEVANCE (how much
    // a lesson's trigger scope overlaps the grounded seed) independently of recency.
    fn render_capped_lessons_scoped(
        lessons: &[(&str, &str, Vec<&str>)],
        seed: &[String],
    ) -> String {
        let graph = crate::contextgraph::sqlite::Projector::open(":memory:", "test").unwrap();
        for (i, (id, summary, about)) in lessons.iter().enumerate() {
            let mut e = Event::new(
                contextgraph::TYPE_LESSON_LEARNED,
                serde_json::to_vec(&json!({
                    "id": id,
                    "summary": summary,
                    "about": about,
                }))
                .unwrap(),
            );
            e.position = (i as u64) + 1;
            graph.apply(&e).unwrap();
        }
        let g = graph.subgraph(seed, 2).unwrap();
        let mut b = String::new();
        write_capped_lessons(&mut b, &g, seed);
        b
    }

    #[test]
    fn lessons_rank_by_blast_radius_relevance_over_pure_recency() {
        // spec 13b unit 2 / d13b-u2-injection-relevance-seam: the lessons slice ranks by
        // blast-radius RELEVANCE (overlap of the lesson's trigger scope with the agent's
        // grounded seed files), with recency the deterministic tie-break - REPLACING the
        // pure-recency order the decisions/findings sections keep. A lesson whose scope
        // covers MORE of the seed must outrank a NEWER lesson whose scope barely overlaps,
        // and among equal-relevance lessons the newer still wins.
        let seed = vec!["a.rs".to_string(), "b.rs".to_string(), "c.rs".to_string()];
        let lessons: Vec<(&str, &str, Vec<&str>)> = vec![
            // Oldest, but covers ALL of the seed -> highest relevance (3).
            ("l_broad_old", "BROAD_MARK", vec!["a.rs", "b.rs", "c.rs"]),
            // Older shallow (relevance 1), newer than l_broad_old.
            ("l_shallow_old", "SHALLOW_OLD_MARK", vec!["a.rs"]),
            // Newest, but only overlaps ONE seed file -> low relevance (1).
            ("l_shallow_new", "SHALLOW_NEW_MARK", vec!["a.rs"]),
        ];
        let out = render_capped_lessons_scoped(&lessons, &seed);
        let pos = |m: &str| {
            out.find(m)
                .unwrap_or_else(|| panic!("{m} must render; output was:\n{out}"))
        };
        // Relevance beats recency: the OLDEST-but-broadest lesson outranks the newest.
        assert!(
            pos("BROAD_MARK") < pos("SHALLOW_NEW_MARK"),
            "the highest-relevance lesson must rank first even though it is the oldest; \
             output was:\n{out}"
        );
        assert!(
            pos("BROAD_MARK") < pos("SHALLOW_OLD_MARK"),
            "the highest-relevance lesson must outrank a shallower one; output was:\n{out}"
        );
        // Recency is the tie-break WITHIN equal relevance: both shallow lessons overlap the
        // seed once, so the newer (l_shallow_new) precedes the older (l_shallow_old).
        assert!(
            pos("SHALLOW_NEW_MARK") < pos("SHALLOW_OLD_MARK"),
            "within equal relevance the newer lesson must win the tie-break; output was:\n{out}"
        );
    }

    #[test]
    fn resume_skips_already_integrated_units() {
        let mut cfg = Config::default();
        cfg.agents.insert("a".into(), agent("a"));
        cfg.workflow.gates.insert("ok".into(), gate_def("true"));
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "a".into(),
                gates: vec!["ok".into()],
                ..Default::default()
            },
        );
        let st = Store::open(":memory:").unwrap();
        let driver = Stub::new();
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        run(&cfg, &deps).unwrap();
        run(&cfg, &deps).unwrap(); // resume on the same store
        let events = st
            .read_all(0, Direction::Forward, &Filter::default())
            .unwrap();
        let starts = events
            .iter()
            .filter(|e| {
                e.type_ == ledger::TYPE_UNIT_STARTED
                    && String::from_utf8_lossy(&e.data).contains("\"id\":\"s\"")
            })
            .count();
        assert_eq!(
            starts, 1,
            "a resumed run must not restart an integrated unit"
        );
    }

    /// Append events into the run stream as if a prior window had emitted them, so a
    /// resumed `run` folds them and continues from the recorded phase.
    fn seed_events_in_run(st: &Store, criteria: &[&str], events: &[Event]) {
        // Seed `events` as the prior-window state of a run started for `criteria` (spec
        // 06, unit 1 run scoping): a leading `RunStarted` so the conductor ADOPTS this
        // run when driven with the SAME criteria and folds the seeded state as its own
        // resume state, rather than minting a fresh run that leaves the seed behind the
        // boundary. `criteria` must match the `Deps::criteria` the test drives `run` with.
        let started = Event::new(
            crate::run::TYPE_RUN_STARTED,
            serde_json::to_vec(&json!({ "run": "test-run", "criteria": criteria })).unwrap(),
        );
        st.append(
            STREAM,
            ExpectedRevision::Any,
            std::slice::from_ref(&started),
        )
        .unwrap();
        st.append(STREAM, ExpectedRevision::Any, events).unwrap();
    }

    #[test]
    fn replay_trajectory_keeps_only_the_world_inputs_and_restrips_the_run_id() {
        // The trajectory is what the WORLD did - agent SpawnResults and gate GateVerdicts -
        // NOT the conductor-derived lifecycle (UnitStarted / UnitStatus / DecisionMade),
        // which the candidate config must re-derive. Order is preserved, the gate-verdict
        // replay key survives (so the re-drive replays the verdict), and the baseline run's
        // run-id stamp is stripped (the caller re-scopes under a fresh RunStarted).
        let spawn_result = Event::new(
            spawn::TYPE_SPAWN_RESULT,
            serde_json::to_vec(&json!({"id": "s/implementer#0", "output": "did it"})).unwrap(),
        )
        .with_meta(crate::run::META_RUN_ID, "old-run");
        let gate_verdict = Event::new(
            contextgraph::TYPE_GATE_VERDICT,
            serde_json::to_vec(&json!({"pass": true, "evidence": "PASS"})).unwrap(),
        )
        .with_meta(META_REPLAY_KEY, "s/gate:check#0")
        .with_meta(crate::run::META_RUN_ID, "old-run");
        let baseline = vec![
            Event::new(
                crate::run::TYPE_RUN_STARTED,
                serde_json::to_vec(&json!({"run": "old-run", "criteria": []})).unwrap(),
            ),
            Event::new(
                ledger::TYPE_UNIT_STARTED,
                serde_json::to_vec(&json!({"id": "s", "agent": "worker"})).unwrap(),
            ),
            spawn_result,
            Event::new(
                ledger::TYPE_UNIT_STATUS,
                serde_json::to_vec(&json!({"id": "s", "status": "green"})).unwrap(),
            ),
            gate_verdict,
            Event::new(
                contextgraph::TYPE_DECISION_MADE,
                serde_json::to_vec(&json!({"id": "d", "summary": "x"})).unwrap(),
            ),
        ];

        let traj = replay_trajectory(&baseline);
        assert_eq!(
            traj.iter().map(|e| e.type_.as_str()).collect::<Vec<_>>(),
            [spawn::TYPE_SPAWN_RESULT, contextgraph::TYPE_GATE_VERDICT],
            "only the world inputs survive, in order - no derived lifecycle event"
        );
        assert!(
            traj.iter()
                .all(|e| !e.meta.contains_key(crate::run::META_RUN_ID)),
            "the baseline run-id stamp is stripped so the caller re-scopes freely"
        );
        assert_eq!(
            traj[1].meta.get(META_REPLAY_KEY).map(String::as_str),
            Some("s/gate:check#0"),
            "the gate-verdict replay key survives so the re-drive replays the verdict"
        );
    }

    /// Commit a file on a unit's DETERMINISTIC branch exactly as a prior window would:
    /// create the branch via a worktree, write+commit the file, then remove the
    /// transient worktree dir (the branch ref survives as the durable checkpoint).
    fn commit_on_unit_branch(repo: &str, unit_id: &str, file: &str, content: &str) {
        let branch = unit_branch(unit_id);
        let dir = std::env::temp_dir().join(format!(
            "rigger-seed-{}-{}",
            sanitize_for_path(unit_id),
            &uuid::Uuid::new_v4().to_string()[..8]
        ));
        let wt = crate::worktree::Worktree::create(repo, dir.to_str().unwrap(), &branch).unwrap();
        std::fs::write(Path::new(&wt.dir).join(file), content).unwrap();
        let committed = wt.commit("rigger: prior window work").unwrap();
        assert!(!committed.is_empty(), "the prior window must commit work");
        wt.remove().unwrap();
        assert!(
            crate::worktree::Worktree::branch_has_work(repo, &branch),
            "the seeded branch must carry committed work"
        );
    }

    #[test]
    fn resume_reuses_a_units_branch_instead_of_reimplementing() {
        // Resume-continuity: a unit recorded at `verified` in a prior window, with its
        // deterministic branch carrying committed work, must NOT re-run the
        // implementer on resume. It picks the lifecycle up at gates + the three-tier
        // review on the committed code and integrates - building on the prior window's
        // work rather than throwing it away under a per-run-uuid branch.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();

        // The prior window implemented unit `s` and committed it on the deterministic
        // branch, reaching `verified` (gates passed) but not yet approved+merged.
        commit_on_unit_branch(&repo_path, "s", "feature.rs", "fn feature() {}\n");

        let st = Store::open(":memory:").unwrap();
        seed_events_in_run(
            &st,
            &[],
            &[
                Event::new(
                    ledger::TYPE_UNIT_STARTED,
                    serde_json::to_vec(
                        &json!({"id": "s", "agent": "worker", "branch": unit_branch("s")}),
                    )
                    .unwrap(),
                ),
                Event::new(
                    ledger::TYPE_UNIT_STATUS,
                    serde_json::to_vec(&json!({"id": "s", "status": "green"})).unwrap(),
                ),
                Event::new(
                    ledger::TYPE_UNIT_STATUS,
                    serde_json::to_vec(&json!({"id": "s", "status": "verified"})).unwrap(),
                ),
            ],
        );

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("lens".into(), agent("lens"));
        cfg.agents.insert("judge".into(), agent("judge"));
        cfg.workflow.gates.insert("ok".into(), gate_def("true"));
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                gates: vec!["ok".into()],
                on_pass: "merge".into(),
                review: crate::config::ReviewPanel {
                    lenses: vec!["lens".into()],
                    adjudicator: "judge".into(),
                    ..Default::default()
                },
                ..Default::default()
            },
        );

        // The adjudicator approves; the unit must integrate via review, not implement.
        // The lens returns a substantive (non-degenerate) review so it does not trip the
        // Gap-18 respawn loop.
        let driver = Stub {
            output_by_agent: HashMap::from([
                ("judge".to_string(), r#"{"verdict":"approve"}"#.to_string()),
                ("lens".to_string(), "reviewed: no blocker".to_string()),
            ]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path,
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        assert!(
            !driver.spawned("worker"),
            "the implementer must NOT be re-spawned on resume - the prior window's branch is reused"
        );
        assert!(
            driver.spawned("judge"),
            "the resumed unit must still proceed through the three-tier review"
        );
        assert_eq!(
            rs.units["s"].status,
            ledger::Status::Integrated,
            "the resumed unit must integrate, building on the reused branch"
        );
        assert!(
            repo.path().join("feature.rs").exists(),
            "the prior window's committed file must land in the base on resume-integrate"
        );
    }

    #[test]
    fn branch_gc_reclaims_integrated_units_and_retains_escalated_ones_on_resume() {
        // Spec 38, criterion 1: branch-GC is a PROJECTION over the log, so a resume
        // re-reaches the same end state. A unit that reached `integrated` in a PRIOR
        // window is seeded into `integrated` at run start and never re-enters
        // `run_stage` (its worktree is gone, its work merged) - so the inline
        // post-integrate delete never fires for it. Without the resume-time reclaim its
        // `rigger/u/<unit>` branch survives forever (the "15 accumulated" debris the
        // spec corrects). An ESCALATED unit is NOT integrated: the human needs its
        // branch as evidence, so it is RETAINED. Re-folding the same integration on a
        // second resume, with the branch already gone, is a no-op (idempotent).
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();

        // Two prior-window units, each with a durable branch carrying committed work:
        // `landed` reached integrated; `stuck` escalated at the retry bound.
        commit_on_unit_branch(&repo_path, "landed", "landed.rs", "fn landed() {}\n");
        commit_on_unit_branch(&repo_path, "stuck", "stuck.rs", "fn stuck() {}\n");
        assert!(
            branch_present(&repo_path, &unit_branch("landed")),
            "precondition: the integrated unit's branch exists before the run"
        );
        assert!(
            branch_present(&repo_path, &unit_branch("stuck")),
            "precondition: the escalated unit's branch exists before the run"
        );

        let st = Store::open(":memory:").unwrap();
        seed_events_in_run(
            &st,
            &[],
            &[
                Event::new(
                    ledger::TYPE_UNIT_STARTED,
                    serde_json::to_vec(
                        &json!({"id": "landed", "agent": "worker", "branch": unit_branch("landed")}),
                    )
                    .unwrap(),
                ),
                Event::new(
                    ledger::TYPE_UNIT_INTEGRATED,
                    serde_json::to_vec(&json!({"id": "landed", "commit": "abc123"})).unwrap(),
                ),
                Event::new(
                    ledger::TYPE_UNIT_STARTED,
                    serde_json::to_vec(
                        &json!({"id": "stuck", "agent": "worker", "branch": unit_branch("stuck")}),
                    )
                    .unwrap(),
                ),
                Event::new(
                    ledger::TYPE_UNIT_ESCALATED,
                    serde_json::to_vec(&json!({"id": "stuck"})).unwrap(),
                ),
            ],
        );

        let cfg = Config::default();
        let driver = Stub::new();
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        // The projection agrees on the terminal states the sweep keys off.
        assert_eq!(rs.units["landed"].status, ledger::Status::Integrated);
        assert_eq!(rs.units["stuck"].status, ledger::Status::Escalated);

        assert!(
            !branch_present(&repo_path, &unit_branch("landed")),
            "the integrated unit's per-unit branch must be reclaimed on resume"
        );
        assert!(
            branch_present(&repo_path, &unit_branch("stuck")),
            "the escalated unit's branch must be RETAINED as the human's evidence"
        );

        // Idempotent on a further resume-by-replay: re-folding the same integration
        // whose branch is already gone is a no-op, never an error.
        let rs2 = run(&cfg, &deps).unwrap();
        assert_eq!(rs2.units["landed"].status, ledger::Status::Integrated);
        assert!(
            !branch_present(&repo_path, &unit_branch("landed")),
            "the reclaimed branch stays gone (idempotent)"
        );
        assert!(
            branch_present(&repo_path, &unit_branch("stuck")),
            "the escalated unit's branch is still retained on the second resume"
        );
    }

    /// Commit throwaway work on an ARBITRARY branch name (periphery seed helper). The
    /// sibling `commit_on_unit_branch` only ever commits on the CANONICAL
    /// `unit_branch(id)`, so it cannot stage a unit whose RECORDED branch differs from
    /// that derivation; this stages exactly that case for the recorded-branch-preference
    /// boundary below. Mirrors `commit_on_unit_branch`: a one-file worktree, committed and
    /// immediately removed, leaving the branch carrying real work.
    fn commit_on_named_branch(repo: &str, branch: &str, file: &str, content: &str) {
        let dir = std::env::temp_dir().join(format!(
            "rigger-seed-{}-{}",
            sanitize_for_path(branch),
            &uuid::Uuid::new_v4().to_string()[..8]
        ));
        let wt = crate::worktree::Worktree::create(repo, dir.to_str().unwrap(), branch).unwrap();
        std::fs::write(Path::new(&wt.dir).join(file), content).unwrap();
        let committed = wt.commit("rigger: prior window work").unwrap();
        assert!(!committed.is_empty(), "the prior window must commit work");
        wt.remove().unwrap();
        assert!(
            crate::worktree::Worktree::branch_has_work(repo, branch),
            "the seeded branch must carry committed work"
        );
    }

    // Periphery layer (SDET), spec 38 criterion 1: the inside-out test
    // `branch_gc_reclaims_integrated_units_and_retains_escalated_ones_on_resume` proves
    // the happy path of the ONE cross-module seam this unit adds - `run` at resume folds
    // the prior log and calls `gc_integrated_branches`, which projects
    // `ledger::RunState` and drives `Worktree::delete_branch` per Integrated unit. That
    // seam's branch-name resolution has two arms:
    //   let branch = if u.branch.is_empty() { unit_branch(&u.id) } else { u.branch.clone() };
    // The unit test only ever seeds `branch == unit_branch(id)` (non-empty AND equal to
    // the derivation), so it exercises neither the `is_empty()` FALLBACK arm nor the
    // RECORDED-vs-derived distinction. The two tests below drive the same public `run`
    // seam and pin those two boundary edges the inside-out layer is structurally blind to.

    #[test]
    fn branch_gc_falls_back_to_the_derived_branch_when_unitstarted_recorded_no_branch() {
        // Edge: an integrated unit whose `UnitStarted` carried NO `branch` field. The
        // fold defaults `u.branch` to empty (serde default on `UnitStarted::branch`), so
        // the sweep's `u.branch.is_empty()` arm must reclaim it by the DERIVED name.
        // Without that arm such a unit's `rigger/u/<unit>` branch accumulates forever -
        // the very debris spec 38 corrects - and the unit test never reaches it.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();

        // The prior window committed `orphan` on its canonical branch; the seeded
        // `UnitStarted` omits `branch`, so only the DERIVED name can reclaim it.
        commit_on_unit_branch(&repo_path, "orphan", "orphan.rs", "fn orphan() {}\n");
        assert!(
            branch_present(&repo_path, &unit_branch("orphan")),
            "precondition: the integrated unit's derived branch exists before the run"
        );

        let st = Store::open(":memory:").unwrap();
        seed_events_in_run(
            &st,
            &[],
            &[
                // No `branch` field -> the fold leaves `u.branch` empty (serde default).
                Event::new(
                    ledger::TYPE_UNIT_STARTED,
                    serde_json::to_vec(&json!({"id": "orphan", "agent": "worker"})).unwrap(),
                ),
                Event::new(
                    ledger::TYPE_UNIT_INTEGRATED,
                    serde_json::to_vec(&json!({"id": "orphan", "commit": "def456"})).unwrap(),
                ),
            ],
        );

        let cfg = Config::default();
        let driver = Stub::new();
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        assert_eq!(rs.units["orphan"].status, ledger::Status::Integrated);
        assert!(
            rs.units["orphan"].branch.is_empty(),
            "fold precondition: no recorded branch, so only the derivation can reclaim it"
        );
        assert!(
            !branch_present(&repo_path, &unit_branch("orphan")),
            "an integrated unit whose UnitStarted recorded no branch is reclaimed via the DERIVED name"
        );
    }

    #[test]
    fn branch_gc_reclaims_the_recorded_branch_not_the_derived_name_when_they_differ() {
        // Edge: an integrated unit whose RECORDED branch differs from today's
        // `unit_branch(id)` derivation. The sweep PREFERS the recorded value
        // (`else { u.branch.clone() }`); a "simplification" to always derive
        // `unit_branch(&u.id)` would pass the unit test (there recorded == derived) yet
        // strand every unit recorded under an older naming scheme - the back-compat
        // vector. A canonical-name decoy proves the sweep reclaims the RECORDED ref and
        // leaves the derivation untouched.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();

        let recorded = "rigger/u/relic-legacy-scheme";
        assert_ne!(
            recorded,
            unit_branch("relic"),
            "the recorded branch must DIFFER from the derivation for this test to discriminate"
        );

        commit_on_named_branch(&repo_path, recorded, "relic.rs", "fn relic() {}\n");
        commit_on_unit_branch(&repo_path, "relic", "decoy.rs", "fn decoy() {}\n");
        assert!(branch_present(&repo_path, recorded));
        assert!(branch_present(&repo_path, &unit_branch("relic")));

        let st = Store::open(":memory:").unwrap();
        seed_events_in_run(
            &st,
            &[],
            &[
                Event::new(
                    ledger::TYPE_UNIT_STARTED,
                    serde_json::to_vec(
                        &json!({"id": "relic", "agent": "worker", "branch": recorded}),
                    )
                    .unwrap(),
                ),
                Event::new(
                    ledger::TYPE_UNIT_INTEGRATED,
                    serde_json::to_vec(&json!({"id": "relic", "commit": "aaa111"})).unwrap(),
                ),
            ],
        );

        let cfg = Config::default();
        let driver = Stub::new();
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        assert_eq!(rs.units["relic"].status, ledger::Status::Integrated);
        assert_eq!(rs.units["relic"].branch, recorded);
        assert!(
            !branch_present(&repo_path, recorded),
            "the sweep must reclaim the unit's RECORDED branch"
        );
        assert!(
            branch_present(&repo_path, &unit_branch("relic")),
            "the canonical-derived branch is a different ref and must be left untouched"
        );
    }

    /// Build a single implement+review stage `s` (worker implements, one lens, one
    /// adjudicator), returning the config. The adjudicator's canned verdict is `verdict`.
    fn sha_stamp_cfg() -> Config {
        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("lens".into(), agent("lens"));
        cfg.agents.insert("judge".into(), agent("judge"));
        cfg.workflow.gates.insert("ok".into(), gate_def("true"));
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                gates: vec!["ok".into()],
                on_pass: "merge".into(),
                review: crate::config::ReviewPanel {
                    lenses: vec!["lens".into()],
                    adjudicator: "judge".into(),
                    ..Default::default()
                },
                ..Default::default()
            },
        );
        cfg
    }

    #[test]
    fn review_boundary_events_carry_the_worktree_sha() {
        // spec 11, unit 1: the `verified` and `reviewed` review-boundary statuses carry the
        // reviewed worktree HEAD sha as metadata (mirroring the commit UnitIntegrated
        // carries), so the flip-flop fold can tell a verdict reversal on the SAME code from
        // a legitimate remediation on new code.
        let repo = init_repo();
        let cfg = sha_stamp_cfg();
        let st = Store::open(":memory:").unwrap();
        let driver = Stub {
            write_file: Some("feature.rs".into()),
            output_by_agent: HashMap::from([
                ("judge".to_string(), r#"{"verdict":"approve"}"#.to_string()),
                ("lens".to_string(), "reviewed: no blocker".to_string()),
            ]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo.path().to_str().unwrap().to_string(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        run(&cfg, &deps).unwrap();

        let events = st.read_stream(STREAM, 0, Direction::Forward).unwrap();
        let sha_of = |status: &str| -> Option<String> {
            events
                .iter()
                .find(|e| {
                    e.type_ == ledger::TYPE_UNIT_STATUS
                        && String::from_utf8_lossy(&e.data)
                            .contains(&format!("\"status\":\"{status}\""))
                })
                .and_then(|e| e.meta.get(META_WORKTREE_SHA).cloned())
        };
        let verified_sha = sha_of("verified").expect("verified carries a worktree sha");
        let reviewed_sha = sha_of("reviewed").expect("reviewed carries a worktree sha");
        assert_eq!(
            verified_sha.len(),
            40,
            "the stamp is a full git sha: {verified_sha:?}"
        );
        assert!(verified_sha.chars().all(|c| c.is_ascii_hexdigit()));
        // Both boundary events stamp the SAME committed tree the tiers judged this attempt.
        assert_eq!(
            verified_sha, reviewed_sha,
            "verified and reviewed must stamp the same reviewed sha"
        );
    }

    #[test]
    fn a_review_reject_unitfailed_carries_the_worktree_sha() {
        // spec 11, unit 1: the review-reject `UnitFailed` also carries the reviewed sha, so
        // the fold can pair a reject with a later approve on the same sha.
        let repo = init_repo();
        let cfg = sha_stamp_cfg();
        let st = Store::open(":memory:").unwrap();
        // The adjudicator rejects every attempt, so the unit fails (and eventually
        // escalates); each review-reject UnitFailed must carry the sha.
        let driver = Stub {
            write_file: Some("feature.rs".into()),
            output_by_agent: HashMap::from([
                ("judge".to_string(), r#"{"verdict":"reject"}"#.to_string()),
                (
                    "lens".to_string(),
                    "reviewed: a blocker remains".to_string(),
                ),
            ]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo.path().to_str().unwrap().to_string(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        run(&cfg, &deps).unwrap();

        let events = st.read_stream(STREAM, 0, Direction::Forward).unwrap();
        let reject_with_sha = events.iter().find(|e| {
            e.type_ == ledger::TYPE_UNIT_FAILED
                && e.meta
                    .get(META_WORKTREE_SHA)
                    .is_some_and(|s| s.len() == 40 && s.chars().all(|c| c.is_ascii_hexdigit()))
        });
        assert!(
            reject_with_sha.is_some(),
            "a review-reject UnitFailed must carry the reviewed worktree sha"
        );
    }

    #[test]
    fn stamps_the_model_alias_and_resolved_id_on_live_lifecycle_events() {
        // spec 05 line 52, the LIVE (non-replay) path: the conductor copies the resolved
        // model each spawn returns on `AgentResult::resolved_model` - independent of the
        // driver - onto the unit events it records for that spawn, alongside the requested
        // alias. This exercises the adjudicator/`reviewed` path the replay-driver test does
        // not, and proves the copy is not replay-specific.
        let store = Store::open(":memory:").unwrap();

        let mut cfg = Config::default();
        cfg.agents.insert(
            "worker".into(),
            AgentDef {
                id: "worker".into(),
                model: "sonnet".into(),
                ..Default::default()
            },
        );
        cfg.agents.insert(
            "lens".into(),
            AgentDef {
                id: "lens".into(),
                model: "haiku".into(),
                ..Default::default()
            },
        );
        cfg.agents.insert(
            "judge".into(),
            AgentDef {
                id: "judge".into(),
                model: "opus".into(),
                ..Default::default()
            },
        );
        cfg.workflow.stages.insert(
            "u".into(),
            Stage {
                name: "u".into(),
                agent: "worker".into(),
                // Repo-less: the review approves and then `on_pass: none` stops before
                // integrate, so no git repo is needed - `reviewed` is still emitted for the
                // adjudicator spawn.
                on_pass: "none".into(),
                review: crate::config::ReviewPanel {
                    lenses: vec!["lens".into()],
                    adjudicator: "judge".into(),
                    ..Default::default()
                },
                ..Default::default()
            },
        );

        // Each spawn reports the concrete model it ran as (what a worker records via
        // `rigger result --meta` on the stepwise path); the adjudicator approves.
        let driver = Stub {
            output_by_agent: HashMap::from([
                ("judge".to_string(), r#"{"verdict":"approve"}"#.to_string()),
                // A substantive lens result so it does not trip the Gap-18 respawn loop.
                ("lens".to_string(), "reviewed: no blocker".to_string()),
            ]),
            resolved_model_by_agent: HashMap::from([
                (
                    "worker".to_string(),
                    "claude-sonnet-4-5-20250101".to_string(),
                ),
                ("judge".to_string(), "claude-opus-4-8-20260101".to_string()),
            ]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        run(&cfg, &deps).unwrap();

        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        let status_meta = |want: &str, key: &str| -> Option<String> {
            events
                .iter()
                .find(|e| {
                    e.type_ == ledger::TYPE_UNIT_STATUS
                        && String::from_utf8_lossy(&e.data)
                            .contains(&format!("\"status\":\"{want}\""))
                })
                .and_then(|e| e.meta.get(key).cloned())
        };

        // The implementer spawn's green and verified events carry the worker's requested
        // alias and the resolved id it ran as.
        for st in ["green", "verified"] {
            assert_eq!(
                status_meta(st, META_MODEL_ALIAS).as_deref(),
                Some("sonnet"),
                "{st} carries the implementer's requested alias"
            );
            assert_eq!(
                status_meta(st, META_MODEL_RESOLVED).as_deref(),
                Some("claude-sonnet-4-5-20250101"),
                "{st} carries the implementer's resolved id"
            );
        }
        // The adjudicator spawn's reviewed event carries the judge's alias and resolved id.
        assert_eq!(
            status_meta("reviewed", META_MODEL_ALIAS).as_deref(),
            Some("opus"),
            "reviewed carries the adjudicator's requested alias"
        );
        assert_eq!(
            status_meta("reviewed", META_MODEL_RESOLVED).as_deref(),
            Some("claude-opus-4-8-20260101"),
            "reviewed carries the adjudicator's resolved id"
        );
        // UnitStarted carries the requested alias (known before any result).
        let started = events
            .iter()
            .find(|e| e.type_ == ledger::TYPE_UNIT_STARTED)
            .expect("the unit started");
        assert_eq!(
            started.meta.get(META_MODEL_ALIAS).map(String::as_str),
            Some("sonnet")
        );
    }

    /// Build a repo-less single stage with a lens + adjudicator review panel and
    /// `on_pass: none` (so the approved review folds and emits `reviewed` without needing
    /// a git repo to integrate into). The Gap-18 tests below drive its reviewers to
    /// degenerate (empty) results and assert the respawn/halt behavior.
    fn degenerate_reviewer_cfg() -> Config {
        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("sdet".into(), agent("sdet"));
        cfg.agents.insert("judge".into(), agent("judge"));
        cfg.workflow.stages.insert(
            "u".into(),
            Stage {
                name: "u".into(),
                agent: "worker".into(),
                on_pass: "none".into(),
                review: crate::config::ReviewPanel {
                    lenses: vec!["sdet".into()],
                    adjudicator: "judge".into(),
                    ..Default::default()
                },
                ..Default::default()
            },
        );
        cfg
    }

    fn has_status(events: &[Event], status: &str) -> bool {
        events.iter().any(|e| {
            e.type_ == ledger::TYPE_UNIT_STATUS
                && String::from_utf8_lossy(&e.data).contains(&format!("\"status\":\"{status}\""))
        })
    }

    #[test]
    fn a_degenerate_adjudicator_result_respawns_and_a_substantive_retry_folds_normally() {
        // Gap 18 (spec 07): a reviewer result that is empty/whitespace-only is an
        // INFRASTRUCTURE fault, not a verdict. The adjudicator's ORIGINAL spawn returns
        // whitespace-only; the conductor respawns it under the deterministic
        // `~retry1` id, and that substantive (approving) result folds NORMALLY.
        let store = Store::open(":memory:").unwrap();
        let cfg = degenerate_reviewer_cfg();
        let driver = Stub {
            output_by_spawn_id: HashMap::from([
                // Original adjudicator spawn: whitespace only -> degenerate, respawned.
                (spawn_id("u", ROLE_ADJUDICATOR, 0), "   \n\t  ".to_string()),
                // First respawn: a real approving verdict -> folds normally.
                (
                    spawn_retry_id("u", ROLE_ADJUDICATOR, 0, 1),
                    r#"{"verdict":"approve"}"#.to_string(),
                ),
            ]),
            // The lens returns a substantive review so only the ADJUDICATOR exercises the
            // degenerate-respawn path under test.
            output_by_agent: HashMap::from([("sdet".to_string(), "lens: no blocker".to_string())]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        run(&cfg, &deps).expect("a substantive retry folds the review normally");

        // The adjudicator was spawned exactly twice: the degenerate original + one retry.
        assert_eq!(
            driver.spawn_count("judge"),
            2,
            "the degenerate adjudicator is respawned exactly once before it returns a verdict"
        );
        // The respawn used the DETERMINISTIC retry-suffixed id, not a fresh/random one.
        let ids = driver.spawn_ids();
        assert!(
            ids.contains(&spawn_id("u", ROLE_ADJUDICATOR, 0)),
            "the original spawn keeps its plain id: {ids:?}"
        );
        assert!(
            ids.contains(&spawn_retry_id("u", ROLE_ADJUDICATOR, 0, 1)),
            "the respawn uses the deterministic ~retry1 id: {ids:?}"
        );

        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        // The substantive verdict folded: `reviewed` is emitted ONLY on an explicit approve.
        assert!(
            has_status(&events, "reviewed"),
            "the approving retry result folds into the review outcome (reviewed emitted)"
        );
        // The unit was NOT charged a remediation attempt: no UnitFailed, no UnitEscalated.
        assert!(
            !events.iter().any(|e| e.type_ == ledger::TYPE_UNIT_FAILED),
            "a degenerate-then-recovered review must not charge the unit an attempt"
        );
        assert!(
            !events
                .iter()
                .any(|e| e.type_ == ledger::TYPE_UNIT_ESCALATED),
            "a degenerate-then-recovered review must not escalate the unit"
        );
        // The implementer ran exactly once - no remediation re-implement.
        assert_eq!(driver.spawn_count("worker"), 1);
    }

    #[test]
    fn a_gating_spawn_that_emits_an_approve_verdict_but_returns_no_verdict_line_hard_errors_with_the_result_channel_fix(
    ) {
        // Spec 18, unit 3: the runtime verdict-channel mismatch backstop. A gating
        // adjudicator whose RESULT carries NO parseable verdict line, yet emitted an
        // approve-shaped verdict via rigger_emit DURING its spawn, mistook the event
        // channel for the gate. The gate reads ONLY the result channel, so folding the
        // empty verdict as a reject would remediate a unit the reviewer actually
        // approved. The conductor HARD-ERRORS with the result-channel fix message
        // instead of the silent reject-and-remediate loop (the diagnostic use of events:
        // events explain the failure, the result channel still decides).
        let store = Store::open(":memory:").unwrap();
        let cfg = degenerate_reviewer_cfg();
        let driver = Stub {
            output_by_agent: HashMap::from([
                // A substantive lens review, so only the ADJUDICATOR exercises the path.
                ("sdet".to_string(), "lens: no blocker".to_string()),
                // The adjudicator returns a NON-degenerate result (so it is NOT the Gap-18
                // empty-result path) that carries NO `{"verdict":...}` line - just prose.
                (
                    "judge".to_string(),
                    "I have reviewed the unit and it looks good to me.".to_string(),
                ),
            ]),
            // ...but the adjudicator recorded its approve-shaped verdict ONLY as an
            // emitted event (rigger_emit), never on its result output.
            emits_by_agent: HashMap::from([(
                "judge".to_string(),
                vec![(
                    contextgraph::TYPE_DECISION_MADE.to_string(),
                    json!({"id": "verdict", "verdict": "approve"}),
                )],
            )]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let err = match run(&cfg, &deps) {
            Ok(_) => panic!(
                "a gating spawn that emits approve but returns no verdict line must HARD-ERROR"
            ),
            Err(e) => e,
        };
        // The hard error names the SPEC-pinned result-channel fix.
        assert!(
            err.0
                .contains("the gate reads the result channel, not emitted events")
                && err.0.contains("end your output with the verdict line"),
            "the hard error carries the result-channel fix message: {err:?}"
        );
        // The internal recognition sentinel is stripped before it surfaces.
        assert!(
            !err.0.contains('\u{1}'),
            "the internal mismatch marker is stripped from the surfaced message: {err:?}"
        );

        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        // NOT folded as a reject and remediated: no attempt charged, no escalation, and
        // nothing approved (`reviewed` is emitted ONLY on a result-channel approve).
        assert!(
            !events.iter().any(|e| e.type_ == ledger::TYPE_UNIT_FAILED),
            "a verdict-channel mismatch must not charge the unit a remediation attempt"
        );
        assert!(
            !events
                .iter()
                .any(|e| e.type_ == ledger::TYPE_UNIT_ESCALATED),
            "a verdict-channel mismatch must not escalate the unit"
        );
        assert!(
            !has_status(&events, "reviewed"),
            "nothing was approved on the result channel, so no `reviewed` status is folded"
        );
        // The implementer ran exactly once - the mismatch halts rather than looping the
        // unit back through re-implement remediation.
        assert_eq!(
            driver.spawn_count("worker"),
            1,
            "the mismatch halts the run; the unit is not re-implemented"
        );
        // The adjudicator is NOT respawned: this is a substantive (non-degenerate) result,
        // distinct from the Gap-18 empty-result respawn path.
        assert_eq!(
            driver.spawn_count("judge"),
            1,
            "a non-degenerate result carrying an emit-only verdict is not respawned"
        );
    }

    #[test]
    fn a_gating_spawn_that_returns_a_reject_verdict_line_is_a_normal_reject_even_if_it_emitted_approve(
    ) {
        // The mismatch backstop fires ONLY when the result channel carries NO verdict at
        // all. A gating spawn that DID put a `{"verdict":"reject"}` line on its result
        // DECIDED on the result channel; an approve-shaped event emitted alongside it is
        // ignored (the result channel still decides), so this is an ordinary reject that
        // remediates, never the hard-error halt. This pins that `has_verdict_line` gates
        // the backstop, so a legitimate reject is never misread as a mismatch.
        let store = Store::open(":memory:").unwrap();
        let mut cfg = degenerate_reviewer_cfg();
        // One remediation attempt then escalate, so the reject loop terminates cheaply.
        cfg.workflow.defaults.max_retries = 1;
        let driver = Stub {
            output_by_agent: HashMap::from([
                ("sdet".to_string(), "lens: no blocker".to_string()),
                ("judge".to_string(), r#"{"verdict":"reject"}"#.to_string()),
            ]),
            emits_by_agent: HashMap::from([(
                "judge".to_string(),
                vec![(
                    contextgraph::TYPE_DECISION_MADE.to_string(),
                    json!({"id": "verdict", "verdict": "approve"}),
                )],
            )]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        // A reject that exhausts remediation escalates; `run` still returns Ok (the run
        // completed, the unit escalated), never the mismatch hard error.
        run(&cfg, &deps).expect("a result-channel reject is a normal reject, not a mismatch halt");
        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        assert!(
            events
                .iter()
                .any(|e| e.type_ == ledger::TYPE_UNIT_ESCALATED),
            "a result-channel reject remediates and escalates - it is not the mismatch halt"
        );
    }

    #[test]
    fn a_gating_spawn_with_no_verdict_line_and_no_emitted_approve_is_an_ordinary_reject() {
        // The backstop fires on the CONJUNCTION (no verdict line AND an emitted approve).
        // This pins the emitted_approve leg in ISOLATION (carry-forward
        // sdet-u18-3-emitted-approve-conjunct-untested): a non-degenerate result carrying
        // NO verdict line AND emitting NO approve is an ordinary empty verdict - the gate
        // reads no approval, so it folds as a reject and remediates, NEVER the hard-error
        // halt. Guards the store-sourced backstop from widening to fire on ANY missing
        // verdict line (which would misread a genuine empty-verdict reject as a mismatch).
        let store = Store::open(":memory:").unwrap();
        let mut cfg = degenerate_reviewer_cfg();
        // One remediation attempt then escalate, so the reject loop terminates cheaply.
        cfg.workflow.defaults.max_retries = 1;
        let driver = Stub {
            output_by_agent: HashMap::from([
                ("sdet".to_string(), "lens: no blocker".to_string()),
                // A non-degenerate result with NO parseable verdict line...
                (
                    "judge".to_string(),
                    "I have reviewed the unit and it looks good to me.".to_string(),
                ),
            ]),
            // ...and the adjudicator emitted NOTHING - no approve-shaped event - so the
            // mismatch conjunction is false: this is a plain empty-verdict reject.
            ..Stub::new()
        };
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        // No hard error: an empty verdict with no emitted approve remediates and escalates.
        run(&cfg, &deps)
            .expect("an empty verdict with no emitted approve is a normal reject, not a halt");
        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        assert!(
            events
                .iter()
                .any(|e| e.type_ == ledger::TYPE_UNIT_ESCALATED),
            "no emitted approve means an ordinary reject that remediates and escalates, not a halt"
        );
    }

    #[test]
    fn the_workflow_live_path_correlates_the_approve_by_stamp_not_a_bare_stream_position() {
        // Reject-fix guard (spec 18, unit 3; arch-u18-3r3-workflow-live-degrades-to-shared-
        // position-window + sdet-u18-3r2-workflow-path-still-races). The workflow live driver
        // (rigger serve) does NOT park its spawns, so a workflow gating spawn records NO
        // park/result window; its emits are correlated by the MCP server's per-spawn
        // [`META_SPAWN`] STAMP instead. This pins `gating_spawn_emitted_approve` directly on a
        // WORKFLOW-SHAPED store (a RunStarted, an approve, and NO SpawnRequested/SpawnResult):
        //  - an UNSTAMPED approve (a concurrent sibling adjudicator's, or a stale one) is NOT
        //    attributed to a windowless spawn - the bare shared-stream position that the reject
        //    forbade never fires the backstop, so an innocent unit's empty-verdict reject is
        //    never falsely hard-errored (the concurrent-sibling false POSITIVE, closed);
        //  - an approve STAMPED with THIS spawn's id IS attributed - the correlation the MCP
        //    server writes for the spawn it is serving, which is what makes the backstop fire on
        //    the parkless live driver (the emit-only-approve persona still caught);
        //  - a DIFFERENT spawn's stamp is never THIS spawn's, even sharing the reviewer role
        //    token a concurrent sibling carries.
        let store = Store::open(":memory:").unwrap();
        crate::run::ensure_started(&store, &[]).unwrap();

        let me = spawn_id("u", ROLE_ADJUDICATOR, 0);
        let sibling = spawn_id("v", ROLE_ADJUDICATOR, 0);
        let seed_approve = |meta: &[(&str, &str)]| {
            let mut e = crate::eventstore::Event::new(
                contextgraph::TYPE_DECISION_MADE,
                serde_json::to_vec(&json!({"id": "verdict", "verdict": "approve"})).unwrap(),
            );
            for (k, v) in meta {
                e = e.with_meta(*k, *v);
            }
            store
                .append(
                    STREAM,
                    crate::eventstore::ExpectedRevision::Any,
                    std::slice::from_ref(&e),
                )
                .unwrap();
        };

        let cfg = Config::default();
        let driver = Stub::new();
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let ctx = RunCtx {
            cfg: &cfg,
            deps: &deps,
            run_id: String::new(),
            gate_tracker: Mutex::new(HashMap::new()),
            integrate_mu: Mutex::new(()),
            spawns: AtomicU32::new(0),
            base_spawns: 0,
            recorded_spawn_ids: HashSet::new(),
            budget_broke: std::sync::atomic::AtomicBool::new(false),
            parked: std::sync::atomic::AtomicBool::new(false),
            manual_review: std::sync::atomic::AtomicBool::new(false),
            budget_halted: std::sync::atomic::AtomicBool::new(false),
            #[cfg(feature = "symbols")]
            ingested: std::sync::atomic::AtomicBool::new(false),
            prior_status: HashMap::new(),
            prior_attempts: HashMap::new(),
            replayed_keys: Mutex::new(HashSet::new()),
            gate_verdicts: Mutex::new(HashMap::new()),
            green_digests: Mutex::new(HashMap::new()),
            stale_units: Mutex::new(HashSet::new()),
            compensations: Mutex::new(Vec::new()),
            compensation_feedback: Mutex::new(HashMap::new()),
            compensation_attempts: Mutex::new(HashMap::new()),
            compensated_commits: Mutex::new(HashSet::new()),
            taxonomy: failure::Taxonomy::default(),
        };

        // An UNSTAMPED approve with no spawn-lifecycle events: not attributed to a windowless
        // spawn (the false-positive the reject turned on, closed).
        seed_approve(&[]);
        assert!(
            !ctx.gating_spawn_emitted_approve(&me).unwrap(),
            "an unstamped approve with no recorded window must NOT be attributed on the workflow \
             live path - a bare stream position is never enough"
        );

        // An approve STAMPED with THIS spawn's id IS attributed - the MCP-server correlation.
        seed_approve(&[(META_SPAWN, &me)]);
        assert!(
            ctx.gating_spawn_emitted_approve(&me).unwrap(),
            "an approve stamped with THIS spawn's id is attributed on the workflow live path"
        );

        // A concurrent SIBLING adjudicator (a different spawn id, no window of its own) is
        // never falsely attributed the unstamped approve NOR another spawn's stamped one.
        assert!(
            !ctx.gating_spawn_emitted_approve(&sibling).unwrap(),
            "a sibling spawn is not attributed another spawn's stamped approve or a bare position"
        );
    }

    #[test]
    fn a_degenerate_lens_result_respawns_the_lens_before_the_review_proceeds() {
        // The respawn loop wraps ALL THREE reviewer roles: a degenerate tier-1 LENS is
        // respawned the same way an adjudicator is (a shared helper, one authority), so a
        // flaky lens spawn does not corrupt the review.
        let store = Store::open(":memory:").unwrap();
        let cfg = degenerate_reviewer_cfg();
        let driver = Stub {
            output_by_spawn_id: HashMap::from([
                // Original lens spawn: empty stdout AND (no emits_by_agent set) no
                // ReviewFinding -> the conductor OBSERVED it produce nothing in-process, so
                // it is degenerate and respawned.
                (spawn_id("u", &lens_role("sdet"), 0), String::new()),
                // First lens respawn: a substantive review (its output is folded via
                // the graph, not a verdict, so any non-empty text lets the review proceed).
                (
                    spawn_retry_id("u", &lens_role("sdet"), 0, 1),
                    "reviewed the diff; no blocking defect".to_string(),
                ),
            ]),
            output_by_agent: HashMap::from([(
                "judge".to_string(),
                r#"{"verdict":"approve"}"#.to_string(),
            )]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        run(&cfg, &deps).expect("the review proceeds once the degenerate lens recovers");

        assert_eq!(
            driver.spawn_count("sdet"),
            2,
            "the degenerate lens is respawned exactly once"
        );
        assert!(
            driver
                .spawn_ids()
                .contains(&spawn_retry_id("u", &lens_role("sdet"), 0, 1)),
            "the lens respawn uses the deterministic ~retry1 id"
        );
        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        assert!(has_status(&events, "reviewed"), "the review still approves");
        assert!(
            !events.iter().any(|e| e.type_ == ledger::TYPE_UNIT_FAILED),
            "a degenerate lens must not charge the unit an attempt"
        );
    }

    #[test]
    fn a_lens_that_emitted_a_finding_but_reports_empty_stdout_is_not_degenerate() {
        // Fix 1 for adj-u2gap18 / adv-u2gap18-empty-success-is-a-valid-outcome-misread-as-
        // degenerate: a lens's stdout is NOT its verdict - it emits findings to the graph -
        // so an EMPTY stdout is the normal outcome, NOT degeneracy, when the lens emitted a
        // ReviewFinding. The lens here emits one ReviewFinding and reports empty stdout; it
        // must fold on its FIRST spawn (no respawn), and the review must proceed.
        let store = Store::open(":memory:").unwrap();
        let cfg = degenerate_reviewer_cfg();
        let driver = Stub {
            // The lens does its real work through the graph (a ReviewFinding) and returns
            // an EMPTY stdout - exactly the healthy shape the prior version misread.
            emits_by_agent: HashMap::from([(
                "sdet".to_string(),
                vec![(
                    contextgraph::TYPE_REVIEW_FINDING.to_string(),
                    json!({"id": "f-sdet-1", "summary": "a real concern", "about": ["u"]}),
                )],
            )]),
            output_by_agent: HashMap::from([
                // sdet's stdout is deliberately empty (its finding is the work).
                ("sdet".to_string(), String::new()),
                ("judge".to_string(), r#"{"verdict":"approve"}"#.to_string()),
            ]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        run(&cfg, &deps).expect("a finding-emitting lens with empty stdout is not degenerate");

        // The lens was spawned EXACTLY ONCE - its empty stdout was not misread as degenerate
        // (no respawn), because it emitted a ReviewFinding.
        assert_eq!(
            driver.spawn_count("sdet"),
            1,
            "a lens that emitted a ReviewFinding is not degenerate on an empty stdout"
        );
        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        // Its finding really did reach the log (the graph is the channel), and the review
        // approved normally.
        assert!(
            events
                .iter()
                .any(|e| e.type_ == contextgraph::TYPE_REVIEW_FINDING),
            "the lens's ReviewFinding is recorded"
        );
        assert!(
            has_status(&events, "reviewed"),
            "the review approves normally"
        );
        assert!(
            !events.iter().any(|e| e.type_ == ledger::TYPE_UNIT_FAILED),
            "a healthy finding-emitting lens charges no attempt"
        );
    }

    #[test]
    fn a_reviewer_that_only_ever_returns_degenerate_output_halts_the_run_loudly_naming_it() {
        // Gap 18: when the respawn bound (two respawns) exhausts with only degenerate
        // results, the unit does NOT lose the attempt - the run halts LOUDLY, naming the
        // dead reviewer. It is an operator infrastructure problem, NOT code for
        // remediation, so it propagates as an Error out of `run` (no UnitFailed/escalate).
        let store = Store::open(":memory:").unwrap();
        let cfg = degenerate_reviewer_cfg();
        // The adjudicator returns whitespace-only on EVERY spawn, including both
        // respawns; the lens returns a substantive review so the halt is provably the
        // adjudicator's, not the lens's.
        let driver = Stub {
            output_by_agent: HashMap::from([
                ("judge".to_string(), "  \n ".to_string()),
                ("sdet".to_string(), "lens: no blocker".to_string()),
            ]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let err = match run(&cfg, &deps) {
            Ok(_) => panic!("an all-degenerate reviewer must halt the run"),
            Err(e) => e,
        };
        // The halt NAMES the dead reviewer (its agent id, the tier, and the unit) so the
        // operator can see WHICH spawn is failing.
        assert!(
            err.0.contains("\"judge\"") && err.0.contains("adjudicator") && err.0.contains("\"u\""),
            "the loud halt must name the dead reviewer, its tier, and the unit: {}",
            err.0
        );
        // The surfaced halt message is CLEAN - the internal recognition marker is stripped
        // by run_wave before it reaches the operator.
        assert!(
            !err.0.contains(DEGENERATE_MARKER),
            "the operator-facing halt must not carry the internal sentinel marker: {:?}",
            err.0
        );
        // It names the REAL recovery (re-record a substantive result; last-write-wins), not
        // the dead "just re-run" promise the adjudicator rejected at adj-u2gap18.
        assert!(
            err.0.contains("rigger result") && err.0.contains("last-write-wins"),
            "the halt must name the working recovery (a corrected re-record), not a bare re-run: {}",
            err.0
        );

        // The adjudicator was spawned exactly THREE times: the original + two respawns.
        assert_eq!(
            driver.spawn_count("judge"),
            3,
            "the respawn bound is two: original + 2 respawns, then halt"
        );
        // Each respawn used the deterministic retry-suffixed id.
        let ids = driver.spawn_ids();
        for id in [
            spawn_id("u", ROLE_ADJUDICATOR, 0),
            spawn_retry_id("u", ROLE_ADJUDICATOR, 0, 1),
            spawn_retry_id("u", ROLE_ADJUDICATOR, 0, 2),
        ] {
            assert!(
                ids.contains(&id),
                "expected deterministic spawn id {id}: {ids:?}"
            );
        }

        // The unit was NOT charged an attempt: an infrastructure halt records no
        // UnitFailed and no UnitEscalated - it is the operator's problem, not the unit's.
        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        assert!(
            !events.iter().any(|e| e.type_ == ledger::TYPE_UNIT_FAILED),
            "a degenerate-reviewer halt must not charge the unit an attempt (no UnitFailed)"
        );
        assert!(
            !events
                .iter()
                .any(|e| e.type_ == ledger::TYPE_UNIT_ESCALATED),
            "a degenerate-reviewer halt is not a code defect for remediation (no UnitEscalated)"
        );
        // And it emits NO per-unit lesson: routing the halt through run_wave's dedicated
        // degenerate arm (not the generic wave-failure arm) keeps it from misattributing
        // the operator's broken reviewer to the unit under review as a LESSON_LEARNED
        // (fix for adv-u2gap18-halt-lesson-misattribution / sdet-u2-halt-emits-unit-lesson-
        // misattribution).
        assert!(
            !events
                .iter()
                .any(|e| e.type_ == contextgraph::TYPE_LESSON_LEARNED),
            "a degenerate-reviewer halt must emit no per-unit lesson (no misattribution)"
        );
        // The implementer ran exactly once - the halt did not restart the unit lifecycle.
        assert_eq!(driver.spawn_count("worker"), 1);
    }

    #[test]
    fn resume_integrates_an_already_approved_unit_without_re_reviewing() {
        // Resume-continuity: a unit whose log shows review APPROVED (`reviewed`) but no
        // UnitIntegrated - the merge was interrupted - must integrate on resume with NO
        // lens/adversary/adjudicator spawns. The verdict was already settled; re-review
        // would re-litigate it and re-spend the budget.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();

        commit_on_unit_branch(&repo_path, "s", "feature.rs", "fn feature() {}\n");

        let st = Store::open(":memory:").unwrap();
        seed_events_in_run(
            &st,
            &[],
            &[
                Event::new(
                    ledger::TYPE_UNIT_STARTED,
                    serde_json::to_vec(
                        &json!({"id": "s", "agent": "worker", "branch": unit_branch("s")}),
                    )
                    .unwrap(),
                ),
                Event::new(
                    ledger::TYPE_UNIT_STATUS,
                    serde_json::to_vec(&json!({"id": "s", "status": "verified"})).unwrap(),
                ),
                Event::new(
                    ledger::TYPE_UNIT_STATUS,
                    serde_json::to_vec(&json!({"id": "s", "status": "reviewed"})).unwrap(),
                ),
            ],
        );

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("lens".into(), agent("lens"));
        cfg.agents.insert("adversary".into(), agent("adversary"));
        cfg.agents.insert("judge".into(), agent("judge"));
        cfg.workflow.gates.insert("ok".into(), gate_def("true"));
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                gates: vec!["ok".into()],
                on_pass: "merge".into(),
                review: crate::config::ReviewPanel {
                    lenses: vec!["lens".into()],
                    adversary: "adversary".into(),
                    adjudicator: "judge".into(),
                    tiers: None,
                },
                ..Default::default()
            },
        );

        let driver = Stub::new();
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path,
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        assert!(
            !driver.spawned("worker"),
            "an approved unit must not re-implement on resume"
        );
        assert!(
            !driver.spawned("lens") && !driver.spawned("adversary") && !driver.spawned("judge"),
            "an already-approved unit must integrate with NO review spawns on resume"
        );
        assert_eq!(
            rs.units["s"].status,
            ledger::Status::Integrated,
            "the approved-but-uninterrupted-merge unit must integrate on resume"
        );
        assert!(
            repo.path().join("feature.rs").exists(),
            "the approved work must land in the base"
        );
    }

    #[test]
    fn a_failed_unit_is_not_terminal_and_resumes() {
        // A unit that FAILED a review/gate in a prior window but did NOT yet escalate
        // (attempts:1 of MAX_RETRIES) is mid-remediation, not terminal. A resumed run
        // must NOT skip it - it re-runs the unit, reusing its deterministic branch (the
        // rejected code persists) and continuing its remediation. Here the resumed
        // attempt is approved, so the unit finishes; the point is it RAN at all rather
        // than being seeded into `terminal` and skipped forever.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();

        // The prior window implemented unit `s`, committed it on the deterministic
        // branch, but its review/gate FAILED once (UnitFailed attempts:1) - it is
        // mid-remediation, not escalated.
        commit_on_unit_branch(&repo_path, "s", "feature.rs", "fn feature() {}\n");

        let st = Store::open(":memory:").unwrap();
        seed_events_in_run(
            &st,
            &[],
            &[
                Event::new(
                    ledger::TYPE_UNIT_STARTED,
                    serde_json::to_vec(
                        &json!({"id": "s", "agent": "worker", "branch": unit_branch("s")}),
                    )
                    .unwrap(),
                ),
                Event::new(
                    ledger::TYPE_UNIT_FAILED,
                    serde_json::to_vec(&json!({"id": "s", "attempts": 1})).unwrap(),
                ),
            ],
        );

        // The folded prior state proves the unit is NOT terminal (the regression this
        // fix closes): a Failed-but-not-escalated unit must be eligible to resume.
        let prior = ledger::project(
            &st.read_all(0, Direction::Forward, &Filter::default())
                .unwrap(),
        )
        .unwrap();
        assert_eq!(prior.units["s"].status, ledger::Status::Failed);
        assert_eq!(prior.units["s"].attempts, 1);
        assert!(
            !prior.is_terminal("s"),
            "a Failed-but-not-escalated unit must not be terminal - else resume skips it forever"
        );

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("lens".into(), agent("lens"));
        cfg.agents.insert("judge".into(), agent("judge"));
        cfg.workflow.gates.insert("ok".into(), gate_def("true"));
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                gates: vec!["ok".into()],
                on_pass: "merge".into(),
                review: crate::config::ReviewPanel {
                    lenses: vec!["lens".into()],
                    adjudicator: "judge".into(),
                    ..Default::default()
                },
                ..Default::default()
            },
        );

        // The resumed attempt's review is approved, so the unit integrates this window.
        // The lens returns a substantive review so it does not trip the Gap-18 respawn loop.
        let driver = Stub {
            write_file: Some("feature.rs".into()),
            output_by_agent: HashMap::from([
                ("judge".to_string(), r#"{"verdict":"approve"}"#.to_string()),
                ("lens".to_string(), "reviewed: no blocker".to_string()),
            ]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path,
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        // The unit RAN on resume - it was not skipped as terminal. A Failed unit's
        // recorded status falls to the Fresh resume-phase, so it re-implements (the
        // worker spawns) to address the recorded findings, reusing its branch.
        assert!(
            driver.spawned("worker"),
            "a Failed-but-not-escalated unit must resume and re-run, not be skipped as terminal"
        );
        assert!(
            crate::worktree::Worktree::branch_has_work(&deps.repo, &unit_branch("s"))
                || repo.path().join("feature.rs").exists(),
            "the resumed unit reuses its deterministic branch - the prior rejected code persists"
        );
        assert_eq!(
            rs.units["s"].status,
            ledger::Status::Integrated,
            "the resumed unit must be able to finish its remediation, not stay stuck"
        );
        assert!(
            repo.path().join("feature.rs").exists(),
            "the prior window's committed file (reused from the branch) lands on integrate"
        );
    }

    #[test]
    fn remediation_attempts_accumulate_across_resume_and_escalate_at_the_bound() {
        // Attempts ACCUMULATE across windows: a unit that already failed twice in a
        // prior window (UnitFailed attempts:2) resumes, makes EXACTLY ONE more attempt
        // (the 3rd), and ESCALATES at MAX_RETRIES TOTAL - it does NOT do a fresh
        // MAX_RETRIES on top of the prior 2. The attempt counter is threaded through
        // resume so the bound counts across windows, not per-window forever.
        assert_eq!(
            safety::MAX_RETRIES,
            3,
            "this test assumes the default bound of 3 (2 prior + 1 resumed = escalate)"
        );

        let st = Store::open(":memory:").unwrap();
        // Prior window: the unit already failed twice (attempts:2), one short of the
        // bound. The next failure must escalate.
        seed_events_in_run(
            &st,
            &[],
            &[
                Event::new(
                    ledger::TYPE_UNIT_STARTED,
                    serde_json::to_vec(&json!({"id": "implement", "agent": "worker"})).unwrap(),
                ),
                Event::new(
                    ledger::TYPE_UNIT_FAILED,
                    serde_json::to_vec(&json!({"id": "implement", "attempts": 2})).unwrap(),
                ),
            ],
        );

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("lens".into(), agent("lens"));
        cfg.agents.insert("adversary".into(), agent("adversary"));
        cfg.agents.insert("adj".into(), agent("adj"));
        cfg.workflow.gates.insert("ok".into(), gate_def("true")); // static gates pass
        cfg.workflow.defaults.review = config::ReviewPanel {
            lenses: vec!["lens".into()],
            adversary: "adversary".into(),
            adjudicator: "adj".into(),
            tiers: None,
        };
        cfg.workflow.stages.insert(
            "implement".into(),
            Stage {
                name: "implement".into(),
                agent: "worker".into(),
                gates: vec!["ok".into()],
                on_pass: "merge".into(),
                ..Default::default()
            },
        );

        // The adjudicator always rejects, so the resumed attempt can only fail again -
        // and with attempts already at 2, that next failure must escalate.
        let driver = Stub {
            output: r#"{"verdict":"reject","issues":[]}"#.into(),
            ..Stub::new()
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        // The unit escalated this window (not churned, not skipped).
        assert_eq!(
            rs.units["implement"].status,
            ledger::Status::Escalated,
            "with 2 prior attempts, the resumed unit must escalate on its next failure"
        );

        // EXACTLY ONE more attempt ran this window: one worker spawn, NOT a fresh
        // MAX_RETRIES (3) on top of the prior 2. The attempt counter resumed at 2.
        let order = driver.call_order.lock().unwrap().clone();
        let worker_spawns = order.iter().filter(|a| *a == "worker").count();
        assert_eq!(
            worker_spawns, 1,
            "the resumed unit must do ONLY the final (3rd) attempt, not a fresh batch; spawns were {order:?}"
        );

        let events = st
            .read_all(0, Direction::Forward, &Filter::default())
            .unwrap();
        // Exactly one UnitEscalated, and it is final.
        let escalations = events
            .iter()
            .filter(|e| e.type_ == ledger::TYPE_UNIT_ESCALATED)
            .count();
        assert_eq!(
            escalations, 1,
            "the unit escalates exactly once at the bound"
        );
        // The escalation lesson records the attempt count at MAX_RETRIES (3 total),
        // not 5 (2 prior + a fresh 3): the bound counted across windows.
        let escalated_at_bound = events.iter().any(|e| {
            e.type_ == contextgraph::TYPE_LESSON_LEARNED
                && String::from_utf8_lossy(&e.data)
                    .contains(&format!("escalated after {} attempts", safety::MAX_RETRIES))
        });
        assert!(
            escalated_at_bound,
            "escalation must record MAX_RETRIES total attempts, proving the count accumulated across the resume"
        );
        // The final folded attempt count is the bound, not the bound-plus-the-prior.
        assert_eq!(
            rs.units["implement"].attempts,
            safety::MAX_RETRIES,
            "the final attempts must reach the bound exactly - the prior count carried over, it did not reset"
        );
    }

    #[test]
    fn an_escalated_unit_stays_terminal_on_resume() {
        // Escalation is FINAL: a unit that genuinely reached MAX_RETRIES and escalated
        // stays terminal and is skipped on resume - no re-run, no fresh attempts.
        let st = Store::open(":memory:").unwrap();
        seed_events_in_run(
            &st,
            &[],
            &[
                Event::new(
                    ledger::TYPE_UNIT_STARTED,
                    serde_json::to_vec(&json!({"id": "s", "agent": "worker"})).unwrap(),
                ),
                Event::new(
                    ledger::TYPE_UNIT_FAILED,
                    serde_json::to_vec(&json!({"id": "s", "attempts": 3})).unwrap(),
                ),
                Event::new(
                    ledger::TYPE_UNIT_ESCALATED,
                    serde_json::to_vec(&json!({"id": "s"})).unwrap(),
                ),
            ],
        );

        // The prior state confirms the escalated unit IS terminal.
        let prior = ledger::project(
            &st.read_all(0, Direction::Forward, &Filter::default())
                .unwrap(),
        )
        .unwrap();
        assert_eq!(prior.units["s"].status, ledger::Status::Escalated);
        assert!(
            prior.is_terminal("s"),
            "an escalated unit must be terminal - escalation is final"
        );

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.workflow.gates.insert("ok".into(), gate_def("true"));
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                gates: vec!["ok".into()],
                on_pass: "merge".into(),
                ..Default::default()
            },
        );

        let driver = Stub::new();
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        assert!(
            !driver.spawned("worker"),
            "an escalated unit must be skipped on resume - escalation is final, no re-run"
        );
        assert_eq!(
            rs.units["s"].status,
            ledger::Status::Escalated,
            "an escalated unit stays escalated across resume"
        );
        // No second UnitStarted for the skipped unit.
        let events = st
            .read_all(0, Direction::Forward, &Filter::default())
            .unwrap();
        let starts = events
            .iter()
            .filter(|e| {
                e.type_ == ledger::TYPE_UNIT_STARTED
                    && String::from_utf8_lossy(&e.data).contains("\"id\":\"s\"")
            })
            .count();
        assert_eq!(
            starts, 1,
            "the escalated unit must not be restarted on resume"
        );
    }

    #[test]
    fn a_fresh_unit_with_no_branch_runs_the_full_lifecycle() {
        // The no-prior-branch path is unchanged: a unit with no deterministic branch
        // (a first run) implements, gates, reviews, and integrates - the implementer
        // and the adjudicator both spawn.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();

        let st = Store::open(":memory:").unwrap();
        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("judge".into(), agent("judge"));
        cfg.workflow.gates.insert("ok".into(), gate_def("true"));
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                gates: vec!["ok".into()],
                on_pass: "merge".into(),
                review: crate::config::ReviewPanel {
                    adjudicator: "judge".into(),
                    ..Default::default()
                },
                ..Default::default()
            },
        );

        let driver = Stub {
            write_file: Some("feature.rs".into()),
            output_by_agent: HashMap::from([(
                "judge".to_string(),
                r#"{"verdict":"approve"}"#.to_string(),
            )]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path,
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        assert!(
            driver.spawned("worker"),
            "a fresh unit with no prior branch must run the implementer"
        );
        assert!(
            driver.spawned("judge"),
            "a fresh unit must run the three-tier review"
        );
        assert_eq!(rs.units["s"].status, ledger::Status::Integrated);
    }

