    /// The addendum 6.2 confidence-tiered subgraph of a touched file `combat.rs`, as ONE edge set
    /// carrying all three tiers - the fixture the tier-filter tests split. `combat.rs` DEFINES
    /// `apply_damage`
    /// (its own EXTRACTED neighborhood) and REFERENCES three symbols at descending confidence:
    /// `apply_damage` resolves in-file (EXTRACTED), `physics.rs::resolve` resolves cross-file
    /// (INFERRED), `legacy.rs::old_hook` resolves nowhere known (AMBIGUOUS - a grep-visible-only
    /// occurrence). Crucially `physics.rs` and `legacy.rs` BOTH carry their OWN EXTRACTED `CONTAINS`
    /// edge, so a flat "files touched by an EXTRACTED edge" scan would wrongly pull them into
    /// `precise`; only a REACHABILITY filter (the seed must reach them across EXTRACTED edges the
    /// whole way) keeps them out - which is what makes the fixture discriminate.
    fn confidence_tier_fixture() -> Graph {
        let node = |id: &str, kind: &str| contextgraph::Node {
            id: id.into(),
            kind: kind.into(),
            attrs: BTreeMap::new(),
        };
        let edge = |from: &str, to: &str, rel: &str, tier: &str| contextgraph::Edge {
            from: from.into(),
            to: to.into(),
            rel: rel.into(),
            valid_from: 0,
            valid_to: None,
            source: 0,
            tier: tier.into(),
        };
        Graph {
            nodes: vec![
                node("combat.rs", contextgraph::KIND_FILE),
                node("physics.rs", contextgraph::KIND_FILE),
                node("legacy.rs", contextgraph::KIND_FILE),
                node("combat.rs::apply_damage", contextgraph::KIND_CODE_ENTITY),
                node("physics.rs::resolve", contextgraph::KIND_CODE_ENTITY),
                node("legacy.rs::old_hook", contextgraph::KIND_CODE_ENTITY),
            ],
            edges: vec![
                // Each file CONTAINS its own definition - always EXTRACTED (spec 29a).
                edge(
                    "combat.rs",
                    "combat.rs::apply_damage",
                    contextgraph::REL_CONTAINS,
                    contextgraph::TIER_EXTRACTED,
                ),
                edge(
                    "physics.rs",
                    "physics.rs::resolve",
                    contextgraph::REL_CONTAINS,
                    contextgraph::TIER_EXTRACTED,
                ),
                edge(
                    "legacy.rs",
                    "legacy.rs::old_hook",
                    contextgraph::REL_CONTAINS,
                    contextgraph::TIER_EXTRACTED,
                ),
                // combat.rs's references, one per confidence tier.
                edge(
                    "combat.rs",
                    "combat.rs::apply_damage",
                    contextgraph::REL_REFERENCES,
                    contextgraph::TIER_EXTRACTED,
                ),
                edge(
                    "combat.rs",
                    "physics.rs::resolve",
                    contextgraph::REL_REFERENCES,
                    contextgraph::TIER_INFERRED,
                ),
                edge(
                    "combat.rs",
                    "legacy.rs::old_hook",
                    contextgraph::REL_REFERENCES,
                    contextgraph::TIER_AMBIGUOUS,
                ),
            ],
        }
    }

    /// spec 29c criterion 2 (`u29c-2`): the CONFIDENCE-TIER blast radius is TWO filters over the ONE
    /// tiered edge set, replacing `BlastRadius{precise,safe,serialize}`. `precise` is the EXTRACTED
    /// sub-graph; `safe` is `EXTRACTED u INFERRED u AMBIGUOUS`; `safe` stays a superset of the grep
    /// union (the AMBIGUOUS = grep-visible-only tail rides in `safe`). Proven over the addendum 6.2
    /// fixture: from seed `combat.rs`, only `combat.rs` is EXTRACTED-reachable, while the INFERRED
    /// (`physics.rs`) and AMBIGUOUS (`legacy.rs`) references widen `safe` - even though both those
    /// files carry their OWN EXTRACTED `CONTAINS` edge, so this pins the REACHABILITY semantics, not
    /// a flat edge scan.
    #[test]
    fn confidence_tier_radius_splits_the_one_edge_set_into_extracted_precise_and_all_tier_safe() {
        let g = confidence_tier_fixture();
        let seed = vec!["combat.rs".to_string()];
        let r = confidence_tier_radius(&g, &seed);

        // precise = the EXTRACTED sub-graph: ONLY combat.rs (its in-file resolved neighborhood).
        // physics.rs / legacy.rs are NOT reachable across EXTRACTED-only edges, so their own
        // EXTRACTED CONTAINS edges never promote them here (reachability, not a flat scan).
        assert_eq!(
            r.precise,
            vec!["combat.rs".to_string()],
            "precise is the EXTRACTED sub-graph reachable from the seed; got {:?}",
            r.precise
        );

        // safe = EXTRACTED u INFERRED u AMBIGUOUS: combat.rs plus the cross-file INFERRED target
        // (physics.rs) plus the grep-visible-only AMBIGUOUS target (legacy.rs), sorted.
        assert_eq!(
            r.safe,
            vec![
                "combat.rs".to_string(),
                "legacy.rs".to_string(),
                "physics.rs".to_string(),
            ],
            "safe is the all-tier reachable file set; got {:?}",
            r.safe
        );

        // The tier SPLIT is real: the INFERRED and AMBIGUOUS files are in safe but NOT precise.
        assert!(
            r.safe.contains(&"physics.rs".to_string())
                && !r.precise.contains(&"physics.rs".to_string()),
            "an INFERRED-only file rides safe, never precise"
        );
        // The AMBIGUOUS tier IS the grep-visible-only occurrences, so keeping it in safe is exactly
        // what makes safe a SUPERSET OF THE GREP UNION (addendum 2.4 correctness invariant).
        assert!(
            r.safe.contains(&"legacy.rs".to_string())
                && !r.precise.contains(&"legacy.rs".to_string()),
            "the AMBIGUOUS (grep-visible-only) tail rides safe - safe stays a grep-superset"
        );
        // precise is always a subset of safe (EXTRACTED reachability is a subset of all-tier).
        assert!(
            r.precise.iter().all(|f| r.safe.contains(f)),
            "precise must be a subset of safe"
        );
        // This filter owns only the tier split; the hub verdict is layered on by the caller.
        assert!(
            !r.serialize,
            "the tier filter itself never sets the hub verdict"
        );
    }

    /// spec 29c criterion 2 wiring: `grounded_blast_radius` COMPUTES the two-view radius by
    /// tier-filtering the ONE seeded subgraph when a graph is present (the tier filter is live, not
    /// dead code), and it PRESERVES the safety floor - `safe` is unioned with the grounder's grep
    /// superset so it can only widen, never narrow below the grep union (addendum 2.4), and the
    /// grounder's `serialize` hub verdict is carried, never silently dropped. The `graph: None` arm
    /// falls back to the grounder radius byte-for-byte, so the two arms observably differ: the graph
    /// arm surfaces the INFERRED/AMBIGUOUS files the grep radius alone never would.
    #[test]
    fn grounded_blast_radius_tier_filters_the_subgraph_and_keeps_the_grep_superset() {
        // A `Projection` double returning the addendum 6.2 tiered subgraph for combat.rs, so the
        // wiring is exercised over a discriminating multi-tier edge set (a real 29a fold scopes a
        // reference to its own file, so it cannot produce a cross-file INFERRED target to split on).
        struct FixedGraph(Graph);
        impl Projection for FixedGraph {
            fn apply(&self, _e: &crate::eventstore::Event) -> Result<(), contextgraph::Error> {
                Ok(())
            }
            fn subgraph(
                &self,
                _seed: &[String],
                _depth: i64,
            ) -> Result<Graph, contextgraph::Error> {
                Ok(self.0.clone())
            }
            fn resolve(&self, _m: &str) -> Result<Option<String>, contextgraph::Error> {
                Ok(None)
            }
        }

        // A grep grounder over a temp tree whose only match seeds the traversal on combat.rs.
        let dir = tempfile::tempdir().unwrap();
        std::fs::write(dir.path().join("combat.rs"), "fn combat_step() {}\n").unwrap();
        let grep = crate::grounder::Grep {
            root: dir.path().to_str().unwrap().to_string(),
        };
        let st = Stage {
            name: "u".into(),
            coverage: "combat_step".into(),
            ..Default::default()
        };
        let cfg = Config::default();
        let store = Store::open(":memory:").unwrap();
        let driver = Stub::new();
        let graph = FixedGraph(confidence_tier_fixture());

        // The grep radius alone (graph: None) is the fallback floor: just the seed file.
        let base_deps = Deps {
            store: &store,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: Some(&grep),
            graph: None,
            criteria: Vec::new(),
        };
        let base = RunCtx::for_test(&cfg, &base_deps).grounded_blast_radius(&st);
        assert_eq!(
            base.safe,
            vec!["combat.rs".to_string()],
            "precondition: the grep radius alone is just the seed file; got {:?}",
            base.safe
        );

        // WITH the graph, the tier filter is live: safe widens to the all-tier reachable set while
        // still containing the grep floor, precise is the EXTRACTED sub-graph, serialize is carried.
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: Some(&grep),
            graph: Some(&graph),
            criteria: Vec::new(),
        };
        let r = RunCtx::for_test(&cfg, &deps).grounded_blast_radius(&st);

        assert!(
            base.safe.iter().all(|f| r.safe.contains(f)),
            "safe must stay a superset of the grep union (addendum 2.4); grep {:?} vs safe {:?}",
            base.safe,
            r.safe
        );
        assert!(
            r.safe.contains(&"physics.rs".to_string())
                && r.safe.contains(&"legacy.rs".to_string()),
            "the graph tier filter is live: safe carries the INFERRED and AMBIGUOUS files the grep \
             radius never had; got {:?}",
            r.safe
        );
        assert_eq!(
            r.precise,
            vec!["combat.rs".to_string()],
            "precise is the EXTRACTED sub-graph; got {:?}",
            r.precise
        );
        assert_eq!(
            r.serialize, base.serialize,
            "the grounder's hub (serialize) verdict is carried through, never dropped"
        );
    }

    /// spec 17 unit 6 (criterion 6, `plan17-c6`): the two-facet fix, proven in ONE scenario under
    /// the `hybrid` grounder.
    ///
    /// (4a) A `BlastRadiusComputed` event IS emitted under `defaults.grounder: hybrid`. `Hybrid`
    /// composes an inner `Symbols`, so it MUST delegate `index_stamp` to it - a non-empty stamp is
    /// the structural-active signal `record_blast_radius` keys the audit off. Before the fix `Hybrid`
    /// inherited the empty-string trait default, so `record_blast_radius` hit its empty-stamp early
    /// return and NO audit ever emitted for a hybrid run (retention unmeasurable).
    ///
    /// (4b) The recorded `precise` equals the files that SEEDED the prompt at AND beyond the
    /// truncation cap. The prompt seed is `grounded_seed` - the distinct FILES of `ground(query, k)`,
    /// a k-LINE-truncated pass - while the radius's `precise` is a k-FILE-truncated structural rank;
    /// past the cap the two diverge. The fixture makes the divergence unmissable: `busy.rs`
    /// references `target` on many LINES, consuming the k-LINE `ground` budget so the distinct-FILE
    /// seed is just {def.rs, busy.rs}; the structural `precise` instead ranks def-then-referencers
    /// truncated at k FILES, carrying `x0.rs..x5.rs` - files that never seeded the prompt. The audit
    /// must record the 2-file seed, not the beyond-cap structural rank.
    ///
    /// Runs under a REAL `Hybrid` in BOTH symbols lanes: the default `turbovec` lane (a real vector
    /// engine is built, hence `#[file_serial(turbovec_model)]`) and `--features symbols` alone
    /// (Hybrid degrades to symbols-only, no model). Excluded from `--no-default-features` (no
    /// `symbols`, no tree-sitter) by the `cfg` gate.
    #[cfg(feature = "symbols")]
    #[test]
    #[cfg_attr(feature = "turbovec", serial_test::file_serial(turbovec_model))]
    fn under_hybrid_the_audit_emits_and_records_the_prompt_seed_as_precise() {
        use crate::grounder::symbols::hybrid::Hybrid;

        let dir = tempfile::tempdir().unwrap();
        // `def.rs` DEFINES `target` (the sole definer). `busy.rs` REFERENCES it on 12 LINES, so it
        // eats the k-LINE `ground` budget and the distinct-FILE seed stays {def.rs, busy.rs}.
        std::fs::write(dir.path().join("def.rs"), "fn target() {}\n").unwrap();
        let body: String = "    target();\n".repeat(12);
        std::fs::write(
            dir.path().join("busy.rs"),
            format!("fn caller() {{\n{body}}}\n"),
        )
        .unwrap();
        // Ten more single-reference files: the STRUCTURAL precise (def, then referencers, truncated
        // at k FILES) ranks these into its top-k, but they NEVER seed the prompt.
        for i in 0..10 {
            std::fs::write(
                dir.path().join(format!("x{i}.rs")),
                format!("fn r{i}() {{ target(); }}\n"),
            )
            .unwrap();
        }
        let root = dir.path().to_str().unwrap();
        let hybrid = Hybrid::open(root, None).expect("hybrid opens");

        // A non-producer stage grounds on its `coverage`, so this grounds every path on `target`.
        let st = Stage {
            name: "u".into(),
            coverage: "target".into(),
            ..Default::default()
        };
        let cfg = Config::default();
        let store = Store::open(":memory:").unwrap();
        let driver = Stub::new();
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: Some(&hybrid),
            graph: None,
            criteria: Vec::new(),
        };
        let ctx = RunCtx::for_test(&cfg, &deps);

        // The EXACT production call sequence (`run_single_stage` / `run_speculation`): the prompt
        // SEED, the two-view radius, then the audit keyed at the attempt.
        let seed = ctx.grounded_seed(&st);
        let radius = ctx.grounded_blast_radius(&st);
        ctx.record_blast_radius(&st, 0, &seed, &radius).unwrap();

        // The seed is the small distinct-FILE set; the structural precise diverges past the cap.
        assert_eq!(
            seed,
            vec!["def.rs".to_string(), "busy.rs".to_string()],
            "the prompt seed is the distinct FILES of ground(target, k): {seed:?}"
        );
        assert!(
            radius.precise.len() > seed.len() && radius.precise.contains(&"x0.rs".to_string()),
            "precondition: the structural precise diverges past the cap, carrying x*.rs files the \
             seed never did: {:?}",
            radius.precise
        );

        // (4a) `Hybrid::index_stamp` delegates to the inner `Symbols` (non-empty), so the audit is
        // NOT skipped by the empty-stamp early return.
        assert!(
            !hybrid.index_stamp().is_empty(),
            "Hybrid::index_stamp must delegate to its inner Symbols (a non-empty structural stamp)"
        );
        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        let audit = events
            .iter()
            .find(|e| e.type_ == TYPE_BLAST_RADIUS_COMPUTED)
            .expect("a BlastRadiusComputed audit IS emitted under the hybrid grounder");

        // (4b) The recorded `precise` equals the prompt seed, NOT the beyond-cap structural rank.
        let v: Value = serde_json::from_slice(&audit.data).unwrap();
        let recorded_precise: Vec<String> = v["precise"]
            .as_array()
            .unwrap()
            .iter()
            .map(|f| f.as_str().unwrap().to_string())
            .collect();
        assert_eq!(
            recorded_precise, seed,
            "the audit must record the prompt seed as precise, not the k-FILE structural rank"
        );
        assert!(
            !recorded_precise.contains(&"x0.rs".to_string()),
            "the recorded precise must NOT carry a beyond-cap structural file the prompt never \
             seeded on: {recorded_precise:?}"
        );
    }

    /// spec 16 unit 3, the BLOCKING empty-radius partition fail-safe (adj-u3-empty-radius-partitions-
    /// fail-open): `partition_wave` must UNPARTITION an EMPTY radius - a total, unassessable grounding
    /// miss - into its OWN singleton batch, exactly like a HUB (`serialize`) radius, and NEVER
    /// co-schedule it with a real unit. An empty want-set is disjoint from every batch, so the
    /// pre-fix code collapsed it into the FIRST shared batch (the fail-OPEN direction, the OPPOSITE
    /// of `route_review_tier`'s empty -> full stance). This MULTI-unit test drives `partition_wave`
    /// directly over a structural grounder and pins the whole own-batch + append path: two disjoint
    /// shareable units co-schedule, while the empty-radius unit AND the hub unit each take their own
    /// batch. Runs in BOTH lanes (the StructuralStubGrounder is not symbols-gated).
    #[test]
    fn partition_wave_own_batches_an_empty_radius_never_co_scheduling_it() {
        let br = |files: &[&str], serialize: bool| BlastRadius {
            precise: files.iter().map(|s| s.to_string()).collect(),
            safe: files.iter().map(|s| s.to_string()).collect(),
            serialize,
        };
        // u_a / u_b are disjoint shareable radii; u_empty grounds to NOTHING (no by_query entry
        // => BlastRadius::default, empty safe, serialize false); u_hub is a hub (serialize true).
        let grounder = StructuralStubGrounder {
            by_query: HashMap::from([
                ("u_a".to_string(), br(&["a.rs"], false)),
                ("u_b".to_string(), br(&["b.rs"], false)),
                ("u_hub".to_string(), br(&["h.rs"], true)),
            ]),
            stamp: "idxhash/ts-tags-v1".to_string(),
        };
        let cfg = Config::default();
        let mut stages: BTreeMap<String, Stage> = BTreeMap::new();
        let ready: Vec<String> = ["u_a", "u_b", "u_empty", "u_hub"]
            .iter()
            .map(|s| s.to_string())
            .collect();
        for name in &ready {
            stages.insert(
                name.clone(),
                Stage {
                    name: name.clone(),
                    coverage: name.clone(),
                    partition: "by-blast-radius".into(),
                    ..Default::default()
                },
            );
        }
        let store = Store::open(":memory:").unwrap();
        let driver = Stub::new();
        let runner = RecordingRunner::new(&[]);
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &runner,
            repo: String::new(),
            grounder: Some(&grounder),
            graph: None,
            criteria: Vec::new(),
        };
        let ctx = RunCtx::for_test(&cfg, &deps);
        let batches = ctx.partition_wave(&stages, &ready);

        let batch_of = |unit: &str| {
            batches
                .iter()
                .find(|b| b.iter().any(|n| n == unit))
                .cloned()
                .unwrap_or_else(|| panic!("{unit} landed in no batch: {batches:?}"))
        };
        let a_batch = batch_of("u_a");
        assert!(
            a_batch.contains(&"u_b".to_string()),
            "two disjoint shareable units co-schedule in one batch: {batches:?}"
        );
        assert!(
            !a_batch.contains(&"u_empty".to_string()),
            "an EMPTY radius must NOT co-schedule with a real unit (the fail-open is closed): {batches:?}"
        );
        assert_eq!(
            batch_of("u_empty"),
            vec!["u_empty".to_string()],
            "an empty radius is unassessable and takes its OWN singleton batch: {batches:?}"
        );
        assert_eq!(
            batch_of("u_hub"),
            vec!["u_hub".to_string()],
            "a hub radius takes its OWN singleton batch: {batches:?}"
        );
    }

    /// spec 16 unit 3, the SPECULATION-path wiring (sdet-u16-3-speculation-wiring-untested): the
    /// first-green-wins speculation path must record the `BlastRadiusComputed` audit at attempt 0
    /// AND route the winner's review tier over the UNCAPPED SAFE view, exactly like the single-lane
    /// path - so a beyond-cap high-risk file present only in `.safe` still forces the FULL panel. A
    /// regression routing speculation over the capped precise seed, or dropping the speculation
    /// audit, would go green without this test.
    #[test]
    fn speculation_over_a_structural_grounder_records_the_audit_and_routes_full() {
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();

        // precise (the capped seed): 8 low-risk src files, none high-risk. safe (uncapped): those
        // PLUS a high-risk spec file the cap excludes - the ONLY thing that can force full is the
        // beyond-cap high-risk membership over the safe view, so routing over precise would go light.
        let precise: Vec<String> = (0..8).map(|i| format!("src/f{i}.rs")).collect();
        let mut safe = precise.clone();
        safe.push("specs/core.md".to_string());
        let grounder = StructuralStubGrounder {
            by_query: HashMap::from([(
                "s".to_string(),
                BlastRadius {
                    precise,
                    safe,
                    serialize: false,
                },
            )]),
            stamp: "idxhash/ts-tags-v1".to_string(),
        };

        // A tiered stage at speculation width 2 (K>1 routes through `run_speculation`).
        let mut stage = tiered_stage(20, &["specs/"]);
        stage.speculation_width = 2;
        let cfg = tiered_cfg(stage);
        let store = Store::open(":memory:").unwrap();
        let driver = CacheDriver {
            contents: vec!["work\n".into()],
            approve_at: 0,
        };
        let runner = RecordingRunner::new(&[]);
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &runner,
            repo: repo_path,
            grounder: Some(&grounder),
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();
        assert_eq!(rs.units["s"].status, ledger::Status::Integrated);

        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        // (1) the speculation path recorded the blast-radius audit (record_blast_radius at attempt 0).
        let audits = blast_radius_audits(&events);
        let (unit, safe_recorded, _serialize) = audits
            .first()
            .expect("the speculation path records the blast-radius audit");
        assert_eq!(unit, "s");
        assert!(
            safe_recorded.iter().any(|f| f == "specs/core.md"),
            "the recorded safe view carries the beyond-cap high-risk file: {safe_recorded:?}"
        );
        // (2) the winner's review tier routed FULL over the SAFE view (routing the capped precise
        // seed, which excludes specs/core.md, would have gone light).
        let evidence = review_tier_evidence(&events).expect("a tiers policy logs the routing");
        assert_eq!(
            evidence["review-tier"],
            json!(TIER_FULL),
            "speculation routes the review tier over the safe view: {evidence}"
        );
        assert_eq!(evidence["high-risk-path"], json!("specs/core.md"));
    }

    #[test]
    fn staleness_flags_only_downstream_units_whose_radius_intersects_the_touched_files() {
        // spec 12, unit 2 (the marking authority, in isolation): when a unit integrates
        // touching a file set, EXACTLY the OTHER units whose grounded blast radius intersects
        // those files are stale. Four-unit fixture proving each exclusion: `up` integrates
        // touching `shared.rs`; `near` grounds ONTO `shared.rs` (stale); `far` grounds
        // elsewhere (stands); a `plan` PRODUCER grounds onto `shared.rs` too yet is excluded
        // (it emits a DAG, not a gate verdict to invalidate); and `up` never stales itself.
        let mut stages: BTreeMap<String, Stage> = BTreeMap::new();
        for (name, coverage) in [("up", "up"), ("near", "near"), ("far", "far")] {
            stages.insert(
                name.into(),
                Stage {
                    name: name.into(),
                    coverage: coverage.into(),
                    ..Default::default()
                },
            );
        }
        stages.insert(
            "plan".into(),
            Stage {
                name: "plan".into(),
                coverage: "plan".into(),
                produces: "units".into(),
                ..Default::default()
            },
        );
        let grounder = StubGrounder {
            by_query: HashMap::from([
                ("up".to_string(), vec!["shared.rs".to_string()]),
                (
                    "near".to_string(),
                    vec!["shared.rs".to_string(), "near.rs".to_string()],
                ),
                ("far".to_string(), vec!["far.rs".to_string()]),
                ("plan".to_string(), vec!["shared.rs".to_string()]),
            ]),
        };
        let touched = vec!["shared.rs".to_string()];
        assert_eq!(
            stale_downstream_units(&stages, Some(&grounder), "up", &touched),
            vec!["near".to_string()],
            "only `near` is stale: its radius intersects shared.rs; `up` never stales itself, \
             `far` is disjoint, and the `plan` producer has no gate verdict to invalidate"
        );
        // No grounder => no computable radius => nothing staled (best-effort, exactly like
        // `grounded_seed` returns an empty seed when no grounder is configured).
        assert!(
            stale_downstream_units(&stages, None, "up", &touched).is_empty(),
            "with no grounder there is no blast radius to intersect, so nothing is staled"
        );
    }

    #[test]
    fn staleness_grounds_on_the_safe_superset_so_a_grep_only_reference_still_stales_a_downstream_unit(
    ) {
        // spec 17 unit 3 (3a): stale_downstream_units must ground on the SAFE-superset view, not the
        // precise (name-level) view. A downstream unit whose PRECISE radius misses a reference that
        // is visible only to grep (a macro body / re-export / reflection string) must STILL be marked
        // stale when the integrating unit touches that grep-only file - otherwise its cached green
        // gate verdicts are reused and it integrates against changed code (the fail-open the safe
        // view exists to close). With symbols INACTIVE (safe == precise) the behavior is unchanged.
        let mut stages: BTreeMap<String, Stage> = BTreeMap::new();
        for name in ["up", "hidden"] {
            stages.insert(
                name.into(),
                Stage {
                    name: name.into(),
                    coverage: name.into(),
                    ..Default::default()
                },
            );
        }
        // `hidden`'s PRECISE view is only hidden.rs; its SAFE view adds macros.rs - a reference
        // visible ONLY to grep, exactly the symbols grounder's uncapped structural-union-grep radius.
        let structural = StructuralStubGrounder {
            by_query: HashMap::from([(
                "hidden".to_string(),
                BlastRadius {
                    precise: vec!["hidden.rs".to_string()],
                    safe: vec!["hidden.rs".to_string(), "macros.rs".to_string()],
                    serialize: false,
                },
            )]),
            stamp: "idxhash/ts-tags-v1".to_string(),
        };
        let touched = vec!["macros.rs".to_string()];
        assert_eq!(
            stale_downstream_units(&stages, Some(&structural), "up", &touched),
            vec!["hidden".to_string()],
            "the grep-only reference macros.rs lives in `hidden`'s SAFE view but not its precise \
             view; grounding staleness on the safe superset marks `hidden` stale, closing the \
             cached-green fail-open a precise-only intersection would leave open"
        );

        // Symbols INACTIVE: a grounder that inherits the DEFAULT blast_radius returns safe == precise
        // == ground. `hidden` grounds ONLY to hidden.rs there, so touching the grep-only macros.rs
        // stales nothing - the shipped default is byte-for-byte unchanged.
        let plain = StubGrounder {
            by_query: HashMap::from([("hidden".to_string(), vec!["hidden.rs".to_string()])]),
        };
        assert!(
            stale_downstream_units(&stages, Some(&plain), "up", &touched).is_empty(),
            "with symbols inactive safe == precise, so a grep-only file outside the precise radius \
             stales nothing - the default path is unchanged"
        );
    }

    #[test]
    fn rule6_conflict_detection_grounds_on_the_safe_superset_so_a_grep_only_shared_reference_conflicts(
    ) {
        // spec 17 unit 3 (3b): dag_unit_blast_radii must feed rule-6 conflict detection the
        // SAFE-superset view, not the precise seed. Two units whose PRECISE radii are DISJOINT but
        // whose SAFE radii both include one grep-only file (a shared macro / re-export) TRULY share a
        // blast radius; grounding the analysis on the safe superset detects them as conflicting at
        // decomposition time. On the precise view the shared grep-only file is invisible and the
        // conflict is missed. With symbols INACTIVE (safe == precise) the two disjoint units raise
        // nothing - the shipped default is unchanged.
        let mut stages: BTreeMap<String, Stage> = BTreeMap::new();
        for name in ["u1", "u2"] {
            stages.insert(
                name.into(),
                Stage {
                    name: name.into(),
                    agent: "worker".into(),
                    coverage: name.into(),
                    ..Default::default()
                },
            );
        }
        // Precise radii are disjoint (u1.rs vs u2.rs); both SAFE radii add shared_macro.rs, a
        // reference visible only to grep that both units truly reach.
        let structural = StructuralStubGrounder {
            by_query: HashMap::from([
                (
                    "u1".to_string(),
                    BlastRadius {
                        precise: vec!["u1.rs".to_string()],
                        safe: vec!["u1.rs".to_string(), "shared_macro.rs".to_string()],
                        serialize: false,
                    },
                ),
                (
                    "u2".to_string(),
                    BlastRadius {
                        precise: vec!["u2.rs".to_string()],
                        safe: vec!["u2.rs".to_string(), "shared_macro.rs".to_string()],
                        serialize: false,
                    },
                ),
            ]),
            stamp: "idxhash/ts-tags-v1".to_string(),
        };
        let cfg = Config::default();
        let store = Store::open(":memory:").unwrap();
        let driver = Stub::new();
        let runner = RecordingRunner::new(&[]);
        let none: HashSet<String> = HashSet::new();
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &runner,
            repo: String::new(),
            grounder: Some(&structural),
            graph: None,
            criteria: Vec::new(),
        };
        let ctx = RunCtx::for_test(&cfg, &deps);
        let radii = ctx.dag_unit_blast_radii(&stages, "gate", &none, &none);
        let conflicts = blast_radius_conflicts(&radii);
        assert_eq!(
            conflicts,
            vec![(
                "u1".to_string(),
                "u2".to_string(),
                vec!["shared_macro.rs".to_string()]
            )],
            "u1 and u2 have DISJOINT precise seeds but share the grep-only shared_macro.rs in their \
             safe views; grounding rule-6 detection on the safe superset surfaces the conflict a \
             precise-only analysis would miss: {radii:?}"
        );

        // Symbols INACTIVE: a StubGrounder inherits the DEFAULT blast_radius (safe == precise), so
        // each unit's safe radius is just its disjoint precise seed and no conflict is raised - the
        // shipped default decomposition analysis is byte-for-byte unchanged.
        let plain = StubGrounder {
            by_query: HashMap::from([
                ("u1".to_string(), vec!["u1.rs".to_string()]),
                ("u2".to_string(), vec!["u2.rs".to_string()]),
            ]),
        };
        let plain_deps = Deps {
            store: &store,
            driver: &driver,
            gates: &runner,
            repo: String::new(),
            grounder: Some(&plain),
            graph: None,
            criteria: Vec::new(),
        };
        let plain_ctx = RunCtx::for_test(&cfg, &plain_deps);
        let plain_radii = plain_ctx.dag_unit_blast_radii(&stages, "gate", &none, &none);
        assert!(
            blast_radius_conflicts(&plain_radii).is_empty(),
            "with symbols inactive safe == precise; the two disjoint units share no file and raise \
             no rule-6 conflict: {plain_radii:?}"
        );
    }

    #[test]
    fn a_resume_reseeds_the_stale_set_from_the_prior_unitintegrated_marks() {
        // spec 12, unit 2 (replay determinism): a stepwise resume recovers the STALE set
        // purely from the log - every unit named in a prior UnitIntegrated META_STALE mark,
        // comma-joined, empty segments ignored - so a stale unit keeps stopping-to-hit across
        // the process boundary. A mark on a NON-UnitIntegrated event is ignored (only the
        // integration event carries the invalidation).
        let events = vec![
            Event::new(ledger::TYPE_UNIT_INTEGRATED, br#"{"id":"alpha"}"#.to_vec())
                .with_meta(META_STALE, "beta,delta"),
            // A second integration adds another stale unit and tolerates a trailing empty.
            Event::new(ledger::TYPE_UNIT_INTEGRATED, br#"{"id":"beta"}"#.to_vec())
                .with_meta(META_STALE, "epsilon,"),
            // An integration that staled nobody carries no mark.
            Event::new(ledger::TYPE_UNIT_INTEGRATED, br#"{"id":"gamma"}"#.to_vec()),
            // A stray mark on some OTHER event type must never seed the set.
            Event::new(ledger::TYPE_UNIT_STATUS, br#"{"id":"zeta"}"#.to_vec())
                .with_meta(META_STALE, "zeta"),
        ];
        let seeded = stale_units_from_log(&events);
        let mut got: Vec<String> = seeded.into_iter().collect();
        got.sort();
        assert_eq!(
            got,
            vec![
                "beta".to_string(),
                "delta".to_string(),
                "epsilon".to_string()
            ],
            "the stale set is exactly the units named across the UnitIntegrated marks"
        );
    }

    /// Drives the staleness end-to-end fixture. `alpha` (upstream) writes `shared.rs` (whose
    /// content carries `beta`'s grounding keyword) and its adjudicator approves immediately,
    /// so it integrates first. `beta`/`gamma` (downstream, needing alpha) each write their
    /// OWN file with STABLE content and reject attempt 0 then approve attempt 1, so each
    /// re-gates an IDENTICAL tree - a content cache-hit unless staleness refuses it.
    struct StaleDriver;
    impl AgentDriver for StaleDriver {
        fn spawn(
            &self,
            _a: &AgentDef,
            _prompt: &str,
            opts: &SpawnOpts,
            _emit: &dyn Fn(&str, Value) -> Result<(), Error>,
        ) -> Result<AgentResult, Error> {
            let unit = opts.id.split('/').next().unwrap_or_default();
            let attempt = attempt_of(&opts.id);
            if opts.id.contains("/implementer#") {
                if !opts.dir.is_empty() {
                    let (file, content) = match unit {
                        // alpha's touched file, carrying beta's grounding keyword `widget`.
                        "alpha" => ("shared.rs", "// widget helper\n"),
                        // beta/gamma each write their OWN file with fixed content, so their
                        // attempt-0 and attempt-1 trees are byte-identical (a hit candidate).
                        "beta" => ("beta_work.rs", "fn beta() {}\n"),
                        _ => ("gamma_work.rs", "fn gamma() {}\n"),
                    };
                    std::fs::write(Path::new(&opts.dir).join(file), content).unwrap();
                }
                return Ok(AgentResult::default());
            }
            if opts.id.contains("/adjudicator#") {
                // alpha integrates on attempt 0; beta/gamma reject once then approve, so each
                // reaches an attempt-1 re-gate over its identical tree.
                let approve_at = if unit == "alpha" { 0 } else { 1 };
                let out = if attempt >= approve_at {
                    r#"{"verdict":"approve"}"#
                } else {
                    r#"{"verdict":"reject","issues":[]}"#
                };
                return Ok(AgentResult {
                    output: out.into(),
                    resolved_model: String::new(),
                });
            }
            Ok(AgentResult {
                output: "reviewed the diff".into(),
                resolved_model: String::new(),
            })
        }
    }

    #[test]
    fn integrating_a_unit_stales_the_intersecting_downstream_units_cached_verdict_not_the_rest() {
        // spec 12, unit 2 (end-to-end, three-unit dependency fixture): integrating `alpha`
        // (touching `shared.rs`) marks EXACTLY the downstream units whose blast radius
        // intersects `shared.rs` stale - `beta` grounds onto it, `gamma` does not. The stale
        // unit's cached verdicts STOP HITTING: `beta` re-gates its identical attempt-1 tree
        // for real instead of taking the content cache-hit its attempt-0 green would answer,
        // while the unaffected `gamma` still hits and its green STANDS.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();
        // `gamma` grounds onto a file present from the base (a grep grounder searches file
        // CONTENT for the coverage word); `beta` grounds onto shared.rs, which alpha creates.
        std::fs::write(repo.path().join("gamma_only.rs"), "// gizmo lives here\n").unwrap();
        for args in [&["add", "-A"][..], &["commit", "-q", "-m", "fixture"][..]] {
            std::process::Command::new("git")
                .arg("-C")
                .arg(&repo_path)
                .args(args)
                .output()
                .unwrap();
        }
        let grep = crate::grounder::Grep {
            root: repo_path.clone(),
        };

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("lens".into(), agent("lens"));
        cfg.agents.insert("judge".into(), agent("judge"));
        cfg.workflow.gates.insert("g".into(), gate_def("true"));
        let panel = crate::config::ReviewPanel {
            lenses: vec!["lens".into()],
            adjudicator: "judge".into(),
            ..Default::default()
        };
        // alpha upstream (its coverage grounds onto no touched file, so it stales nobody by
        // its own name); beta grounds onto shared.rs (`widget`); gamma onto gamma_only.rs
        // (`gizmo`). beta/gamma depend on alpha so they run only AFTER it integrated + marked.
        let mk = |name: &str, coverage: &str, needs: Vec<String>| Stage {
            name: name.into(),
            agent: "worker".into(),
            coverage: coverage.into(),
            gates: vec!["g".into()],
            on_pass: "merge".into(),
            needs,
            review: panel.clone(),
            ..Default::default()
        };
        cfg.workflow
            .stages
            .insert("alpha".into(), mk("alpha", "alpha", vec![]));
        cfg.workflow
            .stages
            .insert("beta".into(), mk("beta", "widget", vec!["alpha".into()]));
        cfg.workflow
            .stages
            .insert("gamma".into(), mk("gamma", "gizmo", vec!["alpha".into()]));

        let store = Store::open(":memory:").unwrap();
        let driver = StaleDriver;
        let runner = RecordingRunner::new(&[]);
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &runner,
            repo: repo_path.clone(),
            grounder: Some(&grep),
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();
        for name in ["alpha", "beta", "gamma"] {
            assert_eq!(
                rs.units[name].status,
                ledger::Status::Integrated,
                "{name} must integrate"
            );
        }

        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        // The `META_STALE` mark on a unit's UnitIntegrated event, if any.
        let staled_by = |unit: &str| -> Option<String> {
            events
                .iter()
                .find(|e| {
                    e.type_ == ledger::TYPE_UNIT_INTEGRATED
                        && serde_json::from_slice::<Value>(&e.data)
                            .ok()
                            .and_then(|v| v.get("id").and_then(Value::as_str).map(str::to_string))
                            .as_deref()
                            == Some(unit)
                })
                .and_then(|e| e.meta.get(META_STALE).cloned())
        };
        // (1) MARKING: alpha's integration stales EXACTLY beta - never gamma (disjoint
        // radius) and never itself; beta/gamma touch no downstream radius, so they stale none.
        assert_eq!(
            staled_by("alpha").as_deref(),
            Some("beta"),
            "alpha's integration stales exactly beta, whose blast radius intersects shared.rs"
        );
        assert!(
            staled_by("beta").is_none() && staled_by("gamma").is_none(),
            "beta and gamma touch no downstream blast radius, so their integrations stale nobody"
        );

        // (2) CACHE STOPS HITTING vs GREEN STANDS: both re-gate an identical attempt-1 tree,
        // but the stale beta re-runs (no cache-hit) while the unaffected gamma hits.
        let verdict = |unit: &str, attempt: u32| -> &Event {
            let key = format!("{unit}/gate:g#{attempt}");
            events
                .iter()
                .find(|e| {
                    e.type_ == contextgraph::TYPE_GATE_VERDICT
                        && e.meta.get(META_REPLAY_KEY) == Some(&key)
                })
                .unwrap_or_else(|| panic!("no gate verdict recorded for {key}"))
        };
        assert!(
            !verdict("beta", 1).meta.contains_key(META_CACHE_HIT),
            "beta is stale, so its attempt-1 gate RE-RAN rather than reuse its attempt-0 green"
        );
        assert!(
            verdict("gamma", 1).meta.contains_key(META_CACHE_HIT),
            "gamma is unaffected, so its identical attempt-1 tree still cache-hits - green stands"
        );
    }

    #[test]
    fn glob_matches_supports_star_doublestar_and_literals() {
        // `*` is one path segment; `**` spans segments (with an optional separator); `?` is one
        // non-`/` char; a bare path is an exact match. These are the semantics gate `inputs:`
        // globs are selected by (spec 12, unit 3).
        assert!(glob_matches("src/conductor.rs", "src/conductor.rs"));
        assert!(!glob_matches("src/conductor.rs", "src/gate.rs"));
        assert!(glob_matches("src/*.rs", "src/gate.rs"));
        assert!(
            !glob_matches("src/*.rs", "src/contextgraph/mod.rs"),
            "* does not cross /"
        );
        assert!(
            glob_matches("src/**/*.rs", "src/contextgraph/mod.rs"),
            "** crosses /"
        );
        assert!(glob_matches("src/**", "src/anything/deep.rs"));
        assert!(
            glob_matches("a/**/b.rs", "a/b.rs"),
            "** matches zero directories"
        );
        assert!(glob_matches("a/**/b.rs", "a/x/y/b.rs"));
        assert!(glob_matches("gate?.rs", "gate1.rs"));
        assert!(!glob_matches("gate?.rs", "gate12.rs"));
        // A regex metacharacter in the pattern is a literal, not a wildcard.
        assert!(glob_matches("a.b", "a.b"));
        assert!(!glob_matches("a.b", "axb"), ". is escaped to a literal dot");
    }

    #[test]
    fn gate_intersects_radius_runs_unscoped_and_intersecting_gates_only() {
        // A gate with NO inputs is unscoped and always runs; a scoped gate runs iff a glob hits a
        // blast-radius file (spec 12, unit 3).
        let radius = vec!["src/conductor.rs".to_string(), "src/gate.rs".to_string()];
        assert!(
            gate_intersects_radius(&[], &radius),
            "an unscoped gate (no inputs) always runs"
        );
        assert!(gate_intersects_radius(
            &["src/gate.rs".to_string()],
            &radius
        ));
        assert!(gate_intersects_radius(
            &["src/**/*.rs".to_string()],
            &radius
        ));
        assert!(
            !gate_intersects_radius(&["docs/**".to_string()], &radius),
            "a gate whose inputs miss every blast-radius file is skipped"
        );
        assert!(
            !gate_intersects_radius(&["src/gate.rs".to_string()], &[]),
            "an empty blast radius intersects no scoped gate"
        );
    }

    #[test]
    fn blast_radius_narrows_the_inner_loop_and_the_integrate_step_runs_the_full_library() {
        // spec 12, unit 3 (end-to-end): during the implement/remediate INNER LOOP only the gates
        // whose `inputs:` intersect the unit's grounded blast radius run; the rest are SKIPPED and
        // LOGGED (never silent). The INTEGRATE step then runs the EXHAUSTIVE library, so "done" is
        // asserted against the full suite. Unit `s` grounds onto `src/near.rs`; gate `near`
        // (`inputs: [src/near.rs]`) intersects and runs inline, while gate `far`
        // (`inputs: [docs/far.md]`) does NOT - it is skipped inline and run only at integrate.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();

        // A canned blast radius for unit `s`, so the intersection is deterministic regardless of
        // what the implementer's stub actually writes.
        let grounder = StubGrounder {
            by_query: HashMap::from([("s".to_string(), vec!["src/near.rs".to_string()])]),
        };

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("lens".into(), agent("lens"));
        cfg.agents.insert("judge".into(), agent("judge"));
        // Distinct commands so the two gates have DISTINCT content addresses (spec 12, unit 1):
        // otherwise `far` would content-cache-hit `near`'s green over the identical tree and
        // never actually run - the test would not prove the integrate step EXECUTES the gate the
        // inner loop skipped.
        cfg.workflow.gates.insert(
            "near".into(),
            gate_def_inputs("near-check", &["src/near.rs"]),
        );
        cfg.workflow
            .gates
            .insert("far".into(), gate_def_inputs("far-check", &["docs/far.md"]));
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                coverage: "s".into(),
                gates: vec!["near".into(), "far".into()],
                on_pass: "merge".into(),
                review: crate::config::ReviewPanel {
                    lenses: vec!["lens".into()],
                    adjudicator: "judge".into(),
                    ..Default::default()
                },
                ..Default::default()
            },
        );

        let store = Store::open(":memory:").unwrap();
        let driver = CacheDriver {
            contents: vec!["work\n".into()],
            approve_at: 0,
        };
        let runner = RecordingRunner::new(&[]);
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &runner,
            repo: repo_path,
            grounder: Some(&grounder),
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();
        assert_eq!(
            rs.units["s"].status,
            ledger::Status::Integrated,
            "the unit integrates once its exhaustive suite is green"
        );

        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        let find_key = |key: &str| -> Option<&Event> {
            events.iter().find(|e| {
                e.type_ == contextgraph::TYPE_GATE_VERDICT
                    && e.meta.get(META_REPLAY_KEY) == Some(&key.to_string())
            })
        };

        // (1) INNER-LOOP NARROWING + SKIP LOGGING: `far` (its inputs miss the blast radius) is
        // SKIPPED in the inner loop and logged as a `skipped` GateVerdict carrying a reason;
        // `near` (its inputs intersect) is NOT skipped.
        let skip = find_key("s/gate-skip:far#0")
            .expect("far is skipped-and-logged in the blast-radius-narrowed inner loop");
        let skip_v: Value = serde_json::from_slice(&skip.data).unwrap();
        assert_eq!(
            skip_v["skipped"],
            json!(true),
            "the skip verdict is explicitly marked skipped"
        );
        assert!(
            skip_v["evidence"]
                .as_str()
                .unwrap_or_default()
                .contains("skipped"),
            "the skip carries its reason (never silent): {skip_v}"
        );
        assert!(
            !skip.meta.contains_key(META_INPUT_DIGEST),
            "a skip carries no content digest, so it never seeds the content cache"
        );
        assert!(
            find_key("s/gate-skip:near#0").is_none(),
            "near intersects the blast radius, so the inner loop does NOT skip it"
        );

        // (2) EXHAUSTIVE INTEGRATE: by integration the FULL library ran - `far`, skipped inline,
        // has a REAL run verdict (distinct from its skip), and the runner executed both gates.
        let far_run =
            find_key("s/gate:far#0").expect("far RUNS at the exhaustive integrate step (R6)");
        let far_run_v: Value = serde_json::from_slice(&far_run.data).unwrap();
        assert!(
            far_run_v.get("skipped").is_none(),
            "the integrate-step run of far is a REAL verdict, not a skip: {far_run_v}"
        );
        assert!(
            skip.position < far_run.position,
            "far was SKIPPED in the inner loop first, then RUN at the integrate step"
        );
        assert!(
            find_key("s/gate:near#0").is_some(),
            "near ran inline in the inner loop"
        );
        let calls = runner.calls();
        assert!(
            calls.contains(&"near".to_string()) && calls.contains(&"far".to_string()),
            "both gates ran by integrate time - the integrate step runs the full library: {calls:?}"
        );
        assert_eq!(
            calls.iter().filter(|c| c.as_str() == "far").count(),
            1,
            "far's COMMAND ran exactly once - the exhaustive integrate step; the inner loop \
             skipped it and unit 5's post-merge re-gate CACHE-HIT its green (a clean \
             fast-forward changed nothing), so the runner was never invoked a second time: \
             {calls:?}"
        );

        // (3) A skip is not a gate run: the operator metrics never count the `gate-skip:far#0`
        // verdict as a `far` pass. `far` tallies TWO green verdicts - the exhaustive integrate
        // RUN and unit 5's post-merge re-gate, which cache-hit the same green and is logged with
        // provenance (spec 12 global: cache-hits are ALWAYS logged) - both real `pass:true`
        // verdicts the metrics count, exactly like unit 1's cache-hits elsewhere. The SKIP is
        // excluded (like the artifact-tagged integrate bookkeeping), which is what this asserts.
        let m = crate::metrics::project(&events);
        assert_eq!(
            m.gates.get("far").map(|c| c.pass).unwrap_or_default(),
            2,
            "the metrics count far's REAL integrate run and its logged post-merge cache-hit, \
             but NEVER its skip"
        );
    }

    #[test]
    fn a_gate_skipped_inline_but_red_at_the_exhaustive_integrate_door_blocks_the_merge() {
        // spec 12, unit 3 - the R6 safety property (done-when line 25: "integrate ALWAYS runs
        // the full library"). The e2e happy-path test proves the exhaustive integrate step RUNS
        // a gate the inner loop skipped; this test proves the OTHER half - that a RED there
        // BLOCKS the merge and feeds remediation. Without it the `if full.pass` guard at the
        // integrate door is unpinned: a mutation that integrates regardless of the exhaustive
        // result survives the whole suite, because no other test fails a gate at the integrate
        // step. Here gate `far` (`inputs: [docs/far.md]`) misses unit `s`'s blast radius
        // (`src/near.rs`), so the inner loop SKIPS it every attempt - it is red ONLY at the
        // exhaustive integrate door, which is exactly where R6 must catch it.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();

        let grounder = StubGrounder {
            by_query: HashMap::from([("s".to_string(), vec!["src/near.rs".to_string()])]),
        };

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("lens".into(), agent("lens"));
        cfg.agents.insert("judge".into(), agent("judge"));
        // Bound the remediation loop: attempt 0 fails the integrate door and RETRIES, attempt 1
        // fails it again and escalates (`remediate` escalates when attempts >= max), so the unit
        // terminates deterministically without integrating and the integrate door is exercised
        // on a genuine retry.
        cfg.workflow.defaults.max_retries = 2;
        cfg.workflow.gates.insert(
            "near".into(),
            gate_def_inputs("near-check", &["src/near.rs"]),
        );
        cfg.workflow
            .gates
            .insert("far".into(), gate_def_inputs("far-check", &["docs/far.md"]));
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                coverage: "s".into(),
                gates: vec!["near".into(), "far".into()],
                on_pass: "merge".into(),
                review: crate::config::ReviewPanel {
                    lenses: vec!["lens".into()],
                    adjudicator: "judge".into(),
                    ..Default::default()
                },
                ..Default::default()
            },
        );

        let store = Store::open(":memory:").unwrap();
        let driver = CacheDriver {
            contents: vec!["work\n".into()],
            approve_at: 0,
        };
        // `far` FAILS every run; `near` (and everything else) passes. So the inner loop is
        // GREEN (it skips far), the adjudicator APPROVES, and the ONLY thing standing between
        // the unit and a merge is the exhaustive integrate door running the skipped `far`.
        let runner = RecordingRunner::new(&["far"]);
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &runner,
            repo: repo_path,
            grounder: Some(&grounder),
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        // (1) THE MERGE IS BLOCKED: the exhaustive integrate door went red, so the unit never
        // integrates - it exhausts its retries and escalates. A mutation that integrated on a
        // red exhaustive suite would land the unit as Integrated here.
        assert_eq!(
            rs.units["s"].status,
            ledger::Status::Escalated,
            "a red exhaustive integrate door must BLOCK the merge, not land the unit"
        );

        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        assert!(
            !events
                .iter()
                .any(|e| e.type_ == ledger::TYPE_UNIT_INTEGRATED),
            "no UnitIntegrated may be emitted - a tree that fails the full suite never lands"
        );

        let find_key = |key: &str| -> Option<&Event> {
            events.iter().find(|e| {
                e.type_ == contextgraph::TYPE_GATE_VERDICT
                    && e.meta.get(META_REPLAY_KEY) == Some(&key.to_string())
            })
        };

        // (2) IT WAS THE SKIPPED GATE, RUN AT INTEGRATE, THAT BLOCKED IT: `far` is skipped in
        // the inner loop (only a skip verdict inline) yet has a REAL, RED run verdict from the
        // exhaustive integrate pass. This is the whole point of R6 - a gate the narrowed inner
        // loop never ran still gets asserted before the unit can land.
        assert!(
            find_key("s/gate-skip:far#0").is_some(),
            "far is skipped in the blast-radius-narrowed inner loop"
        );
        let far_run =
            find_key("s/gate:far#0").expect("far RUNS at the exhaustive integrate door (R6)");
        let far_run_v: Value = serde_json::from_slice(&far_run.data).unwrap();
        assert_eq!(
            far_run_v["pass"],
            json!(false),
            "the integrate-door run of far is REAL and RED - its failure is what blocks the merge"
        );
        assert!(
            far_run_v.get("skipped").is_none(),
            "the integrate-door run of far is a real verdict, not a skip: {far_run_v}"
        );

        // (3) THE RED FED REMEDIATION: the unit re-entered its lifecycle (a second attempt ran
        // far at the integrate door again) before escalating - the failure is not swallowed, it
        // drives another attempt exactly like an inner-loop gate failure.
        let far_runs = runner
            .calls()
            .iter()
            .filter(|c| c.as_str() == "far")
            .count();
        assert!(
            far_runs >= 2,
            "the integrate-door red must feed remediation: far re-runs at the door on the retry \
             (saw {far_runs} far runs)"
        );
    }

    #[test]
    fn verdict_compensates_names_a_prior_unit_independent_of_approval() {
        // spec 12, unit 4: the `compensate` field on the last JSON verdict line naming a
        // prior integrated unit is parsed INDEPENDENTLY of approve/reject - a review may
        // approve its own unit yet still name an integrated unit as the defect source.
        assert_eq!(
            verdict_compensates(r#"{"verdict":"approve","compensate":"unit-a"}"#).as_deref(),
            Some("unit-a"),
            "an approving verdict can still name a prior unit for compensation"
        );
        assert_eq!(
            verdict_compensates(r#"{"verdict":"reject","compensate":"unit-x"}"#).as_deref(),
            Some("unit-x"),
            "a rejecting verdict can name a prior unit for compensation too"
        );
        // The LAST json line with a `compensate` field wins, mirroring verdict_approves.
        assert_eq!(
            verdict_compensates(
                "{\"compensate\":\"first\"}\n{\"verdict\":\"approve\",\"compensate\":\"last\"}"
            )
            .as_deref(),
            Some("last")
        );
        // No field, empty field, or non-JSON is simply no compensation - never a silent one.
        assert_eq!(verdict_compensates(r#"{"verdict":"approve"}"#), None);
        assert_eq!(
            verdict_compensates(r#"{"verdict":"reject","compensate":"  "}"#),
            None
        );
        assert_eq!(verdict_compensates("no json here"), None);
    }

    /// A driver for the compensation e2e test (spec 12, unit 4): each unit's IMPLEMENTER
    /// writes its OWN file (so the two units touch disjoint paths and revert cleanly), and
    /// the driver records every implementer prompt per unit so the test can prove the
    /// RE-ENTERED unit was prompted with the contradiction. `unit-a`'s adjudicator always
    /// approves; `unit-b`'s adjudicator approves ITS OWN work but names `unit-a` as the
    /// defect source (`compensate`) - the seeded two-unit contradiction (a later unit's work
    /// proves a prior integrated unit wrong).
    struct CompDriver {
        impl_prompts: Mutex<HashMap<String, Vec<String>>>,
    }
    impl AgentDriver for CompDriver {
        fn spawn(
            &self,
            _a: &AgentDef,
            prompt: &str,
            opts: &SpawnOpts,
            _emit: &dyn Fn(&str, Value) -> Result<(), Error>,
        ) -> Result<AgentResult, Error> {
            let unit = opts.id.split('/').next().unwrap_or_default();
            if opts.id.contains("/implementer#") {
                self.impl_prompts
                    .lock()
                    .unwrap()
                    .entry(unit.to_string())
                    .or_default()
                    .push(prompt.to_string());
                if !opts.dir.is_empty() {
                    let (file, content) = match unit {
                        "unit-a" => ("a.rs", "fn a() {}\n"),
                        _ => ("b.rs", "fn b() {}\n"),
                    };
                    std::fs::write(Path::new(&opts.dir).join(file), content).unwrap();
                }
                return Ok(AgentResult::default());
            }
            if opts.id.contains("/adjudicator#") {
                // unit-b's own work is fine (approve), but its work PROVES unit-a wrong, so it
                // names unit-a for compensation. unit-a's own re-review approves cleanly (no
                // further compensation), so the run converges.
                let out = if unit == "unit-b" {
                    r#"{"verdict":"approve","compensate":"unit-a"}"#
                } else {
                    r#"{"verdict":"approve"}"#
                };
                return Ok(AgentResult {
                    output: out.into(),
                    resolved_model: String::new(),
                });
            }
            Ok(AgentResult {
                output: "reviewed the diff".into(),
                resolved_model: String::new(),
            })
        }
    }

    #[test]
    fn a_contradiction_compensates_reverts_and_re_enters_the_integrated_unit() {
        // spec 12, unit 4 (end-to-end, seeded two-unit contradiction - done-when line 26):
        // `unit-a` integrates; then `unit-b`'s review proves it wrong (its adjudicator names
        // unit-a as the defect source). The conductor RECORDS the compensation (as
        // `UnitCompensated` metadata on the existing `UnitFailed` vocabulary), REVERTS unit-a's
        // integrating commit on the run branch, and RE-ENTERS unit-a into remediation with the
        // contradiction as feedback - whereupon unit-a re-implements (now PROMPTED with the
        // contradiction) and re-integrates, so the run converges.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("lens".into(), agent("lens"));
        cfg.agents.insert("judge".into(), agent("judge"));
        cfg.workflow.gates.insert("g".into(), gate_def("true"));
        let panel = crate::config::ReviewPanel {
            lenses: vec!["lens".into()],
            adjudicator: "judge".into(),
            ..Default::default()
        };
        let mk = |name: &str, needs: Vec<String>| Stage {
            name: name.into(),
            agent: "worker".into(),
            gates: vec!["g".into()],
            on_pass: "merge".into(),
            needs,
            review: panel.clone(),
            ..Default::default()
        };
        // unit-b needs unit-a, so unit-a integrates FIRST and then unit-b's review can prove
        // that already-integrated unit-a wrong.
        cfg.workflow
            .stages
            .insert("unit-a".into(), mk("unit-a", vec![]));
        cfg.workflow
            .stages
            .insert("unit-b".into(), mk("unit-b", vec!["unit-a".into()]));

        let store = Store::open(":memory:").unwrap();
        let driver = CompDriver {
            impl_prompts: Mutex::new(HashMap::new()),
        };
        let runner = RecordingRunner::new(&[]);
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &runner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        // CONVERGENCE: unit-a re-integrated after its rollback; unit-b integrated.
        assert_eq!(
            rs.units["unit-a"].status,
            ledger::Status::Integrated,
            "unit-a re-integrates after its compensation rollback"
        );
        assert_eq!(
            rs.units["unit-b"].status,
            ledger::Status::Integrated,
            "unit-b integrates"
        );

        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        let unit_of = |e: &Event| -> Option<String> {
            serde_json::from_slice::<Value>(&e.data)
                .ok()
                .and_then(|v| v.get("id").and_then(Value::as_str).map(str::to_string))
        };
        // unit-a's FIRST integrating commit - the one the contradiction condemns.
        let first_a_commit = events
            .iter()
            .find(|e| {
                e.type_ == ledger::TYPE_UNIT_INTEGRATED && unit_of(e).as_deref() == Some("unit-a")
            })
            .and_then(|e| serde_json::from_slice::<Value>(&e.data).ok())
            .and_then(|v| v.get("commit").and_then(Value::as_str).map(str::to_string))
            .filter(|c| !c.is_empty())
            .expect("unit-a integrated with a real commit");

        // (1) COMPENSATION RECORDED on existing vocabulary: a `UnitFailed` for unit-a carries
        // the reverted commit in META_COMPENSATED - the `UnitCompensated` record, no new event
        // type - naming exactly unit-a's first integrating commit for provenance.
        let compensated = events
            .iter()
            .find(|e| {
                e.type_ == ledger::TYPE_UNIT_FAILED
                    && unit_of(e).as_deref() == Some("unit-a")
                    && e.meta.contains_key(META_COMPENSATED)
            })
            .expect("a UnitCompensated (UnitFailed + META_COMPENSATED) records unit-a's rollback");
        assert_eq!(
            compensated.meta.get(META_COMPENSATED).map(String::as_str),
            Some(first_a_commit.as_str()),
            "the compensation names unit-a's reverted integrating commit"
        );
        assert!(
            compensated
                .meta
                .get(META_CONTRADICTION)
                .is_some_and(|r| r.contains("compensate")),
            "the compensation carries the contradiction reason for provenance and feedback"
        );

        // (2) REVERTED ON THE RUN BRANCH, in an EVENTED (not history-rewriting) rollback: the
        // run branch carries a compensation revert commit for unit-a.
        let log = std::process::Command::new("git")
            .arg("-C")
            .arg(&repo_path)
            .args(["log", "--pretty=%s"])
            .output()
            .unwrap();
        let log = String::from_utf8_lossy(&log.stdout);
        assert!(
            log.lines().any(|l| l.contains("compensate unit-a")),
            "the run branch carries an evented revert of unit-a's integrating commit; log:\n{log}"
        );

        // (3) RE-ENTERED INTO REMEDIATION WITH THE CONTRADICTION AS FEEDBACK: unit-a's
        // implementer ran a SECOND time, and its re-entry prompt names the reverted commit as
        // the contradiction to fix - not a blind restart.
        let prompts = driver
            .impl_prompts
            .lock()
            .unwrap()
            .get("unit-a")
            .cloned()
            .unwrap_or_default();
        assert_eq!(
            prompts.len(),
            2,
            "unit-a implements once, then RE-implements after being compensated"
        );
        assert!(
            prompts[1].contains("your integrating commit was REVERTED"),
            "the re-entered unit-a is prompted with the contradiction as feedback; prompt:\n{}",
            prompts[1]
        );

        // (4) THE TRIGGER IS DURABLE (spec 12, unit 4): the compensation is queued via an
        // evented, fold-neutral UnitStatus mark (META_COMPENSATE_TARGET) the MOMENT the review
        // names unit-a - not held only in the in-memory queue - so a crash before the drain
        // does not drop the rollback. Exactly one such mark names unit-a, and it is BALANCED by
        // the drained UnitFailed, so a resume re-derives NOTHING still pending.
        let queued_marks: Vec<&Event> = events
            .iter()
            .filter(|e| e.meta.get(META_COMPENSATE_TARGET).map(String::as_str) == Some("unit-a"))
            .collect();
        assert_eq!(
            queued_marks.len(),
            1,
            "the compensation trigger records exactly one durable compensation-queued mark for unit-a"
        );
        assert_eq!(
            queued_marks[0].type_,
            ledger::TYPE_UNIT_STATUS,
            "the durable trigger rides the existing UnitStatus vocabulary (no new event type)"
        );
        assert!(
            pending_compensations_from_log(&events).is_empty(),
            "the in-run drain balances the queued mark, so a resume re-derives no pending compensation"
        );
    }

    #[test]
    fn pending_compensations_from_log_re_derives_only_undrained_marks() {
        // spec 12, unit 4 (crash-resume recovery): a durable compensation-queued mark
        // (META_COMPENSATE_TARGET) that has NOT been drained (no matching UnitFailed +
        // META_COMPENSATED for the target) is re-derived as PENDING so a resume re-drives the
        // reverse gear; a mark already balanced by its drain is NOT re-derived (idempotent over
        // the log). This pins the crash-window recovery the ephemeral in-memory queue missed.
        let queued = |target: &str, reason: &str| {
            Event::new(
                ledger::TYPE_UNIT_STATUS,
                serde_json::to_vec(&json!({"id": target, "status": STATUS_COMPENSATION_QUEUED}))
                    .unwrap(),
            )
            .with_meta(META_COMPENSATE_TARGET, target)
            .with_meta(META_CONTRADICTION, reason)
        };
        let drained = |target: &str| {
            Event::new(
                ledger::TYPE_UNIT_FAILED,
                serde_json::to_vec(&json!({"id": target, "attempts": 1})).unwrap(),
            )
            .with_meta(META_COMPENSATED, "deadbeef")
            .with_meta(META_CONTRADICTION, "x")
        };

        // A queued-but-never-drained mark (the crash window) is pending, carrying its reason.
        let pending = pending_compensations_from_log(&[queued("unit-a", "the contradiction")]);
        assert_eq!(
            pending.len(),
            1,
            "an undrained queue mark is re-derived as pending"
        );
        assert_eq!(pending[0].target, "unit-a");
        assert_eq!(
            pending[0].reason, "the contradiction",
            "the re-derived compensation carries the recorded contradiction for feedback"
        );

        // A mark BALANCED by its drain is not re-derived - a completed compensation never
        // re-runs on resume.
        assert!(
            pending_compensations_from_log(&[queued("unit-a", "r"), drained("unit-a")]).is_empty(),
            "a drained compensation is not re-queued"
        );

        // Two cycles for one target: mark, drain, re-integrate, mark again, crash before the
        // second drain -> exactly ONE (the second) is pending, the first stays consumed.
        let two_cycles = pending_compensations_from_log(&[
            queued("unit-a", "first"),
            drained("unit-a"),
            queued("unit-a", "second"),
        ]);
        assert_eq!(
            two_cycles.len(),
            1,
            "only the unconsumed second cycle is pending"
        );
        assert_eq!(two_cycles[0].reason, "second");

        // No marks at all -> nothing pending (a fresh run / a run with no compensation).
        assert!(pending_compensations_from_log(&[drained("unit-a")]).is_empty());
    }

    #[test]
    fn a_durable_compensation_queued_mark_is_fold_neutral_on_the_target() {
        // spec 12, unit 4: the compensation-queued mark must NOT fold the target out of
        // `Integrated` - it must stay integrated until the drain actually reverts it, else a
        // resume would re-schedule it BEFORE the revert and re-implement on the un-reverted
        // branch. Guards the fold-neutrality of STATUS_COMPENSATION_QUEUED against a future
        // Status variant silently capturing it.
        let mut state = ledger::RunState::default();
        state
            .apply(&Event::new(
                ledger::TYPE_UNIT_INTEGRATED,
                serde_json::to_vec(&json!({"id": "unit-a", "commit": "c0"})).unwrap(),
            ))
            .unwrap();
        assert_eq!(state.units["unit-a"].status, ledger::Status::Integrated);
        state
            .apply(
                &Event::new(
                    ledger::TYPE_UNIT_STATUS,
                    serde_json::to_vec(
                        &json!({"id": "unit-a", "status": STATUS_COMPENSATION_QUEUED}),
                    )
                    .unwrap(),
                )
                .with_meta(META_COMPENSATE_TARGET, "unit-a"),
            )
            .unwrap();
        assert_eq!(
            state.units["unit-a"].status,
            ledger::Status::Integrated,
            "a compensation-queued mark leaves the target Integrated (fold-neutral) until the drain reverts it"
        );
    }

    /// A driver for the reverse-gear re-gate test (spec 12, unit 4): `unit-a`'s implementer
    /// writes DIFFERENT content per attempt (so its re-implemented tree is not byte-identical
    /// to the condemned one), `unit-b` condemns `unit-a`, and `unit-a`'s own review approves
    /// each time so the run converges after one rollback.
    struct CompRegateDriver;
    impl AgentDriver for CompRegateDriver {
        fn spawn(
            &self,
            _a: &AgentDef,
            _prompt: &str,
            opts: &SpawnOpts,
            _emit: &dyn Fn(&str, Value) -> Result<(), Error>,
        ) -> Result<AgentResult, Error> {
            let unit = opts.id.split('/').next().unwrap_or_default();
            let attempt = attempt_of(&opts.id);
            if opts.id.contains("/implementer#") {
                if !opts.dir.is_empty() {
                    let (file, content) = match unit {
                        // A distinct body per attempt: the re-implementation (attempt 1) is a
                        // genuinely different tree from the condemned attempt-0 one.
                        "unit-a" if attempt == 0 => ("a.rs", "fn a_v0() {}\n"),
                        "unit-a" => ("a.rs", "fn a_v1() {}\n"),
                        _ => ("b.rs", "fn b() {}\n"),
                    };
                    std::fs::write(Path::new(&opts.dir).join(file), content).unwrap();
                }
                return Ok(AgentResult::default());
            }
            if opts.id.contains("/adjudicator#") {
                let out = if unit == "unit-b" {
                    r#"{"verdict":"approve","compensate":"unit-a"}"#
                } else {
                    r#"{"verdict":"approve"}"#
                };
                return Ok(AgentResult {
                    output: out.into(),
                    resolved_model: String::new(),
                });
            }
            Ok(AgentResult {
                output: "reviewed the diff".into(),
                resolved_model: String::new(),
            })
        }
    }

    #[test]
    fn a_compensated_unit_re_gates_its_re_implemented_tree_not_the_condemned_verdict() {
        // spec 12, unit 4 (the reverse gear's RE-VERIFY half): a compensated unit re-enters at
        // an ADVANCED attempt, so its re-implemented tree runs the gate under a FRESH
        // (unit, attempt, gate) key instead of REPLAYING the condemned pass's verdict. Without
        // the attempt advance the unit re-enters at attempt 0 and the content-BLIND exact-key
        // replay answers the gate from the condemned green - the gate COMMAND never runs on the
        // re-implemented code (a live false green). Proven by the gate-run count: unit-a's gate
        // `ga` must run TWICE (once per implemented tree), not once.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("lens".into(), agent("lens"));
        cfg.agents.insert("judge".into(), agent("judge"));
        // Distinct gates per unit so a gate-run count is attributable to one unit.
        cfg.workflow.gates.insert("ga".into(), gate_def("true"));
        cfg.workflow.gates.insert("gb".into(), gate_def("true"));
        let panel = crate::config::ReviewPanel {
            lenses: vec!["lens".into()],
            adjudicator: "judge".into(),
            ..Default::default()
        };
        let mk = |name: &str, gate: &str, needs: Vec<String>| Stage {
            name: name.into(),
            agent: "worker".into(),
            gates: vec![gate.into()],
            on_pass: "merge".into(),
            needs,
            review: panel.clone(),
            ..Default::default()
        };
        cfg.workflow
            .stages
            .insert("unit-a".into(), mk("unit-a", "ga", vec![]));
        cfg.workflow
            .stages
            .insert("unit-b".into(), mk("unit-b", "gb", vec!["unit-a".into()]));

        let store = Store::open(":memory:").unwrap();
        let driver = CompRegateDriver;
        let runner = RecordingRunner::new(&[]);
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &runner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        assert_eq!(
            rs.units["unit-a"].status,
            ledger::Status::Integrated,
            "unit-a re-integrates its re-implemented tree after the rollback"
        );
        assert_eq!(rs.units["unit-b"].status, ledger::Status::Integrated);

        // The crux: `ga` RAN on BOTH of unit-a's trees. Under the stale-replay bug it runs once
        // (attempt 0) and the re-implemented tree replays that green without re-running.
        let ga_runs = runner.calls().into_iter().filter(|c| c == "ga").count();
        assert_eq!(
            ga_runs, 2,
            "unit-a's gate must RE-RUN on the re-implemented tree, not replay the condemned attempt-0 verdict; ga runs={ga_runs}"
        );

        // And the re-run verdict is recorded under the ADVANCED attempt key, a real gate RUN
        // (no cache-hit / skip citation) on the re-implemented tree.
        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        let regate = events.iter().any(|e| {
            e.meta.get(META_REPLAY_KEY).map(String::as_str) == Some("unit-a/gate:ga#1")
                && !e.meta.contains_key(META_CACHE_HIT)
                && serde_json::from_slice::<Value>(&e.data)
                    .ok()
                    .and_then(|v| v.get("skipped").and_then(Value::as_bool))
                    != Some(true)
        });
        assert!(
            regate,
            "the re-implemented tree records a fresh gate:ga#1 RUN verdict (not a replay/cache-hit/skip)"
        );
    }

    /// A driver for the reverse-gear re-gate test on the REMEDIATED lifecycle (spec 12,
    /// unit 4): unlike [`CompRegateDriver`] (which lets `unit-a` approve its FIRST pass),
    /// `unit-a`'s adjudicator here REJECTS attempt 0 and only approves attempt 1, so `unit-a`
    /// integrates having ALREADY recorded a green gate verdict at attempt 1. When `unit-b`
    /// then condemns it, the reverse gear must clear that attempt-1 key. Each `unit-a` attempt
    /// writes DISTINCT content (`fn a_v{attempt}`) so every one of its trees is a genuinely
    /// different content address; `unit-b` approves its own work but names `unit-a`.
    struct CompRegateRemediatedDriver;
    impl AgentDriver for CompRegateRemediatedDriver {
        fn spawn(
            &self,
            _a: &AgentDef,
            _prompt: &str,
            opts: &SpawnOpts,
            _emit: &dyn Fn(&str, Value) -> Result<(), Error>,
        ) -> Result<AgentResult, Error> {
            let unit = opts.id.split('/').next().unwrap_or_default();
            let attempt = attempt_of(&opts.id);
            if opts.id.contains("/implementer#") {
                if !opts.dir.is_empty() {
                    let (file, content) = match unit {
                        // A distinct body per attempt so no two of unit-a's trees are
                        // byte-identical - each gate run is a distinct content address, so a
                        // fresh key genuinely re-runs the command rather than content-cache
                        // hitting an earlier tree's green.
                        "unit-a" => ("a.rs", format!("fn a_v{attempt}() {{}}\n")),
                        _ => ("b.rs", "fn b() {}\n".to_string()),
                    };
                    std::fs::write(Path::new(&opts.dir).join(file), content).unwrap();
                }
                return Ok(AgentResult::default());
            }
            if opts.id.contains("/adjudicator#") {
                let out = if unit == "unit-b" {
                    // unit-b approves its own work but proves unit-a wrong (names it).
                    r#"{"verdict":"approve","compensate":"unit-a"}"#
                } else if attempt == 0 {
                    // unit-a's FIRST pass is rejected: it consumes attempt 0 and re-implements,
                    // so it records its GREEN gate verdict at attempt 1 when it approves. This
                    // is the attempt key the reverse gear must NOT collide with. Its re-review
                    // after the rollback (attempt >= 1) approves cleanly so the run converges.
                    r#"{"verdict":"reject"}"#
                } else {
                    r#"{"verdict":"approve"}"#
                };
                return Ok(AgentResult {
                    output: out.into(),
                    resolved_model: String::new(),
                });
            }
            Ok(AgentResult {
                output: "reviewed the diff".into(),
                resolved_model: String::new(),
            })
        }
    }

    #[test]
    fn a_compensated_unit_that_remediated_before_integrating_re_gates_at_a_fresh_key() {
        // spec 12, unit 4 (the reverse gear's RE-VERIFY half on the REMEDIATED lifecycle - the
        // blocking regression sdet-s12u4-reentry-collides-with-prior-lifecycle-attempt-key /
        // adv-s12u4-collision-proven-by-run): unit-a REJECTS its own attempt 0 and only approves
        // on attempt 1, so it integrates having ALREADY recorded a green gate verdict at
        // attempt 1. When unit-b then condemns it, the reverse gear must re-enter it ONE PAST
        // its HIGH-WATER attempt (attempt 2) - NOT at attempt 1 where its OWN prior remediation
        // already recorded a green. Advancing only compensation-count+1 over the run-start
        // prior_attempts snapshot (=0 in-run) lands it back on attempt 1, where the
        // content-BLIND exact-key replay answers the re-implemented tree from the condemned
        // green and the gate COMMAND never runs (a live false green). Proven by the gate-run
        // count: unit-a's gate `ga` must run THREE times (attempt 0, the attempt-1
        // re-implementation, and the attempt-2 reverse-gear re-implementation), not two.
        //
        // The zero-remediation sibling (a_compensated_unit_re_gates_its_re_implemented_tree_...)
        // only drives unit-a approving its first pass, so a fixed +1 advance passes it; this
        // case is the mutation-distinguishing one it missed.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("lens".into(), agent("lens"));
        cfg.agents.insert("judge".into(), agent("judge"));
        // Distinct gates per unit so a gate-run count is attributable to one unit.
        cfg.workflow.gates.insert("ga".into(), gate_def("true"));
        cfg.workflow.gates.insert("gb".into(), gate_def("true"));
        let panel = crate::config::ReviewPanel {
            lenses: vec!["lens".into()],
            adjudicator: "judge".into(),
            ..Default::default()
        };
        let mk = |name: &str, gate: &str, needs: Vec<String>| Stage {
            name: name.into(),
            agent: "worker".into(),
            gates: vec![gate.into()],
            on_pass: "merge".into(),
            needs,
            review: panel.clone(),
            ..Default::default()
        };
        cfg.workflow
            .stages
            .insert("unit-a".into(), mk("unit-a", "ga", vec![]));
        cfg.workflow
            .stages
            .insert("unit-b".into(), mk("unit-b", "gb", vec!["unit-a".into()]));

        let store = Store::open(":memory:").unwrap();
        let driver = CompRegateRemediatedDriver;
        let runner = RecordingRunner::new(&[]);
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &runner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        assert_eq!(
            rs.units["unit-a"].status,
            ledger::Status::Integrated,
            "unit-a re-integrates its re-implemented tree after the rollback"
        );
        assert_eq!(rs.units["unit-b"].status, ledger::Status::Integrated);

        // The crux: `ga` RAN on ALL THREE of unit-a's trees (attempt 0, the attempt-1
        // re-implementation, and the reverse-gear attempt-2 re-implementation). Under the
        // stale-key collision it runs only twice - the reverse-gear re-entry lands on attempt 1
        // and replays unit-a's OWN prior-remediation green without re-running the command.
        let ga_runs = runner.calls().into_iter().filter(|c| c == "ga").count();
        assert_eq!(
            ga_runs, 3,
            "unit-a's gate must RE-RUN on the re-implemented tree at a FRESH attempt key, not \
             replay the attempt-1 green its own prior remediation recorded; ga runs={ga_runs}"
        );

        // And the reverse-gear verdict is recorded under the HIGH-WATER-advanced attempt key
        // (`#2`, one past the attempt-1 green), a real gate RUN (no cache-hit / skip citation).
        // A `#1` re-run here would be the collision: that key was already green from unit-a's
        // own remediation.
        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        let regate = events.iter().any(|e| {
            e.meta.get(META_REPLAY_KEY).map(String::as_str) == Some("unit-a/gate:ga#2")
                && !e.meta.contains_key(META_CACHE_HIT)
                && serde_json::from_slice::<Value>(&e.data)
                    .ok()
                    .and_then(|v| v.get("skipped").and_then(Value::as_bool))
                    != Some(true)
        });
        assert!(
            regate,
            "the reverse-gear re-implemented tree records a fresh gate:ga#2 RUN verdict at the \
             high-water-advanced key (not a replay/cache-hit/skip, and not a colliding #1)"
        );
    }

    /// A driver for the crash-resume compensation test (spec 12, unit 4): unit-a's implementer
    /// writes its file and records each prompt (to prove the re-entry carries the seeded
    /// contradiction); its adjudicator approves with no further compensation, so the resumed
    /// rollback converges.
    struct ResumeCompDriver {
        impl_prompts: Mutex<Vec<String>>,
    }
    impl AgentDriver for ResumeCompDriver {
        fn spawn(
            &self,
            _a: &AgentDef,
            prompt: &str,
            opts: &SpawnOpts,
            _emit: &dyn Fn(&str, Value) -> Result<(), Error>,
        ) -> Result<AgentResult, Error> {
            if opts.id.contains("/implementer#") {
                self.impl_prompts.lock().unwrap().push(prompt.to_string());
                if !opts.dir.is_empty() {
                    std::fs::write(Path::new(&opts.dir).join("a.rs"), "fn a_fixed() {}\n").unwrap();
                }
                return Ok(AgentResult::default());
            }
            if opts.id.contains("/adjudicator#") {
                return Ok(AgentResult {
                    output: r#"{"verdict":"approve"}"#.into(),
                    resolved_model: String::new(),
                });
            }
            Ok(AgentResult {
                output: "reviewed the diff".into(),
                resolved_model: String::new(),
            })
        }
    }

    #[test]
    fn a_resume_re_drives_a_durably_queued_but_undrained_compensation() {
        // spec 12, unit 4 (crash-resume of the reverse gear): a prior window durably QUEUED a
        // compensation of the integrated unit-a (a review named it) but CRASHED before the
        // drain reverted it - so the log carries unit-a Integrated + a compensation-queued mark
        // but NO drained UnitFailed. On resume the conductor must re-derive the still-pending
        // compensation, REVERT unit-a's integrating commit, and re-enter unit-a - never leave a
        // converged run with a green ledger over a tree that still holds the condemned work.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();

        // The prior window's integrating commit of unit-a, on the run branch (HEAD).
        std::fs::write(Path::new(&repo_path).join("a.rs"), "fn a_condemned() {}\n").unwrap();
        let commit_c = {
            for args in [
                &["add", "a.rs"][..],
                &["commit", "-q", "-m", "unit-a integrates"][..],
            ] {
                std::process::Command::new("git")
                    .arg("-C")
                    .arg(&repo_path)
                    .args(args)
                    .output()
                    .unwrap();
            }
            let out = std::process::Command::new("git")
                .arg("-C")
                .arg(&repo_path)
                .args(["rev-parse", "HEAD"])
                .output()
                .unwrap();
            String::from_utf8_lossy(&out.stdout).trim().to_string()
        };

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("lens".into(), agent("lens"));
        cfg.agents.insert("judge".into(), agent("judge"));
        cfg.workflow.gates.insert("g".into(), gate_def("true"));
        cfg.workflow.stages.insert(
            "unit-a".into(),
            Stage {
                name: "unit-a".into(),
                agent: "worker".into(),
                gates: vec!["g".into()],
                on_pass: "merge".into(),
                review: crate::config::ReviewPanel {
                    lenses: vec!["lens".into()],
                    adjudicator: "judge".into(),
                    ..Default::default()
                },
                ..Default::default()
            },
        );

        let store = Store::open(":memory:").unwrap();
        // Seed the crash state: unit-a integrated at commit C, a durable compensation-queued
        // mark naming unit-a, and NO drained UnitFailed - the trigger fired, the drain did not.
        let contradiction = r#"{"verdict":"approve","compensate":"unit-a"}"#;
        seed_events_in_run(
            &store,
            &[],
            &[
                Event::new(
                    ledger::TYPE_UNIT_INTEGRATED,
                    serde_json::to_vec(&json!({"id": "unit-a", "commit": commit_c})).unwrap(),
                ),
                Event::new(
                    ledger::TYPE_UNIT_STATUS,
                    serde_json::to_vec(
                        &json!({"id": "unit-a", "status": STATUS_COMPENSATION_QUEUED}),
                    )
                    .unwrap(),
                )
                .with_meta(META_COMPENSATE_TARGET, "unit-a")
                .with_meta(META_CONTRADICTION, contradiction),
            ],
        );

        let driver = ResumeCompDriver {
            impl_prompts: Mutex::new(Vec::new()),
        };
        let runner = RecordingRunner::new(&[]);
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &runner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        // The resume re-drove the rollback: unit-a re-implemented and re-integrated.
        assert_eq!(
            rs.units["unit-a"].status,
            ledger::Status::Integrated,
            "the resumed run re-integrates unit-a after re-driving the queued compensation"
        );

        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();
        // The seeded queue mark was DRAINED on resume: a UnitFailed for unit-a now names the
        // reverted commit C in META_COMPENSATED (the rollback completed, not dropped).
        let drained = events.iter().any(|e| {
            e.type_ == ledger::TYPE_UNIT_FAILED
                && e.meta.get(META_COMPENSATED).map(String::as_str) == Some(commit_c.as_str())
        });
        assert!(
            drained,
            "on resume the queued compensation is drained: a UnitFailed reverts unit-a's commit C"
        );

        // The condemned commit was reverted on the run branch (an evented rollback), so the
        // final tree does NOT still carry unit-a's condemned artifact under a green ledger.
        let log = std::process::Command::new("git")
            .arg("-C")
            .arg(&repo_path)
            .args(["log", "--pretty=%s"])
            .output()
            .unwrap();
        let log = String::from_utf8_lossy(&log.stdout);
        assert!(
            log.lines().any(|l| l.contains("compensate unit-a")),
            "the resume reverts unit-a's condemned commit on the run branch; log:\n{log}"
        );

        // The re-entered unit-a's first prompt carries the SEEDED contradiction (recovered from
        // the durable mark), so the re-implementation fixes the specific defect.
        let prompts = driver.impl_prompts.lock().unwrap().clone();
        assert!(
            prompts
                .first()
                .is_some_and(|p| p.contains("your integrating commit was REVERTED")),
            "the re-entered unit-a is prompted with the recovered contradiction; prompts:\n{prompts:?}"
        );
    }

    /// The base `m.rs` content the merge-break fixture below starts from: six MARK-free
    /// lines so `unit-a`'s top insert and `unit-b`'s bottom append land in NON-overlapping
    /// hunks that git auto-merges cleanly (no conflict) into a tree carrying BOTH marks.
    const MERGE_BREAK_BASE: &str = "l1\nl2\nl3\nl4\nl5\nl6\n";

    /// A driver for the post-merge re-gate fixture (spec 12, unit 5): `unit-a` and `unit-b`
    /// are two batch-mates with NO dependency between them (the grounder placed them in one
    /// wave), each editing the SAME file `m.rs`. `unit-a` PREPENDS one `MARK` line, `unit-b`
    /// APPENDS one - so each unit's OWN tree carries exactly one MARK (its gate passes in
    /// isolation), but the textual auto-merge combines both into a two-MARK tree the gate
    /// REJECTS. Both writes are recomputed from the fixed base each attempt (idempotent), so
    /// a remediation re-attempt never doubles a unit's own mark. A barrier makes both
    /// worktrees branch from the SAME base commit (neither integrates before the other's
    /// branch exists), which is what creates the unpredicted overlap.
    struct MergeBreakDriver {
        repo: String,
    }
    impl AgentDriver for MergeBreakDriver {
        fn spawn(
            &self,
            _a: &AgentDef,
            _prompt: &str,
            opts: &SpawnOpts,
            _emit: &dyn Fn(&str, Value) -> Result<(), Error>,
        ) -> Result<AgentResult, Error> {
            let unit = opts.id.split('/').next().unwrap_or_default();
            if opts.id.contains("/implementer#") {
                if !opts.dir.is_empty() {
                    // Barrier: block until BOTH unit branches exist, so both worktrees were
                    // cut from the SAME base commit (neither has integrated yet - an
                    // implementer runs strictly before its unit's integrate). This is the
                    // UNPREDICTED-overlap case unit 5 targets: two batch-mates that actually
                    // edit the same region, each green alone, broken when merged.
                    for _ in 0..400 {
                        let n = std::process::Command::new("git")
                            .arg("-C")
                            .arg(&self.repo)
                            .args(["branch", "--list", "rigger/u/*"])
                            .output()
                            .map(|o| String::from_utf8_lossy(&o.stdout).lines().count())
                            .unwrap_or(0);
                        if n >= 2 {
                            break;
                        }
                        std::thread::sleep(std::time::Duration::from_millis(25));
                    }
                    // Idempotent per attempt: always the fixed base plus this unit's ONE mark.
                    let content = if unit == "unit-a" {
                        format!("MARK\n{MERGE_BREAK_BASE}")
                    } else {
                        format!("{MERGE_BREAK_BASE}MARK\n")
                    };
                    std::fs::write(Path::new(&opts.dir).join("m.rs"), content).unwrap();
                }
                return Ok(AgentResult::default());
            }
            if opts.id.contains("/adjudicator#") {
                return Ok(AgentResult {
                    output: r#"{"verdict":"approve"}"#.into(),
                    resolved_model: String::new(),
                });
            }
            Ok(AgentResult {
                output: "reviewed the diff".into(),
                resolved_model: String::new(),
            })
        }
    }

    #[test]
    fn integrate_re_gates_the_merged_tree_and_a_merge_break_blocks_the_second_unit() {
        // spec 12, unit 5 (Gap 21): two units each PASS their gate in isolation but merge into
        // a FAILING tree. The grounder placed them in one batch (no dependency), so both cut
        // their worktree from the same base and each gates only its OWN one-MARK tree green.
        // The FIRST to win the integrate lock merges cleanly (a fast-forward over the base) and
        // its post-merge re-gate is a CONTENT-CACHE HIT of the pre-merge green - near-free - so
        // it integrates. The SECOND merges into a TWO-MARK tree the grounder never predicted:
        // its post-merge re-gate MISSES the cache, RUNS on the merged tree, goes RED, and BLOCKS
        // the integration - the merge is rolled back (nothing lands) and the unit re-enters
        // remediation fed the merge-break evidence. The broken two-MARK tree is NEVER recorded
        // with an UnitIntegrated.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();
        // Seed the shared file at the base so both units branch from a tree that already holds
        // it (their edits are a top prepend / bottom append of one MARK line each).
        std::fs::write(Path::new(&repo_path).join("m.rs"), MERGE_BREAK_BASE).unwrap();
        for args in [
            &["add", "m.rs"][..],
            &["commit", "-q", "-m", "base m.rs"][..],
        ] {
            std::process::Command::new("git")
                .arg("-C")
                .arg(&repo_path)
                .args(args)
                .output()
                .unwrap();
        }

        let mut cfg = Config::default();
        // Bound the losing unit's merge/rollback cascade: it re-breaks every attempt, so cap
        // remediation low and let it escalate.
        cfg.workflow.defaults.max_retries = 2;
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("lens".into(), agent("lens"));
        cfg.agents.insert("judge".into(), agent("judge"));
        // A real shell gate over the tree: PASS with at most one MARK line, RED (with a
        // greppable reason) once the merge introduces a second.
        cfg.workflow.gates.insert(
            "g".into(),
            gate_def(
                "c=$(grep -c MARK m.rs 2>/dev/null); c=${c:-0}; \
                 if [ \"$c\" -le 1 ]; then exit 0; else \
                 echo 'gate g failed: merge introduced duplicate MARK'; exit 1; fi",
            ),
        );
        let panel = crate::config::ReviewPanel {
            lenses: vec!["lens".into()],
            adjudicator: "judge".into(),
            ..Default::default()
        };
        let mk = |name: &str| Stage {
            name: name.into(),
            agent: "worker".into(),
            gates: vec!["g".into()],
            on_pass: "merge".into(),
            needs: vec![],
            review: panel.clone(),
            ..Default::default()
        };
        cfg.workflow.stages.insert("unit-a".into(), mk("unit-a"));
        cfg.workflow.stages.insert("unit-b".into(), mk("unit-b"));

        let store = Store::open(":memory:").unwrap();
        let driver = MergeBreakDriver {
            repo: repo_path.clone(),
        };
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        // Exactly one unit integrated; the other was BLOCKED by the post-merge re-gate and
        // escalated (it re-breaks the merge every attempt). Order between them is a lock race,
        // so the assertions are order-independent.
        let statuses: Vec<_> = ["unit-a", "unit-b"]
            .iter()
            .map(|u| (*u, rs.units[*u].status))
            .collect();
        let winner = statuses
            .iter()
            .find(|(_, s)| *s == ledger::Status::Integrated)
            .map(|(u, _)| *u)
            .expect("exactly one unit must integrate its merged tree");
        let loser = if winner == "unit-a" {
            "unit-b"
        } else {
            "unit-a"
        };
        assert_eq!(
            rs.units[loser].status,
            ledger::Status::Escalated,
            "the merge-broken unit never integrates a failing tree; it escalates after the block"
        );

        let events = store.read_stream(STREAM, 0, Direction::Forward).unwrap();

        // (1) The broken TWO-MARK tree never landed: the run branch's m.rs carries exactly ONE
        // MARK (the winner's), and there is exactly ONE UnitIntegrated (for the winner).
        let merged = std::fs::read_to_string(Path::new(&repo_path).join("m.rs")).unwrap();
        assert_eq!(
            merged.matches("MARK").count(),
            1,
            "the run branch holds only the winner's one MARK; the broken merged tree was rolled back:\n{merged}"
        );
        let integrations: Vec<String> = events
            .iter()
            .filter(|e| e.type_ == ledger::TYPE_UNIT_INTEGRATED)
            .filter_map(|e| {
                serde_json::from_slice::<Value>(&e.data)
                    .ok()
                    .and_then(|v| v.get("id").and_then(Value::as_str).map(str::to_string))
            })
            .collect();
        assert_eq!(
            integrations,
            vec![winner.to_string()],
            "only the winner records an UnitIntegrated; the merge-broken unit never does"
        );

        // (2) The loser's post-merge re-gate RAN on the merged tree and went RED, carrying the
        // merge-break evidence - keyed apart from the pre-merge `{unit}/gate:` verdict so it did
        // NOT replay the isolation green.
        let postmerge_red = events.iter().any(|e| {
            e.type_ == contextgraph::TYPE_GATE_VERDICT
                && e.meta
                    .get(META_REPLAY_KEY)
                    .is_some_and(|k| k.starts_with(&format!("{loser}/postmerge-gate:g#")))
                && serde_json::from_slice::<Value>(&e.data).ok().map(|v| {
                    v.get("pass").and_then(Value::as_bool) == Some(false)
                        && v.get("evidence")
                            .and_then(Value::as_str)
                            .is_some_and(|s| s.contains("merge introduced duplicate MARK"))
                }) == Some(true)
        });
        assert!(
            postmerge_red,
            "the loser's merged tree records a RED post-merge re-gate verdict carrying the merge-break evidence"
        );

        // (3) The winner's post-merge re-gate was NEAR-FREE: a content-addressed cache-hit of
        // its pre-merge green (its clean fast-forward merge changed nothing the gate reads), not
        // a fresh run.
        let winner_hit = events.iter().any(|e| {
            e.type_ == contextgraph::TYPE_GATE_VERDICT
                && e.meta
                    .get(META_REPLAY_KEY)
                    .is_some_and(|k| k.starts_with(&format!("{winner}/postmerge-gate:g#")))
                && e.meta.contains_key(META_CACHE_HIT)
        });
        assert!(
            winner_hit,
            "the winner's post-merge re-gate is a content-cache hit of its pre-merge green (near-free)"
        );

        // (4) The loser re-entered remediation after the block (a UnitFailed at an advanced
        // attempt), proving the merge-break fed its lifecycle rather than wedging.
        let loser_remediated = events.iter().any(|e| {
            e.type_ == ledger::TYPE_UNIT_FAILED
                && serde_json::from_slice::<Value>(&e.data).ok().map(|v| {
                    v.get("id").and_then(Value::as_str) == Some(loser)
                        && v.get("attempts").and_then(Value::as_u64).unwrap_or(0) >= 1
                }) == Some(true)
        });
        assert!(
            loser_remediated,
            "the blocked unit re-enters remediation (UnitFailed at an advanced attempt) fed the merge-break"
        );
    }

    #[test]
    fn a_deferred_gate_runs_once_at_the_phase_boundary_not_inline() {
        // A stage with both an inline (core) gate and a deferred gate. The deferred
        // gate must NOT run during the unit's inline lifecycle - the unit integrates on
        // its inline gate alone - and must run EXACTLY ONCE at the run's end-of-run
        // phase boundary, after the unit has integrated.
        let mut cfg = Config::default();
        cfg.agents.insert("a".into(), agent("a"));
        cfg.workflow.gates.insert("inline".into(), gate_def("true"));
        cfg.workflow.gates.insert(
            "deferred".into(),
            config::Gate {
                run: "true".into(),
                kind: "deferred".into(),
                inputs: Vec::new(),
            },
        );
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "a".into(),
                gates: vec!["inline".into(), "deferred".into()],
                ..Default::default()
            },
        );
        let st = Store::open(":memory:").unwrap();
        let driver = Stub::new();
        let runner = RecordingRunner::new(&[]);
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &runner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        // The unit integrated on its INLINE gate (the deferred gate played no part in
        // the unit's own lifecycle decision).
        assert_eq!(rs.units["s"].status, ledger::Status::Integrated);

        // The deferred gate ran exactly once, and it ran AFTER the inline gate - i.e.
        // at the phase boundary, never inline per unit.
        let calls = runner.calls();
        assert_eq!(
            calls.iter().filter(|c| *c == "deferred").count(),
            1,
            "the deferred gate must run exactly once (at the phase boundary), not per unit; calls: {calls:?}"
        );
        let inline_at = calls.iter().position(|c| c == "inline").unwrap();
        let deferred_at = calls.iter().position(|c| c == "deferred").unwrap();
        assert!(
            deferred_at > inline_at,
            "the deferred gate must run AFTER the inline gate (at end-of-run), not during the inline lifecycle; calls: {calls:?}"
        );

        // The deferred gate emitted a GateVerdict at the boundary, and (since it
        // passed) the run is fully done.
        let events = st
            .read_all(0, Direction::Forward, &Filter::default())
            .unwrap();
        assert!(
            events.iter().any(|e| {
                e.type_ == contextgraph::TYPE_GATE_VERDICT
                    && String::from_utf8_lossy(&e.data).contains("\"gate\":\"deferred\"")
            }),
            "the deferred gate must emit a GateVerdict at the phase boundary"
        );
        assert!(
            rs.done() && rs.fully_done(&[]),
            "a passing deferred gate must leave the run reported fully done"
        );
    }

    #[test]
    fn a_failing_deferred_gate_is_surfaced_and_the_run_is_not_done() {
        // A failing DEFERRED gate must be surfaced truthfully: a DeferredGateFailed
        // event is recorded AND the run is reported not-fully-done, even though the
        // unit itself integrated on its (passing) inline gate. A deferred failure must
        // NOT silently pass as success.
        let mut cfg = Config::default();
        cfg.agents.insert("a".into(), agent("a"));
        cfg.workflow.gates.insert("inline".into(), gate_def("true"));
        cfg.workflow.gates.insert(
            "deferred".into(),
            config::Gate {
                run: "false".into(),
                kind: "deferred".into(),
                inputs: Vec::new(),
            },
        );
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "a".into(),
                gates: vec!["inline".into(), "deferred".into()],
                ..Default::default()
            },
        );
        let st = Store::open(":memory:").unwrap();
        let driver = Stub::new();
        // The deferred gate fails; the inline gate passes.
        let runner = RecordingRunner::new(&["deferred"]);
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &runner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        // The unit still integrated - its INLINE gate passed; the deferred failure is a
        // run-level concern, not a per-unit one.
        assert_eq!(rs.units["s"].status, ledger::Status::Integrated);

        // The failure is recorded as an event naming the gate...
        let events = st
            .read_all(0, Direction::Forward, &Filter::default())
            .unwrap();
        assert!(
            events.iter().any(|e| {
                e.type_ == TYPE_DEFERRED_GATE_FAILED
                    && String::from_utf8_lossy(&e.data).contains("\"gate\":\"deferred\"")
            }),
            "a failing deferred gate must emit a DeferredGateFailed event naming the gate"
        );
        // ...and the run is reported NOT fully done despite every unit integrating.
        assert!(
            !rs.done(),
            "a failing deferred gate must leave the run reported not done"
        );
        assert!(
            !rs.fully_done(&[]),
            "a failing deferred gate must leave the run reported not fully done"
        );
        assert!(
            rs.deferred_gate_failed,
            "the run state must record the deferred-gate failure"
        );
    }

    /// A gate runner that FAILS one named gate with caller-supplied evidence and passes
    /// every other gate. Lets a test drive a specific gate (e.g. a deferred phase-boundary
    /// gate) into a failure whose evidence the taxonomy classifies, while the unit's inline
    /// gate still passes so the unit integrates.
    struct FailOneGate {
        fail: String,
        evidence: String,
    }
    impl gate::Runner for FailOneGate {
        fn run(&self, g: &Gate, _dir: &str, _target: &str) -> gate::GateResult {
            if g.id == self.fail {
                gate::GateResult {
                    pass: false,
                    evidence: self.evidence.clone(),
                }
            } else {
                gate::GateResult {
                    pass: true,
                    evidence: "PASS".into(),
                }
            }
        }
    }

    #[test]
    fn a_default_infra_fault_at_a_deferred_gate_does_not_demote() {
        // Spec 10, unit 2 - the DEFERRED leg of the SINGLE classification authority. A
        // persistent infra outage (one the SHIPPED DEFAULT taxonomy classifies `infra`) at
        // a DEFERRED phase-boundary gate must HOLD the ratchet exactly as the identical
        // fault does at an INLINE gate (FailNoDemote): an outage must never cost a graduated
        // gate its earned autonomy. run_deferred_gates used to hardcode `if pass {CleanPass}
        // else {FailDemote}`, a second failure-classification path that BYPASSED
        // self.taxonomy and demoted the deferred gate AutoNotify->Manual on the SAME fault
        // the inline site holds - two demotion policies for one fault by gate SITE, the
        // exact harm this unit exists to prevent. No failure_rules are authored, so the
        // shipped default taxonomy governs and classifies the outage below as infra.
        let mut cfg = Config::default();
        cfg.agents.insert("a".into(), agent("a"));
        cfg.workflow.gates.insert("inline".into(), gate_def("true"));
        cfg.workflow.gates.insert(
            "deferred".into(),
            config::Gate {
                run: "false".into(),
                kind: "deferred".into(),
                inputs: Vec::new(),
            },
        );
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "a".into(),
                gates: vec!["inline".into(), "deferred".into()],
                ..Default::default()
            },
        );
        let st = Store::open(":memory:").unwrap();
        let driver = Stub::new();
        // The inline gate passes (the unit integrates); the deferred gate fails at the
        // phase boundary with an outage the DEFAULT taxonomy recognises as infra. The
        // deferred gate is seeded at the default autonomy (AutoNotify, above Manual), so a
        // bug-path FailDemote WOULD emit a visible GateDemoted.
        let runner = FailOneGate {
            fail: "deferred".into(),
            evidence: "FAIL\nno space left on device".into(),
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &runner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        // The unit integrated on its passing inline gate.
        assert_eq!(rs.units["s"].status, ledger::Status::Integrated);

        let events = st.read_stream(STREAM, 0, Direction::Forward).unwrap();
        // The deferred failure is still surfaced truthfully...
        assert!(
            events.iter().any(|e| {
                e.type_ == TYPE_DEFERRED_GATE_FAILED
                    && String::from_utf8_lossy(&e.data).contains("\"gate\":\"deferred\"")
            }),
            "a failing deferred gate must still surface a DeferredGateFailed event"
        );
        // ...but an INFRA outage classified through the SINGLE authority must NEVER demote
        // the deferred gate's ratchet - the same HOLD the inline site gives the identical
        // fault. This is the pinned single-authority invariant the reject demanded.
        assert!(
            !events.iter().any(|e| e.type_ == TYPE_GATE_DEMOTED),
            "a persistent infra fault at a deferred gate must HOLD the ratchet (FailNoDemote), not demote it"
        );
    }

    #[test]
    fn a_replayed_step_re_runs_no_recorded_gate_and_appends_no_duplicate_events() {
        // spec 04, criterion 4: a step re-running the conductor over recorded history
        // appends no unit event or gate verdict twice, and a recorded GateVerdict is
        // REPLAYED without re-running its gate command (finding adv-replay-dup-lifecycle).
        use crate::driver::replay::ReplayDriver;

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.workflow.gates.insert("check".into(), gate_def("true"));
        cfg.workflow.stages.insert(
            "u".into(),
            Stage {
                name: "u".into(),
                agent: "worker".into(),
                gates: vec!["check".into()],
                // No review panel and on_pass:none: the unit verifies and STAYS at
                // `verified` (never integrates), so every step re-runs it fresh over the
                // recorded implementer result - the exact shape a mid-flight unit replays.
                on_pass: "none".into(),
                ..Default::default()
            },
        );

        let st = Store::open(":memory:").unwrap();
        // Begin the run before recording, as production does (`run` calls `ensure_started`
        // before any spawn is parked): the run-scoped replay lookup answers only results
        // inside the current run's slice, so the recorded result must follow the boundary.
        crate::run::ensure_started(&st, &[]).unwrap();
        // A courier already recorded the implementer's result, so the replay driver
        // ANSWERS the implementer spawn (never parks it) and the gate is reached both
        // steps.
        crate::spawn::record_result(
            &st,
            &crate::spawn::SpawnResult::ok(spawn_id("u", ROLE_IMPLEMENTER, 0), "done"),
        )
        .unwrap();

        // Two consecutive steps replay the SAME recorded history. The gate runner
        // records every command it runs, so a re-run of an already-recorded gate would
        // show up as a second call.
        let runner = RecordingRunner::new(&[]);
        for _ in 0..2 {
            let driver = ReplayDriver::new(&st);
            let deps = Deps {
                store: &st,
                driver: &driver,
                gates: &runner,
                repo: String::new(),
                grounder: None,
                graph: None,
                criteria: Vec::new(),
            };
            run(&cfg, &deps).unwrap();
        }

        // The gate command ran EXACTLY ONCE across both steps: the second step replayed
        // the recorded verdict instead of re-running the command.
        assert_eq!(
            runner
                .calls()
                .iter()
                .filter(|c| c.as_str() == "check")
                .count(),
            1,
            "a recorded GateVerdict must be replayed, its command never re-run"
        );

        let events = st.read_stream(STREAM, 0, Direction::Forward).unwrap();
        let count_status = |status: &str| {
            events
                .iter()
                .filter(|e| {
                    e.type_ == ledger::TYPE_UNIT_STATUS
                        && String::from_utf8_lossy(&e.data)
                            .contains(&format!("\"status\":\"{status}\""))
                })
                .count()
        };
        assert_eq!(
            events
                .iter()
                .filter(|e| e.type_ == ledger::TYPE_UNIT_STARTED)
                .count(),
            1,
            "UnitStarted is appended once, not once per replay step"
        );
        assert_eq!(
            count_status("green"),
            1,
            "green is appended once across steps"
        );
        assert_eq!(
            count_status("verified"),
            1,
            "verified is appended once across steps"
        );
        assert_eq!(
            events
                .iter()
                .filter(|e| e.type_ == contextgraph::TYPE_GATE_VERDICT)
                .count(),
            1,
            "the GateVerdict is appended once - the replay re-emits none"
        );
    }

    #[test]
    fn a_re_step_replays_a_recorded_deferred_gate_without_re_running_it() {
        // spec 04, criterion 4: a deferred gate's recorded verdict is replayed on a
        // re-step, never re-running the (whole-tree) command or duplicating the verdict.
        use crate::driver::replay::ReplayDriver;

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.workflow.gates.insert("inline".into(), gate_def("true"));
        cfg.workflow.gates.insert(
            "deferred".into(),
            config::Gate {
                run: "true".into(),
                kind: "deferred".into(),
                inputs: Vec::new(),
            },
        );
        cfg.workflow.stages.insert(
            "u".into(),
            Stage {
                name: "u".into(),
                agent: "worker".into(),
                gates: vec!["inline".into(), "deferred".into()],
                on_pass: "none".into(),
                ..Default::default()
            },
        );

        let st = Store::open(":memory:").unwrap();
        // Begin the run before recording (production ordering): the run-scoped replay lookup
        // answers only results inside the current run's slice.
        crate::run::ensure_started(&st, &[]).unwrap();
        crate::spawn::record_result(
            &st,
            &crate::spawn::SpawnResult::ok(spawn_id("u", ROLE_IMPLEMENTER, 0), "done"),
        )
        .unwrap();

        let runner = RecordingRunner::new(&[]);
        for _ in 0..2 {
            let driver = ReplayDriver::new(&st);
            let deps = Deps {
                store: &st,
                driver: &driver,
                gates: &runner,
                repo: String::new(),
                grounder: None,
                graph: None,
                criteria: Vec::new(),
            };
            run(&cfg, &deps).unwrap();
        }

        let calls = runner.calls();
        assert_eq!(
            calls.iter().filter(|c| c.as_str() == "deferred").count(),
            1,
            "the deferred gate runs once across steps, then replays; calls: {calls:?}"
        );
        assert_eq!(
            calls.iter().filter(|c| c.as_str() == "inline").count(),
            1,
            "the inline gate runs once across steps, then replays; calls: {calls:?}"
        );

        let events = st.read_stream(STREAM, 0, Direction::Forward).unwrap();
        let verdicts = |gate: &str| {
            events
                .iter()
                .filter(|e| {
                    e.type_ == contextgraph::TYPE_GATE_VERDICT
                        && String::from_utf8_lossy(&e.data)
                            .contains(&format!("\"gate\":\"{gate}\""))
                })
                .count()
        };
        assert_eq!(
            verdicts("deferred"),
            1,
            "no duplicate deferred GateVerdict on replay"
        );
        assert_eq!(
            verdicts("inline"),
            1,
            "no duplicate inline GateVerdict on replay"
        );
    }

    #[test]
    fn a_parked_step_never_records_a_partial_tree_deferred_verdict() {
        // BLOCKER 1 (finding adv-deferred-replay-locks-partial-tree): under stepwise
        // replay an early step empties the wave loop with the unit PARKED (its
        // implementer not yet recorded), so NOTHING has run against the tree. The
        // deferred gate must NOT run/record then - doing so would lock in a base/partial
        // -tree verdict that every later step replays, so the deferred gate would NEVER
        // validate the assembled tree. It must instead run exactly once, on the step
        // that drains the park and the unit reaches its settled state.
        use crate::driver::replay::ReplayDriver;

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.workflow.gates.insert("inline".into(), gate_def("true"));
        cfg.workflow.gates.insert(
            "deferred".into(),
            config::Gate {
                run: "true".into(),
                kind: "deferred".into(),
                inputs: Vec::new(),
            },
        );
        cfg.workflow.stages.insert(
            "u".into(),
            Stage {
                name: "u".into(),
                agent: "worker".into(),
                gates: vec!["inline".into(), "deferred".into()],
                // on_pass:none lets the unit settle at `verified` (no repo to integrate
                // into) - the exact "unit verified but not integrated" state the
                // reviewer's probe reached on step 2.
                on_pass: "none".into(),
                ..Default::default()
            },
        );

        let st = Store::open(":memory:").unwrap();
        let runner = RecordingRunner::new(&[]);

        // STEP 1: the implementer is NOT recorded, so it PARKS. The unit never reaches
        // its gates, and the run has not converged.
        {
            let driver = ReplayDriver::new(&st);
            let deps = Deps {
                store: &st,
                driver: &driver,
                gates: &runner,
                repo: String::new(),
                grounder: None,
                graph: None,
                criteria: Vec::new(),
            };
            run(&cfg, &deps).unwrap();
        }
        assert_eq!(
            runner
                .calls()
                .iter()
                .filter(|c| c.as_str() == "deferred")
                .count(),
            0,
            "the deferred gate must NOT run while the unit is parked (partial tree)"
        );
        let deferred_verdicts = |events: &[Event]| {
            events
                .iter()
                .filter(|e| {
                    e.type_ == contextgraph::TYPE_GATE_VERDICT
                        && String::from_utf8_lossy(&e.data).contains("\"gate\":\"deferred\"")
                })
                .count()
        };
        let events = st.read_stream(STREAM, 0, Direction::Forward).unwrap();
        assert_eq!(
            deferred_verdicts(&events),
            0,
            "a parked step records NO deferred GateVerdict - no partial-tree verdict to lock in"
        );

        // A courier records the implementer's result: the park drains.
        crate::spawn::record_result(
            &st,
            &crate::spawn::SpawnResult::ok(spawn_id("u", ROLE_IMPLEMENTER, 0), "done"),
        )
        .unwrap();

        // STEP 2: the implementer replays, the unit reaches `verified`, and the run
        // converges - so NOW the deferred gate runs, once, against the settled tree.
        {
            let driver = ReplayDriver::new(&st);
            let deps = Deps {
                store: &st,
                driver: &driver,
                gates: &runner,
                repo: String::new(),
                grounder: None,
                graph: None,
                criteria: Vec::new(),
            };
            run(&cfg, &deps).unwrap();
        }
        assert_eq!(
            runner
                .calls()
                .iter()
                .filter(|c| c.as_str() == "deferred")
                .count(),
            1,
            "the deferred gate runs exactly once, on the converged step that drained the park"
        );
        assert_eq!(
            deferred_verdicts(&st.read_stream(STREAM, 0, Direction::Forward).unwrap()),
            1,
            "the deferred verdict is recorded on the converged step, against the assembled tree"
        );

        // STEP 3: re-stepping the completed run replays the recorded verdict - it never
        // re-runs the command nor duplicates the verdict.
        {
            let driver = ReplayDriver::new(&st);
            let deps = Deps {
                store: &st,
                driver: &driver,
                gates: &runner,
                repo: String::new(),
                grounder: None,
                graph: None,
                criteria: Vec::new(),
            };
            run(&cfg, &deps).unwrap();
        }
        assert_eq!(
            runner
                .calls()
                .iter()
                .filter(|c| c.as_str() == "deferred")
                .count(),
            1,
            "a re-step replays the recorded deferred verdict, never re-running its command"
        );
        assert_eq!(
            deferred_verdicts(&st.read_stream(STREAM, 0, Direction::Forward).unwrap()),
            1,
            "no duplicate deferred GateVerdict across the converged step and its replays"
        );
    }

    #[test]
    fn a_manual_review_paused_unit_defers_the_whole_tree_gate() {
        // PRIMARY BLOCKER (findings rf-converged-ignores-budget-refusal /
        // adv-confirm-converged-nonpark-partial-tree, F58/F60): a manual-review-paused
        // unit emits ManualReview and returns pending WITHOUT parking - it is
        // terminal-inserted but never integrated, and it does ZERO work this step (the
        // pause is checked BEFORE the implementer or the inline gate ever runs). The old
        // `!parked && stages.all(terminal.contains)` guard was TRUE against this
        // partial/base tree, so it ran+recorded the whole-tree deferred verdict against a
        // tree missing the paused unit - and the run-scoped key locked that partial-tree
        // result in forever, replayed on every later step even after the human approves.
        // The tree is NOT final while a unit awaits a human, so the deferred gate must be
        // DEFERRED: it must run/record NOTHING here.
        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.workflow.gates.insert("inline".into(), gate_def("true"));
        cfg.workflow.gates.insert(
            "deferred".into(),
            config::Gate {
                run: "true".into(),
                kind: "deferred".into(),
                inputs: Vec::new(),
            },
        );
        // A Manual-autonomy stage pauses on its gate awaiting a human (§4.3). It also
        // references the deferred gate, so the phase boundary would collect+run it if it
        // (wrongly) considered the tree final.
        cfg.workflow.stages.insert(
            "m".into(),
            Stage {
                name: "m".into(),
                agent: "worker".into(),
                gates: vec!["inline".into(), "deferred".into()],
                autonomy: "manual".into(),
                ..Default::default()
            },
        );

        let st = Store::open(":memory:").unwrap();
        let runner = RecordingRunner::new(&[]);
        // A blocking Stub driver never parks; the pause is a non-park terminal path.
        let driver = Stub::new();
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &runner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        assert_ne!(
            rs.units["m"].status,
            ledger::Status::Integrated,
            "the manual unit is paused, not integrated"
        );
        let events = st.read_stream(STREAM, 0, Direction::Forward).unwrap();
        assert!(
            events.iter().any(|e| e.type_ == TYPE_MANUAL_REVIEW),
            "the manual stage must emit ManualReview (it is paused, awaiting a human)"
        );
        assert_eq!(
            runner
                .calls()
                .iter()
                .filter(|c| c.as_str() == "deferred")
                .count(),
            0,
            "the deferred gate must NOT run while a unit is manual-review-paused: the \
             tree is missing that unit's work, so it is not final"
        );
        let deferred_verdicts = events
            .iter()
            .filter(|e| {
                e.type_ == contextgraph::TYPE_GATE_VERDICT
                    && String::from_utf8_lossy(&e.data).contains("\"gate\":\"deferred\"")
            })
            .count();
        assert_eq!(
            deferred_verdicts, 0,
            "a manual-review-paused step records NO deferred GateVerdict - there is no \
             partial-tree verdict to lock in for every later step to replay"
        );
    }

    #[test]
    fn an_escalated_dep_still_runs_the_whole_tree_deferred_gate() {
        // SECONDARY BLOCKER (finding adv-converged-escalated-dep-suppresses-deferred,
        // F59): an escalated unit is terminal-forever-yet-never-integrated, and
        // `ready_stages` gates its dependents on INTEGRATED deps - so a dependent behind
        // an escalated dep NEVER becomes ready, never runs, and never enters `terminal`.
        // The old `stages.all(terminal.contains)` clause then stayed false FOREVER and
        // permanently SUPPRESSED the whole-tree deferred gate (e.g. a security scan) on
        // every run and resume - a regression from the pre-diff behavior where the
        // deferred gate ran unconditionally at run end. When a unit escalates-forever the
        // tree is as-assembled as it will ever be, so the deferred gate MUST still run
        // against it, once, rather than be suppressed.
        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("lens".into(), agent("lens"));
        cfg.agents.insert("adversary".into(), agent("adversary"));
        cfg.agents.insert("adj".into(), agent("adj"));
        cfg.workflow.gates.insert("inline".into(), gate_def("true"));
        cfg.workflow.gates.insert(
            "deferred".into(),
            config::Gate {
                run: "true".into(),
                kind: "deferred".into(),
                inputs: Vec::new(),
            },
        );
        cfg.workflow.defaults.review = config::ReviewPanel {
            lenses: vec!["lens".into()],
            adversary: "adversary".into(),
            adjudicator: "adj".into(),
            tiers: None,
        };
        // `s` passes its inline gate but the adjudicator ALWAYS rejects, so it remediates
        // to the bound and ESCALATES. It also references the deferred whole-tree gate.
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                gates: vec!["inline".into(), "deferred".into()],
                on_pass: "merge".into(),
                ..Default::default()
            },
        );
        // `d` depends on `s`. Because `s` escalates (never integrates), `d` is
        // UNREACHABLE - it never becomes ready and never enters `terminal`.
        cfg.workflow.stages.insert(
            "d".into(),
            Stage {
                name: "d".into(),
                agent: "worker".into(),
                needs: vec!["s".into()],
                gates: vec!["inline".into()],
                ..Default::default()
            },
        );

        let st = Store::open(":memory:").unwrap();
        let runner = RecordingRunner::new(&[]);
        // Every review agent returns a reject verdict; only the adjudicator's gates the
        // unit, so `s` retries to the bound and escalates.
        let driver = Stub {
            output: r#"{"verdict":"reject","issues":[]}"#.into(),
            ..Stub::new()
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &runner,
            repo: String::new(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        assert_eq!(
            rs.units["s"].status,
            ledger::Status::Escalated,
            "the always-rejected unit must escalate, not integrate"
        );
        assert!(
            !rs.units.contains_key("d"),
            "the dependent behind the escalated unit is unreachable: it never starts"
        );
        assert_eq!(
            runner
                .calls()
                .iter()
                .filter(|c| c.as_str() == "deferred")
                .count(),
            1,
            "the whole-tree deferred gate must STILL run once against the as-assembled \
             tree when a unit escalates-forever - not be suppressed permanently"
        );
        let deferred_verdicts = |events: &[Event]| {
            events
                .iter()
                .filter(|e| {
                    e.type_ == contextgraph::TYPE_GATE_VERDICT
                        && String::from_utf8_lossy(&e.data).contains("\"gate\":\"deferred\"")
                })
                .count()
        };
        assert_eq!(
            deferred_verdicts(&st.read_stream(STREAM, 0, Direction::Forward).unwrap()),
            1,
            "the deferred verdict is recorded once, against the as-assembled escalated tree"
        );

        // RESUME: `s` is folded terminal (Escalated) and skipped, `d` stays unreachable,
        // and nothing is transiently pending - so the tree is still final. The recorded
        // deferred verdict REPLAYS: the command never re-runs and no duplicate verdict is
        // appended (spec 04, criterion 4 - replay is idempotent).
        let rs2 = run(&cfg, &deps).unwrap();
        assert_eq!(
            rs2.units["s"].status,
            ledger::Status::Escalated,
            "the escalated unit stays terminal across resume"
        );
        assert_eq!(
            runner
                .calls()
                .iter()
                .filter(|c| c.as_str() == "deferred")
                .count(),
            1,
            "a re-step replays the recorded deferred verdict, never re-running its command"
        );
        assert_eq!(
            deferred_verdicts(&st.read_stream(STREAM, 0, Direction::Forward).unwrap()),
            1,
            "no duplicate deferred GateVerdict across the escalated run and its replay"
        );
    }

    #[test]
    fn a_recorded_failing_deferred_verdict_re_surfaces_its_failure_on_replay() {
        // BLOCKER-adjacent (finding adv-deferred-failed-lost-on-crash / F50): the
        // GateVerdict and the DeferredGateFailed are two SEPARATE appends. Simulate a
        // crash between them - a recorded FAILING deferred verdict with NO
        // DeferredGateFailed yet - and assert the next step replays the verdict AND
        // re-surfaces the failure (keyed, so exactly once), so a red deferred gate can
        // never be reported as a finished run.
        use crate::driver::replay::ReplayDriver;

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.workflow.gates.insert("inline".into(), gate_def("true"));
        cfg.workflow.gates.insert(
            "deferred".into(),
            config::Gate {
                run: "false".into(),
                kind: "deferred".into(),
                inputs: Vec::new(),
            },
        );
        cfg.workflow.stages.insert(
            "u".into(),
            Stage {
                name: "u".into(),
                agent: "worker".into(),
                gates: vec!["inline".into(), "deferred".into()],
                on_pass: "none".into(),
                ..Default::default()
            },
        );

        let st = Store::open(":memory:").unwrap();
        // Run scoping (spec 06, unit 1): begin the run first so the recorded result and
        // deferred verdict below fall INSIDE the current run and are replayed on resume.
        crate::run::ensure_started(&st, &[]).unwrap();
        // The implementer result is recorded (the unit reaches `verified` and the run
        // converges), and a FAILING deferred verdict is already recorded under its replay
        // key - but the DeferredGateFailed is MISSING, exactly as a crash between the two
        // appends would leave it.
        crate::spawn::record_result(
            &st,
            &crate::spawn::SpawnResult::ok(spawn_id("u", ROLE_IMPLEMENTER, 0), "done"),
        )
        .unwrap();
        let verdict_key = deferred_gate_verdict_key("deferred");
        st.append(
            STREAM,
            ExpectedRevision::Any,
            &[Event::new(
                contextgraph::TYPE_GATE_VERDICT,
                serde_json::to_vec(&json!({"gate": "deferred", "pass": false, "evidence": "boom"}))
                    .unwrap(),
            )
            .with_meta(META_REPLAY_KEY, &verdict_key)],
        )
        .unwrap();

        // The gate runner would record any command it runs; the recorded verdict must be
        // replayed, its (whole-tree) command never re-run.
        let runner = RecordingRunner::new(&["deferred"]);
        let rs = {
            let driver = ReplayDriver::new(&st);
            let deps = Deps {
                store: &st,
                driver: &driver,
                gates: &runner,
                repo: String::new(),
                grounder: None,
                graph: None,
                criteria: Vec::new(),
            };
            run(&cfg, &deps).unwrap()
        };

        assert!(
            !runner.calls().iter().any(|c| c.as_str() == "deferred"),
            "the recorded failing deferred verdict is replayed, its command never re-run"
        );
        let count_failed = || {
            st.read_stream(STREAM, 0, Direction::Forward)
                .unwrap()
                .iter()
                .filter(|e| e.type_ == TYPE_DEFERRED_GATE_FAILED)
                .count()
        };
        assert_eq!(
            count_failed(),
            1,
            "the lost DeferredGateFailed is re-surfaced from the replayed verdict, exactly once"
        );
        assert!(
            rs.deferred_gate_failed && !rs.done() && !rs.fully_done(&[]),
            "a red deferred gate is never reported as a finished run, even after the crash"
        );

        // Re-stepping does not append a second DeferredGateFailed (it is keyed).
        {
            let driver = ReplayDriver::new(&st);
            let deps = Deps {
                store: &st,
                driver: &driver,
                gates: &runner,
                repo: String::new(),
                grounder: None,
                graph: None,
                criteria: Vec::new(),
            };
            run(&cfg, &deps).unwrap();
        }
        assert_eq!(
            count_failed(),
            1,
            "the re-surfaced DeferredGateFailed is idempotent across further replays"
        );
    }

    #[test]
    fn a_replayed_fan_out_review_reject_appends_no_duplicate_unitfailed() {
        // BLOCKER 2 (findings rf-fanout-replay-dup-unitfailed / adv-confirm-fanout-dup-
        // unitfailed): a standalone fan-out review stage that REJECTS is `Failed` (not
        // terminal), so it is re-seeded ready every step. Before the fix it restarted at
        // attempt 0 each step, re-ran the recorded rejecting adjudicator, and re-appended
        // a duplicate UnitFailed - and the escalation bound never accumulated. Seeding
        // attempts from the log (mirroring the per-unit path) makes a replay step PARK at
        // the next unrecorded review-attempt without re-emitting the recorded failure.
        use crate::driver::replay::ReplayDriver;

        let mut cfg = Config::default();
        cfg.agents.insert("judge".into(), agent("judge"));
        cfg.workflow.stages.insert(
            "rev".into(),
            Stage {
                name: "rev".into(),
                // A fan-out review stage: empty agent + fan-out strategy, one
                // adjudicator, no lenses - so the adjudicator IS the frontier spawn.
                strategy: "fan-out".into(),
                adjudicator: "judge".into(),
                ..Default::default()
            },
        );

        let st = Store::open(":memory:").unwrap();
        // Begin the run before recording (production ordering): the run-scoped replay lookup
        // answers only results inside the current run's slice.
        crate::run::ensure_started(&st, &[]).unwrap();
        // The adjudicator's attempt-0 verdict is recorded as a REJECT, so the replay
        // driver answers it (the review runs to a reject) instead of parking it.
        crate::spawn::record_result(
            &st,
            &crate::spawn::SpawnResult::ok(
                spawn_id("rev", ROLE_ADJUDICATOR, 0),
                "{\"verdict\":\"reject\"}",
            ),
        )
        .unwrap();

        let runner = RecordingRunner::new(&[]);
        let count_failed = || {
            st.read_stream(STREAM, 0, Direction::Forward)
                .unwrap()
                .iter()
                .filter(|e| e.type_ == ledger::TYPE_UNIT_FAILED)
                .count()
        };

        // Three consecutive replay steps over the SAME recorded rejecting verdict.
        for _ in 0..3 {
            let driver = ReplayDriver::new(&st);
            let deps = Deps {
                store: &st,
                driver: &driver,
                gates: &runner,
                repo: String::new(),
                grounder: None,
                graph: None,
                criteria: Vec::new(),
            };
            run(&cfg, &deps).unwrap();
        }

        assert_eq!(
            count_failed(),
            1,
            "the recorded review reject yields ONE UnitFailed across replays, not one per step"
        );
        // The bound accumulates from the log: the folded attempt count is 1 (the first
        // rejected attempt), not reset to 0 every step.
        let rs = ledger::project(&st.read_stream(STREAM, 0, Direction::Forward).unwrap()).unwrap();
        assert_eq!(
            rs.units["rev"].attempts, 1,
            "the escalation bound accumulates across steps (attempts folded from the log)"
        );
        assert_eq!(
            rs.units["rev"].status,
            ledger::Status::Failed,
            "a rejected review stage stays Failed (non-terminal), resuming on the next step"
        );
    }

    /// The current HEAD commit hash of a git repo, for asserting a lens produced no
    /// commit.
    fn git_head(repo: &str) -> String {
        let out = std::process::Command::new("git")
            .arg("-C")
            .arg(repo)
            .args(["rev-parse", "HEAD"])
            .output()
            .unwrap();
        String::from_utf8_lossy(&out.stdout).trim().to_string()
    }

    fn init_repo() -> tempfile::TempDir {
        let dir = tempfile::tempdir().unwrap();
        let p = dir.path().to_str().unwrap();
        for args in [
            &["init", "-q"][..],
            &["config", "user.email", "t@example.com"],
            &["config", "user.name", "t"],
            &["commit", "--allow-empty", "-q", "-m", "init"],
        ] {
            std::process::Command::new("git")
                .arg("-C")
                .arg(p)
                .args(args)
                .output()
                .unwrap();
        }
        dir
    }

    /// FIX 2: a gate runner that PASSES only when the worktree it is handed (`dir`)
    /// is CLEAN - `git status --porcelain` is empty. It fails on a dirty tree. So the
    /// gate passes iff the conductor committed the implementer's work BEFORE running
    /// it; if the conductor gated the dirty worktree (the false-green bug) this gate
    /// would see the uncommitted file and fail.
    struct CleanTreeGate {
        saw_dirty: std::sync::atomic::AtomicBool,
    }
    impl gate::Runner for CleanTreeGate {
        fn run(&self, _g: &Gate, dir: &str, _target: &str) -> gate::GateResult {
            let out = std::process::Command::new("git")
                .arg("-C")
                .arg(dir)
                .args(["status", "--porcelain"])
                .output()
                .unwrap();
            let porcelain = String::from_utf8_lossy(&out.stdout);
            let dirty = !porcelain.trim().is_empty();
            if dirty {
                self.saw_dirty.store(true, Ordering::SeqCst);
            }
            gate::GateResult {
                pass: !dirty,
                evidence: if dirty {
                    format!("worktree was dirty when gated: {}", porcelain.trim())
                } else {
                    "tree clean".into()
                },
            }
        }
    }

    #[test]
    fn gate_measures_the_committed_artifact_not_the_dirty_worktree() {
        // FIX 2 (the false-green): the implementer writes an uncommitted file; the
        // gate passes ONLY against a clean, committed tree. The conductor must commit
        // the worktree BEFORE gating, so the gate sees the committed artifact (clean
        // tree) and the unit integrates. If the conductor gated the dirty worktree -
        // the bug a real run hit, where `cargo test` passed on uncommitted tests that
        // never reached the committed artifact - this gate would fail and the unit
        // would never integrate.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();
        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.workflow
            .gates
            .insert("clean".into(), gate_def("unused"));
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                gates: vec!["clean".into()],
                on_pass: "merge".into(),
                ..Default::default()
            },
        );
        let st = Store::open(":memory:").unwrap();
        // The implementer writes a file but never commits it - exactly the dirty
        // worktree a real implementer leaves before integration.
        let driver = Stub {
            write_file: Some("feature.rs".into()),
            ..Stub::new()
        };
        let runner = CleanTreeGate {
            saw_dirty: std::sync::atomic::AtomicBool::new(false),
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &runner,
            repo: repo_path,
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();
        assert!(
            !runner.saw_dirty.load(Ordering::SeqCst),
            "the gate must run against a COMMITTED (clean) tree - the conductor commits before gating"
        );
        assert_eq!(
            rs.units["s"].status,
            ledger::Status::Integrated,
            "with the worktree committed before gating, the clean-tree gate passes and the unit integrates"
        );
        // The committed artifact actually landed in the repo.
        assert!(
            repo.path().join("feature.rs").exists(),
            "the committed, gated artifact must merge into the base repo"
        );
    }

    #[test]
    fn conductor_spawns_the_sdet_author_at_the_build_seam_so_its_tests_land_in_the_committed_tree()
    {
        // spec 33 done-when (this criterion OWNS the spawn placement + role token): the
        // conductor SPAWNS the `sdet-author` agent at the build seam - AFTER the
        // implementer emits green and BEFORE the pre-gate commit, in the implementer's
        // OWN worktree - resolved through the existing agent-loading path by the fixed
        // `sdet-author` id, so the periphery tests it authors are committed with the unit
        // and judged by the gates. The load-bearing, NON-VACUOUS proof of the
        // BEFORE-the-pre-gate-commit placement is assertion #5: the sdet-author writes a
        // DISTINCTIVE file no other spawn writes, and it must be ADDED in the SAME commit
        // as the implementer's diff - the pre-gate commit `git add -A` that runs before
        // the gates - so the tree the GATES judge already contains it and a FAILING
        // periphery test would redden them. Merely landing in the merged base tree proves
        // NOTHING about placement (integrate's own `git add -A` sweeps ANY dirty file in
        // regardless); being in the pre-gate commit does. Move the spawn BELOW that commit
        // and the file is added only at integrate - a LATER, different commit - so
        // assertion #5 fails.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();
        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents
            .insert(ROLE_SDET_AUTHOR.into(), agent(ROLE_SDET_AUTHOR));
        cfg.workflow.gates.insert("ok".into(), gate_def("true"));
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                gates: vec!["ok".into()],
                on_pass: "merge".into(),
                ..Default::default()
            },
        );
        let st = Store::open(":memory:").unwrap();
        // The implementer writes the unit's feature (a non-empty diff to gate); the
        // sdet-author authors a DISTINCTIVE periphery test that only it writes.
        let driver = Stub {
            write_file: Some("feature.rs".into()),
            write_file_by_agent: HashMap::from([(
                ROLE_SDET_AUTHOR.to_string(),
                "sdet_periphery_test.rs".to_string(),
            )]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();
        assert_eq!(
            rs.units["s"].status,
            ledger::Status::Integrated,
            "the unit integrates with the sdet-author's periphery tests swept into the committed tree"
        );

        // (1) The sdet-author was spawned via the existing fixed-id agent-loading path.
        assert!(
            driver.spawned(ROLE_SDET_AUTHOR),
            "the conductor must spawn the sdet-author at the build seam"
        );
        // (2) It ran in the implementer's OWN worktree (same cwd), never the main
        // checkout - so its writes are exactly the ones the pre-gate commit sweeps in.
        let impl_dir = driver.dirs_for("worker");
        let sdet_dir = driver.dirs_for(ROLE_SDET_AUTHOR);
        assert_eq!(
            sdet_dir.first(),
            impl_dir.first(),
            "the sdet-author must run in the implementer's worktree, not its own or the main repo"
        );
        // (3) It was spawned AFTER the implementer emits green (the green-then-author
        // seam), not before or in place of it.
        let order = driver.call_order.lock().unwrap().clone();
        let impl_pos = order.iter().position(|id| id == "worker");
        let sdet_pos = order.iter().position(|id| id == ROLE_SDET_AUTHOR);
        assert!(
            impl_pos < sdet_pos,
            "the sdet-author must be spawned AFTER the implementer, got order {order:?}"
        );
        // (4) Its deterministic spawn id derives from the role token (spec 33: the id is
        // `spawn_id(stage, ROLE_SDET_AUTHOR, attempt)`), so a stepwise/replay driver
        // answers or parks it exactly like the implementer.
        assert!(
            driver
                .spawn_ids()
                .iter()
                .any(|id| *id == spawn_id("s", ROLE_SDET_AUTHOR, 0)),
            "the sdet-author spawn must carry its deterministic role-token id"
        );
        // (5) NON-VACUOUS placement proof (the load-bearing half of the criterion): the
        // sdet-author's periphery test must be committed BY THE PRE-GATE COMMIT - the
        // `git add -A` the conductor runs BEFORE the gates - so the tree the gates judge
        // (and the adjudicator later inspects) already contains it and a FAILING periphery
        // test reddens them. Asserting only that the file reached the merged base tree is
        // VACUOUS: `integrate()` runs its OWN `git add -A` (worktree.rs) and sweeps any
        // residual dirty file into the merge regardless of placement, so a spawn moved
        // BELOW the pre-gate commit still lands the file. We instead assert the file was
        // ADDED in the SAME commit as the implementer's diff - they were committed together
        // by the one pre-gate commit. Move the spawn below the pre-gate commit and the
        // sdet file is added only at integrate (a LATER, DIFFERENT commit), failing this.
        let added_in = |path: &str| -> String {
            let out = std::process::Command::new("git")
                .arg("-C")
                .arg(repo.path())
                .args(["log", "--diff-filter=A", "--format=%H", "--", path])
                .output()
                .unwrap();
            String::from_utf8_lossy(&out.stdout).trim().to_string()
        };
        let feature_add = added_in("feature.rs");
        let sdet_add = added_in("sdet_periphery_test.rs");
        assert!(
            !sdet_add.is_empty(),
            "the sdet-author's authored periphery test must be committed with the unit and merged"
        );
        assert_eq!(
            sdet_add, feature_add,
            "the sdet-author's periphery test must be ADDED in the SAME pre-gate commit as the \
             implementer's diff (proving the spawn ran BEFORE the pre-gate commit); move the spawn \
             below that commit and it lands only at integrate - a later, different commit - failing this"
        );
    }

    #[test]
    fn the_sdet_author_spawn_respects_the_budget_breaker_at_its_own_spawn_site() {
        // The regression guard for the reserve_spawn mitigation at the sdet-author spawn
        // seam (this criterion's budget clause): the sdet spawn funnels through the single
        // spawn-budget mutation authority (`reserve_spawn`) exactly like the implementer
        // and every reviewer tier, so a SPENT budget REFUSES it instead of letting it spawn
        // past the breaker - keeping the cross-step budget symmetry
        // (cumulative = base_spawns + admitted-this-process) intact.
        //
        // At `defaults.budget = 1` the implementer is admitted (it reserves and spends the
        // one slot), so control reaches the sdet seam that follows; the sdet reserve is then
        // REFUSED, so the sdet-author never spawns. The load-bearing assertion is
        // `!driver.spawned(ROLE_SDET_AUTHOR)`: delete the `if self.reserve_spawn(&sdet_id)`
        // guard and the sdet spawns UNRESERVED - past the spent budget - turning it RED and
        // reopening the exact rejected unreserved-spawn defect. The flagship test above runs
        // at the default budget = 0 (unlimited), where `reserve_spawn` always admits, so it
        // cannot exercise this refusal - only a bounded budget can.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();
        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents
            .insert(ROLE_SDET_AUTHOR.into(), agent(ROLE_SDET_AUTHOR));
        cfg.workflow.gates.insert("ok".into(), gate_def("true"));
        // One spawn slot for the whole run: the implementer admits and spends it, so the
        // sdet reserve that immediately follows in the same wave must be refused.
        cfg.workflow.defaults.budget = 1;
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                gates: vec!["ok".into()],
                on_pass: "merge".into(),
                ..Default::default()
            },
        );
        let st = Store::open(":memory:").unwrap();
        // Same distinctive per-agent write as the flagship: were the sdet admitted it would
        // author `sdet_periphery_test.rs`. Here it must never run, so that file is never
        // written - the refusal is what this test pins.
        let driver = Stub {
            write_file: Some("feature.rs".into()),
            write_file_by_agent: HashMap::from([(
                ROLE_SDET_AUTHOR.to_string(),
                "sdet_periphery_test.rs".to_string(),
            )]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        // The run completes (Ok): a spent budget halts the run with a BudgetExhausted
        // record, never a raw error.
        run(&cfg, &deps).unwrap();

        // The implementer WAS admitted - it reserved the one budget slot and ran - so
        // control reached the sdet spawn seam that follows it. Without this the sdet refusal
        // below would be vacuous (the seam never reached), so it anchors the regression:
        // the seam IS exercised, and the sdet is refused AT it.
        assert!(
            driver.spawned("worker"),
            "the implementer must be admitted (spending the one budget slot) so the sdet seam is reached"
        );
        // LOAD-BEARING (the regression guard the adjudicator required): with the budget spent
        // by the implementer, the sdet reserve is REFUSED, so the sdet-author must NOT spawn -
        // it respects the breaker at its own spawn site instead of spawning past it. Delete
        // the `if self.reserve_spawn(&sdet_id)` guard at the seam and the sdet spawns
        // unreserved, past the spent budget, turning this assertion RED.
        assert!(
            !driver.spawned(ROLE_SDET_AUTHOR),
            "a spent budget must REFUSE the sdet-author reserve so it does not spawn past the breaker"
        );
        // The refusal is a genuine budget trip - the breaker binds at THIS spawn site too,
        // recorded as BudgetExhausted (never a raw error) - so a run exceeding its budget at
        // the sdet seam halts exactly like one exceeding it at the implementer or a reviewer,
        // and the single-authority budget accounting (which this reserve now funnels through)
        // stays the source of truth.
        let events = st
            .read_all(0, Direction::Forward, &Filter::default())
            .unwrap();
        assert!(
            events.iter().any(|e| e.type_ == TYPE_BUDGET_EXHAUSTED),
            "a budget spent at the sdet spawn site must trip the breaker with a BudgetExhausted record"
        );
    }

    #[test]
    fn a_parked_sdet_author_spawn_holds_the_unit_instead_of_integrating_without_its_periphery_tests(
    ) {
        // The regression guard for the sdet-author PARKED arm at the build seam (this
        // criterion OWNS only the parked arm; Ok-advancement / absent-agent / crash are the
        // next unit's). Under the REAL stepwise/replay driver the sdet-author spawn PARKS on
        // first encounter - the NORMAL first-pass path, exactly like the implementer - and the
        // conductor must UNWIND the unit cleanly (`Err(is_parked) => return Err(e)`) so a
        // later step replays its result and the periphery tests it authors DO land in the
        // committed tree the gates judge. The flagship and budget tests both use a Stub that
        // never parks, so this primary path was untested.
        //
        // Here the implementer returns a normal `Ok` (writing the unit's feature), so control
        // reaches the sdet seam; the sdet-author spawn then PARKS. The LOAD-BEARING assertion
        // is that the unit does NOT integrate: the parked arm returns BEFORE the pre-gate
        // commit, so the unit is held (`status != Integrated`) rather than swept to Integrated.
        // Swallow the arm (`Err(is_parked) => {}`) and the parked sdet is ignored - control
        // falls through to the pre-gate commit + gates + (trivially-approved empty review) +
        // integrate, and the unit reaches `Integrated` WITHOUT the sdet ever authoring its
        // periphery tests, silently defeating spec 33's core guarantee - turning this RED.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();
        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents
            .insert(ROLE_SDET_AUTHOR.into(), agent(ROLE_SDET_AUTHOR));
        cfg.workflow.gates.insert("ok".into(), gate_def("true"));
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                gates: vec!["ok".into()],
                on_pass: "merge".into(),
                ..Default::default()
            },
        );
        let st = Store::open(":memory:").unwrap();
        // The implementer writes the unit's feature and returns a normal Ok, so control flows
        // PAST the implementer's green status DOWN to the sdet seam. The sdet-author's
        // deterministic spawn id PARKS - the stepwise/replay driver signalling an unrecorded
        // frontier - so the seam's parked arm is the code under test. Were the sdet admitted it
        // would author `sdet_periphery_test.rs`; parked, it never even reaches its write.
        let driver = Stub {
            write_file: Some("feature.rs".into()),
            write_file_by_agent: HashMap::from([(
                ROLE_SDET_AUTHOR.to_string(),
                "sdet_periphery_test.rs".to_string(),
            )]),
            park_spawn_ids: std::collections::HashSet::from([spawn_id("s", ROLE_SDET_AUTHOR, 0)]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        // A parked wave unwinds cleanly (no UnitFailed, no error propagated out of `run`): the
        // step ends and a later step replays the recorded result.
        let rs = run(&cfg, &deps).unwrap();

        // ANCHOR (the seam IS reached): the implementer was admitted and ran, so control
        // reached the sdet seam that follows its green status. Without this the park assertion
        // below would be vacuous (the sdet seam never reached).
        assert!(
            driver.spawned("worker"),
            "the implementer must run so control reaches the sdet seam that follows it"
        );
        // ANCHOR (the parked arm IS the code exercised): the sdet-author spawn WAS attempted at
        // the seam - the driver recorded the call before parking it - so it is the PARKED
        // disposition, not an absent-agent skip, that this test drives.
        assert!(
            driver.spawned(ROLE_SDET_AUTHOR),
            "the sdet-author spawn must be attempted at the seam (it then parks)"
        );
        // LOAD-BEARING (the parked arm the adjudicator required covered): a parked sdet-author
        // returns BEFORE the pre-gate commit, so the unit is HELD - it does NOT integrate.
        // Swallow the parked arm (`Err(is_parked) => {}`) and the unit falls through to the
        // pre-gate commit + gates + trivially-approved empty review + integrate, reaching
        // `Integrated` WITHOUT its periphery tests - turning this assertion RED.
        assert_ne!(
            rs.units["s"].status,
            ledger::Status::Integrated,
            "a parked sdet-author must HOLD the unit (not integrate it) so a later step replays \
             the sdet and its periphery tests land in the committed tree the gates judge"
        );
        // REINFORCING: because the unit was held (never committed/merged), NO UnitIntegrated
        // event was recorded - the durable ledger agrees with the in-memory status, and a later
        // step is free to replay the sdet without a stale integrate on the record. This config
        // has the single stage "s", so ANY UnitIntegrated event would be its own.
        let events = st
            .read_all(0, Direction::Forward, &Filter::default())
            .unwrap();
        assert!(
            !events
                .iter()
                .any(|e| e.type_ == ledger::TYPE_UNIT_INTEGRATED),
            "a held (parked-sdet) unit must record no UnitIntegrated event"
        );
    }

    #[test]
    fn speculation_sdet_author_periphery_lands_in_the_committed_tree_the_gates_judge() {
        // spec 33 done-when (this criterion OWNS the spawn placement in BOTH code-building
        // lifecycles): the build seam is wired into the SPECULATION lifecycle too, not only the
        // single lane - otherwise every speculation-built unit (speculation_width > 1) would ship
        // its boundary surface UNTESTED, a silent hole in the "no boundary surface lands untested"
        // guarantee. With width 2 the conductor spawns the sdet-author PER CANDIDATE, and the
        // WINNER integrates with the sdet's periphery test ADDED in the SAME committed tree its
        // gates judged. The load-bearing, NON-VACUOUS proof is assertion #5 (same-commit), exactly
        // as in the single-lane flagship: merely reaching the merged base tree proves nothing about
        // placement (integrate's own `git add -A` sweeps any dirty file in), but being ADDED in the
        // candidate's pre-gate commit - the tree PHASE B's gates then judge - does. Drop the
        // speculation wiring and both the spawn assertion and the same-commit placement go RED.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();
        let mut cfg = spec_cfg(2);
        // The operator-provided sdet-author persona, resolved by the fixed id like every role.
        cfg.agents
            .insert(ROLE_SDET_AUTHOR.into(), agent(ROLE_SDET_AUTHOR));
        let store = Store::open(":memory:").unwrap();
        // Every isolated implementer candidate writes the unit's feature; the sdet-author writes a
        // DISTINCTIVE periphery test that only it writes, so the same-commit proof is non-vacuous.
        // The adjudicator approves so candidate 0 wins and integrates.
        let driver = Stub {
            write_file: Some("feature.rs".into()),
            write_file_by_agent: HashMap::from([(
                ROLE_SDET_AUTHOR.to_string(),
                "sdet_periphery_test.rs".to_string(),
            )]),
            output: r#"{"verdict":"approve"}"#.into(),
            ..Stub::new()
        };
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();
        assert_eq!(
            rs.units["s"].status,
            ledger::Status::Integrated,
            "the winning speculation candidate integrates with the sdet-author's periphery tests"
        );

        // (1) The sdet-author was spawned - the speculation lifecycle wires the seam too, not
        // only the single lane.
        assert!(
            driver.spawned(ROLE_SDET_AUTHOR),
            "the conductor must spawn the sdet-author in the speculation lifecycle, not only the single lane"
        );
        // (2) It was spawned PER CANDIDATE (once per lane), so WHICHEVER candidate wins ships with
        // periphery tests its gates judged - not only lane 0. Two candidates => two sdet spawns.
        assert_eq!(
            driver.spawn_count(ROLE_SDET_AUTHOR),
            2,
            "the sdet-author spawns once per candidate (K=2), so any winner ships tested"
        );
        // (3) Each candidate's sdet-author carries its OWN deterministic lane-keyed id (the budget
        // breaker counts every one), exactly like the candidate implementers.
        let ids = driver.spawn_ids();
        assert!(
            ids.contains(&spawn_id("s", ROLE_SDET_AUTHOR, 0))
                && ids.contains(&spawn_id("s", ROLE_SDET_AUTHOR, 1)),
            "each candidate's sdet-author carries its deterministic lane-keyed id"
        );
        // (4) The sdet-author ran AFTER the implementer at the seam (green-then-author), each in
        // its candidate's OWN worktree - so its writes are exactly the ones the candidate commit
        // sweeps in, never the main checkout.
        let order = driver.call_order.lock().unwrap().clone();
        let first_impl = order.iter().position(|id| id == "worker");
        let first_sdet = order.iter().position(|id| id == ROLE_SDET_AUTHOR);
        assert!(
            first_impl < first_sdet,
            "the sdet-author must be spawned AFTER the implementer at the seam, got {order:?}"
        );
        let sdet_dirs = driver.dirs_for(ROLE_SDET_AUTHOR);
        let impl_dirs = driver.dirs_for("worker");
        assert!(
            !sdet_dirs.is_empty() && sdet_dirs.iter().all(|d| impl_dirs.contains(d)),
            "each sdet-author must run in its candidate's worktree, never its own or the main repo"
        );
        // (5) NON-VACUOUS placement proof (the load-bearing half): the winner's periphery test
        // must be ADDED in the SAME commit as the winner's feature diff - the candidate's pre-gate
        // commit that PHASE B's gates then judge - so a FAILING periphery test would redden those
        // gates. Asserting only that it reached the merged base tree is VACUOUS (integrate's own
        // `git add -A` sweeps any dirty file in regardless); being ADDED in the candidate commit
        // the gates judged is the proof. Drop the speculation wiring and the sdet file is never
        // authored, so `sdet_add` is empty - RED.
        let added_in = |path: &str| -> String {
            let out = std::process::Command::new("git")
                .arg("-C")
                .arg(repo.path())
                .args(["log", "--diff-filter=A", "--format=%H", "--", path])
                .output()
                .unwrap();
            String::from_utf8_lossy(&out.stdout).trim().to_string()
        };
        let feature_add = added_in("feature.rs");
        let sdet_add = added_in("sdet_periphery_test.rs");
        assert!(
            !sdet_add.is_empty(),
            "the winning candidate's periphery test must be committed with it and merged"
        );
        assert_eq!(
            sdet_add, feature_add,
            "the sdet-author's periphery test must be ADDED in the SAME candidate commit as the \
             winner's diff (proving it landed in the committed tree the candidate's gates judged); \
             drop the speculation wiring and it is never authored, failing this"
        );
    }

    #[test]
    fn a_parked_sdet_author_in_a_speculation_candidate_holds_the_unit() {
        // The speculation counterpart of the single-lane parked-arm guard. Under the REAL stepwise
        // driver the candidate implementers park together first; on the next step they replay `Ok`
        // and control reaches the per-candidate sdet seam, where the sdet-author spawn PARKS on its
        // first encounter. The conductor must COLLECT that park (like the implementer park) and NOT
        // commit the candidate, so all candidates park together this step and a LATER step replays
        // the sdet and commits the candidate WITH its periphery. Here the implementers return a
        // normal `Ok` (reaching each sdet seam) and BOTH candidates' sdet spawns PARK, so the whole
        // group is held. The LOAD-BEARING assertion is that NO candidate integrates: swallow the
        // park (commit the candidate anyway) and a candidate integrates WITHOUT its periphery -
        // defeating the guarantee - turning this RED.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();
        let mut cfg = spec_cfg(2);
        cfg.agents
            .insert(ROLE_SDET_AUTHOR.into(), agent(ROLE_SDET_AUTHOR));
        let store = Store::open(":memory:").unwrap();
        // Implementers return normal Ok (so control reaches the sdet seam per candidate); BOTH
        // candidates' sdet spawns PARK, so the group parks together and nothing integrates. Were a
        // sdet admitted it would author `sdet_periphery_test.rs`; parked, it never reaches its write.
        let driver = Stub {
            write_file: Some("feature.rs".into()),
            write_file_by_agent: HashMap::from([(
                ROLE_SDET_AUTHOR.to_string(),
                "sdet_periphery_test.rs".to_string(),
            )]),
            output: r#"{"verdict":"approve"}"#.into(),
            park_spawn_ids: std::collections::HashSet::from([
                spawn_id("s", ROLE_SDET_AUTHOR, 0),
                spawn_id("s", ROLE_SDET_AUTHOR, 1),
            ]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &store,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        // A parked wave unwinds cleanly (no error propagated out of `run`): the step ends and a
        // later step replays the recorded result.
        let rs = run(&cfg, &deps).unwrap();

        // ANCHOR (the seam IS reached): the implementer candidates ran, so control reached the sdet
        // seam that follows each candidate's diff. Without this the park assertion is vacuous.
        assert!(
            driver.spawned("worker"),
            "the implementer candidates must run so control reaches each candidate's sdet seam"
        );
        // ANCHOR (the parked arm IS the code exercised): the sdet-author spawn WAS attempted in a
        // candidate - the driver recorded the call before parking it - so it is the PARKED
        // disposition this test drives.
        assert!(
            driver.spawned(ROLE_SDET_AUTHOR),
            "the sdet-author spawn must be attempted in a candidate (it then parks)"
        );
        // LOAD-BEARING: a parked sdet-author in a candidate HOLDS the group - the candidate is not
        // committed, so NO candidate integrates. Swallow the park (commit the candidate anyway) and
        // a candidate integrates WITHOUT its periphery, reaching Integrated - turning this RED.
        assert_ne!(
            rs.units["s"].status,
            ledger::Status::Integrated,
            "a parked sdet-author in a candidate must HOLD the unit so a later step replays the sdet \
             and its periphery tests land in the committed tree the gates judge"
        );
        // REINFORCING: because the group was held (no candidate committed/merged), NO UnitIntegrated
        // event was recorded - the durable ledger agrees with the in-memory status. This config has
        // the single stage "s", so ANY UnitIntegrated event would be its own.
        let events = store
            .read_all(0, Direction::Forward, &Filter::default())
            .unwrap();
        assert!(
            !events
                .iter()
                .any(|e| e.type_ == ledger::TYPE_UNIT_INTEGRATED),
            "a held (parked-sdet) speculation unit must record no UnitIntegrated event"
        );
        // LOAD-BEARING (the HOLD-not-ESCALATE half of the park-collect arm): a parked group must be
        // HELD for a LATER step to replay - not driven TERMINAL. `status != Integrated` and "no
        // UnitIntegrated" (above) are EQUALLY satisfied by an escalation, so they cannot tell "held
        // for replay" (correct) from "escalated terminal" (wrong): an escalated unit also never
        // integrates, yet it gets NO later step, so its periphery NEVER lands - defeating the same
        // guarantee as a swallowed park, by a different failure mode. Drop just `any_parked = true`
        // at the park-collect arm (keeping `continue`) and the all-parked group leaves `candidates`
        // empty, PHASE B runs zero, and the escalation tail fires a UnitEscalated the shipped code
        // never records. Assert NO UnitEscalated so this test RED-lights that mutation and pins the
        // unit as parked-for-replay, matching this test's own claim.
        assert!(
            !events
                .iter()
                .any(|e| e.type_ == ledger::TYPE_UNIT_ESCALATED),
            "a held (parked-sdet) speculation unit must be HELD for a later replay step, not \
             escalated terminal - so it must record no UnitEscalated event"
        );
    }

    #[test]
    fn an_empty_accounting_sdet_author_result_advances_the_build_to_commit_gates_and_integrate() {
        // spec 33 done-when (this criterion OWNS the result handling; it does NOT own the
        // spawn placement - that is the criterion above). After the sdet-author self-reports,
        // the conductor AWAITS its result and CONTINUES the lifecycle: it proceeds to the
        // pre-gate commit, the gates, the review, and integrates. The spec names two results
        // that must advance - a NORMAL result (the sdet authored periphery tests) and an
        // EMPTY-ACCOUNTING no-op (a purely-internal unit for which the sdet recorded a
        // provably-empty accounting, authoring NO periphery file). Both traverse the ONE Ok
        // arm of the seam (`Ok(_) => Ok(())`), which does NOT branch on whether the sdet
        // authored anything, so pinning that arm via the STRICTER empty-accounting flavor (the
        // sdet writes nothing) also covers the normal-result flavor the placement flagship
        // already integrates. This is c2's INDEPENDENT guard for the advance arm: it does NOT
        // assert same-commit placement (c1's assertion #5) - only that the lifecycle CONTINUES
        // past the sdet's result to a merged unit.
        //
        // NON-VACUOUS: GREEN on shipped code; RED when the Ok arm is made to NOT advance -
        // change `Ok(_) => Ok(())` to `Ok(_) => Err(parked_spawn(&sdet_id))` (treat a normal
        // result as a park) and the seam holds the unit, so it never integrates and the
        // load-bearing `status == Integrated` assertion fails.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();
        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents
            .insert(ROLE_SDET_AUTHOR.into(), agent(ROLE_SDET_AUTHOR));
        cfg.workflow.gates.insert("ok".into(), gate_def("true"));
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                gates: vec!["ok".into()],
                on_pass: "merge".into(),
                ..Default::default()
            },
        );
        let st = Store::open(":memory:").unwrap();
        // Only the IMPLEMENTER authors a file (the unit's feature, so there is a real diff to
        // commit and gate); the sdet-author authors NOTHING - the empty-accounting no-op of a
        // purely-internal unit. `write_file_by_agent` is keyed on the agent id, so leaving the
        // sdet out of it (and `write_file: None`) means its spawn returns a normal result
        // having written no periphery file at all.
        let driver = Stub {
            write_file_by_agent: HashMap::from([("worker".to_string(), "feature.rs".to_string())]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        // ANCHOR (the result-handling arm IS the code exercised, not the absent/park paths):
        // the sdet-author WAS spawned at the seam and returned a normal result. Without this the
        // advance assertion could pass via the absent-agent no-op instead of the Ok arm.
        assert!(
            driver.spawned(ROLE_SDET_AUTHOR),
            "the sdet-author must be spawned and self-report so the Ok result-handling arm is exercised"
        );
        // LOAD-BEARING: the conductor CONTINUED the lifecycle on the sdet's result - proceeding
        // to the pre-gate commit, the gates, the (trivially-approved) review, and integrate -
        // EVEN THOUGH the sdet authored nothing. An empty accounting is not a blocker: the build
        // advances exactly as it would on a normal authored result. Make the Ok arm park instead
        // of advance (`Ok(_) => Err(parked_spawn(&sdet_id))`) and the unit is held, never
        // integrating - turning this RED.
        assert_eq!(
            rs.units["s"].status,
            ledger::Status::Integrated,
            "a normal / empty-accounting sdet-author result must ADVANCE the lifecycle to a merged unit"
        );
    }

    #[test]
    fn an_absent_sdet_author_is_a_clean_no_op_and_the_build_still_integrates() {
        // spec 33 done-when (this criterion OWNS absent-agent tolerance): if no `sdet-author`
        // agent is configured, the build seam is a CLEAN NO-OP - the build proceeds exactly as
        // it did before spec 33, so an operator who has not installed the persona is NEVER
        // blocked. Here the config has the implementer but NO sdet-author agent; the unit must
        // still integrate, and the sdet must never be spawned.
        //
        // The seam is reached (a real worktree, so `dir` is non-empty - the worktree gate does
        // NOT short-circuit first), and the absent-agent arm
        // (`let Some(sdet_def) = self.cfg.agents.get(ROLE_SDET_AUTHOR) else { return Ok(()) }`)
        // is the code under test. NON-VACUOUS: GREEN on shipped code; RED when that arm is made
        // NON-tolerant - change its `return Ok(())` to `return Err(Error("no sdet-author".into()))`
        // and the absent agent propagates an error out of the seam (`spawn_sdet_author(..)?`),
        // so the unit never integrates and `status == Integrated` fails.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();
        let mut cfg = Config::default();
        // Deliberately NO sdet-author agent - the operator has not installed the persona.
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.workflow.gates.insert("ok".into(), gate_def("true"));
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                gates: vec!["ok".into()],
                on_pass: "merge".into(),
                ..Default::default()
            },
        );
        let st = Store::open(":memory:").unwrap();
        // The implementer writes the unit's feature into a REAL worktree, so `dir` is non-empty
        // and control reaches the absent-agent check (not the empty-dir short-circuit before it).
        let driver = Stub {
            write_file_by_agent: HashMap::from([("worker".to_string(), "feature.rs".to_string())]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        // ANCHOR (the absent path IS the one exercised): with no sdet-author configured the
        // conductor never spawns it - distinguishing the clean no-op from a path that spawned
        // and skipped.
        assert!(
            !driver.spawned(ROLE_SDET_AUTHOR),
            "no sdet-author is configured, so the conductor must not spawn one"
        );
        // LOAD-BEARING: the absent sdet-author is a CLEAN no-op - the build proceeds and the
        // unit integrates exactly as it did before spec 33. Make the absent arm non-tolerant
        // (`else { return Err(..) }`) and the error propagates out of the seam, holding the unit
        // - turning this RED.
        assert_eq!(
            rs.units["s"].status,
            ledger::Status::Integrated,
            "an operator without the sdet-author persona must never be blocked: the unit still integrates"
        );
    }

    #[test]
    fn a_crashed_sdet_author_spawn_does_not_block_the_build_the_lifecycle_proceeds() {
        // spec 33 result handling, crash disposition (routed to this criterion by c1:
        // d33-c1 defers the crash arm to c2, and adv-u33c1r2-crash-arm-budget-accounting-c2 +
        // adv-u33c1-crash-arm-commits-partial-writes ask c2 to STATE and pin it). A sdet-author
        // spawn that CRASHES (a non-parked spawn/opts error - a usage-limit / non-zero exit,
        // distinct from a replay PARK) must NOT block the build: the periphery tests are
        // best-effort, so a crashed sdet is tolerated exactly like an absent one - the conductor
        // proceeds to the pre-gate commit, gates, review, and integrates the implementer's unit.
        // The alternative (propagate the crash) would let one operator's flaky sdet agent wedge
        // every unit; the tolerant proceed keeps the build resilient. Under the real
        // stepwise/replay driver the sdet spawn only PARKS or replays and never returns a
        // crash-Err, so this arm is a defensive disposition, unreachable in-loop - which is why
        // proceeding (not a bespoke remediation path) is the minimal correct choice. The
        // crash-without-park budget count divergence flagged for c2 is SHARED with the
        // implementer reserve (conductor.rs), not sdet-specific, so no separate accounting is
        // owed here.
        //
        // NON-VACUOUS: GREEN on shipped code (crash swallowed, `Err(_) => Ok(())`, unit
        // integrates); RED when the crash is propagated instead - change `Err(_) => Ok(())` to
        // `Err(e) => Err(e)` and a crashed sdet errors out of the seam (`spawn_sdet_author(..)?`),
        // so the unit never integrates and `status == Integrated` fails.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();
        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents
            .insert(ROLE_SDET_AUTHOR.into(), agent(ROLE_SDET_AUTHOR));
        cfg.workflow.gates.insert("ok".into(), gate_def("true"));
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                gates: vec!["ok".into()],
                on_pass: "merge".into(),
                ..Default::default()
            },
        );
        let st = Store::open(":memory:").unwrap();
        // The implementer returns a normal Ok (writing the unit's feature), so control reaches
        // the sdet seam; the sdet-author's deterministic spawn id CRASHES (a non-parked Err),
        // exercising the crash arm. `fail_spawn_ids` crashes ONLY the sdet spawn, leaving the
        // implementer's spawn untouched.
        let driver = Stub {
            write_file_by_agent: HashMap::from([("worker".to_string(), "feature.rs".to_string())]),
            fail_spawn_ids: std::collections::HashSet::from([spawn_id("s", ROLE_SDET_AUTHOR, 0)]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        // ANCHOR (the crash arm IS the code exercised): the sdet-author spawn WAS attempted at
        // the seam - the driver recorded the call before crashing it - so it is the CRASH
        // disposition, not an absent-agent skip, that this test drives.
        assert!(
            driver.spawned(ROLE_SDET_AUTHOR),
            "the sdet-author spawn must be attempted at the seam (it then crashes)"
        );
        // LOAD-BEARING: a crashed sdet-author does NOT block the build - the conductor swallows
        // the non-parked error and proceeds to commit + gates + review + integrate, so the unit
        // reaches Integrated (the implementer's work is not held hostage to a flaky sdet). Make
        // the crash propagate (`Err(e) => Err(e)`) and the unit never integrates - turning this RED.
        assert_eq!(
            rs.units["s"].status,
            ledger::Status::Integrated,
            "a crashed sdet-author must not block the build: the lifecycle proceeds and the unit integrates"
        );
    }

    #[test]
    fn an_escalated_unit_does_not_integrate_its_code() {
        // The SAFETY invariant: a unit whose three-tier review REJECTED it (here the
        // adjudicator always rejects, so it fails 3 times and ESCALATES) must NOT have
        // its code merged onto the integration branch. Escalation means "the adversarial
        // review refused this; hand it to a human" - the work-in-progress STAYS on the
        // unit's own branch (`rigger/u/<id>`), and NOTHING fast-forwards / merges onto
        // the integration branch. A real run hit exactly this: a feat(...) commit landed
        // on the run branch even though the unit escalated, and the merged-but-rejected
        // code broke the suite.
        let repo = init_repo();
        let repo_path = repo.path().to_str().unwrap().to_string();

        // The integration branch HEAD BEFORE the run - it must be byte-for-byte
        // unchanged after an escalation (nothing merged).
        let head_before = git_head(&repo_path);

        let mut cfg = Config::default();
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("judge".into(), agent("judge"));
        cfg.workflow.gates.insert("ok".into(), gate_def("true"));
        cfg.workflow.stages.insert(
            "s".into(),
            Stage {
                name: "s".into(),
                agent: "worker".into(),
                gates: vec!["ok".into()],
                on_pass: "merge".into(),
                review: crate::config::ReviewPanel {
                    adjudicator: "judge".into(),
                    ..Default::default()
                },
                ..Default::default()
            },
        );

        let st = Store::open(":memory:").unwrap();
        // The implementer writes a file each attempt (the diff the review then judges);
        // the gates pass (`true`), so review IS reached - and the adjudicator ALWAYS
        // rejects, so the unit retries to the bound and escalates.
        let driver = Stub {
            write_file: Some("feature.rs".into()),
            output_by_agent: HashMap::from([(
                "judge".to_string(),
                r#"{"verdict":"reject","reason":"adversarial review refuses this"}"#.to_string(),
            )]),
            ..Stub::new()
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: repo_path.clone(),
            grounder: None,
            graph: None,
            criteria: Vec::new(),
        };
        let rs = run(&cfg, &deps).unwrap();

        // (c) The unit reaches the terminal ESCALATED state - the review refused it to
        // the bound and it was handed to a human.
        assert_eq!(
            rs.units["s"].status,
            ledger::Status::Escalated,
            "an always-rejected unit must escalate, not integrate"
        );

        // (a) No UnitIntegrated event for the escalated unit - it never landed.
        let events = st
            .read_all(0, Direction::Forward, &Filter::default())
            .unwrap();
        let integrated = events.iter().any(|e| {
            e.type_ == ledger::TYPE_UNIT_INTEGRATED
                && serde_json::from_slice::<Value>(&e.data)
                    .ok()
                    .and_then(|v| v.get("id").and_then(|x| x.as_str()).map(str::to_string))
                    .as_deref()
                    == Some("s")
        });
        assert!(
            !integrated,
            "an escalated unit must emit NO UnitIntegrated event - its code did not land"
        );

        // (b) The integration branch HEAD is UNCHANGED - the rejected code is NOT merged.
        // The unit's feat/work commit stays on `rigger/u/s` for a human, never on base.
        assert_eq!(
            git_head(&repo_path),
            head_before,
            "the integration branch HEAD must be UNCHANGED - nothing merges on escalation"
        );
        assert!(
            !repo.path().join("feature.rs").exists(),
            "the rejected artifact must NOT land in the base repo - it stays on the unit branch"
        );

        // The unit's durable checkpoint branch survives with its work, for the human.
        assert!(
            crate::worktree::Worktree::branch_has_work(&repo_path, &unit_branch("s")),
            "the escalated unit's work must remain on its own branch for a human to inspect"
        );
    }

    // --- Unit 1 (spec 10): the adversarial plan-critique gate ---

    /// A spec-driven workflow with the plan-critique gate wired between `plan` and the
    /// fan-out `implement` template: `plan` produces the DAG, `plan-critique` reviews it
    /// with an adversary + adjudicator (no lenses, per the spec), and `implement` fans
    /// out only after the gate releases. The caller supplies the driver.
    fn critique_cfg() -> Config {
        let mut cfg = Config::default();
        cfg.agents.insert("planner".into(), agent("planner"));
        cfg.agents.insert("worker".into(), agent("worker"));
        cfg.agents.insert("adversary".into(), agent("adversary"));
        cfg.agents.insert("judge".into(), agent("judge"));
        cfg.workflow.gates.insert("ok".into(), gate_def("true"));
        cfg.workflow.stages.insert(
            "plan".into(),
            Stage {
                name: "plan".into(),
                agent: "planner".into(),
                produces: "dag".into(),
                ..Default::default()
            },
        );
        cfg.workflow.stages.insert(
            "plan-critique".into(),
            Stage {
                name: "plan-critique".into(),
                needs: vec!["plan".into()],
                adversary: "adversary".into(),
                adjudicator: "judge".into(),
                ..Default::default()
            },
        );
        cfg.workflow.stages.insert(
            "implement".into(),
            Stage {
                name: "implement".into(),
                agent: "worker".into(),
                strategy: "fan-out".into(),
                needs: vec!["plan-critique".into()],
                gates: vec!["ok".into()],
                on_pass: "merge".into(),
                ..Default::default()
            },
        );
        cfg
    }

    /// A driver whose adjudicator DRAWS its verdict from the conductor's own rule-6
    /// detection: it REJECTS a DAG whose critique prompt surfaces a shared-blast-radius
    /// conflict, and APPROVES one that does not - so the reject is a CONSEQUENCE of the
    /// split, not a blind script. The planner replays a fixed set of UnitProposed emits
    /// on every spawn (its original wave spawn and each critique-driven re-plan), and
    /// every other reviewer returns a benign non-empty result.
    struct CritiqueDriver {
        planner: String,
        adjudicator: String,
        plan_emits: Vec<(String, Value)>,
        // The adjudicator's verdict, modelled directly: the gate rejects a decomposition
        // for a rule 7/8 defect (ownership/disposition) - a JUDGMENT, not a mechanical
        // blast-radius trip. These flags drive the verdict independently of blast-radius
        // overlap (which no longer drives the gate at all): `reject_dag` rejects the first
        // DAG then approves the revision; `reject_always` never approves (models an
        // unresolvable defect that escalates).
        reject_dag: bool,
        reject_always: bool,
        calls: Mutex<Vec<String>>,
        adj_prompts: Mutex<Vec<String>>,
        /// Every prompt the PLANNER was spawned with, in spawn order: the first is the
        /// initial decomposition prompt, each later one is a critique-driven re-plan
        /// (re-emit) prompt. Lets a test assert the refine directive the conductor gives
        /// the planner on a re-emit (spec 31, the id-reuse instruction).
        planner_prompts: Mutex<Vec<String>>,
    }
    impl CritiqueDriver {
        fn new(plan_emits: Vec<(String, Value)>) -> Self {
            CritiqueDriver {
                planner: "planner".into(),
                adjudicator: "judge".into(),
                plan_emits,
                reject_dag: false,
                reject_always: false,
                calls: Mutex::new(Vec::new()),
                adj_prompts: Mutex::new(Vec::new()),
                planner_prompts: Mutex::new(Vec::new()),
            }
        }
        /// A driver whose adjudicator REJECTS the DAG (models a rule 7/8 ownership or
        /// open-disposition defect the gate must catch), then approves the revised DAG.
        fn rejecting(plan_emits: Vec<(String, Value)>) -> Self {
            CritiqueDriver {
                reject_dag: true,
                ..Self::new(plan_emits)
            }
        }
        /// A driver whose adjudicator NEVER approves (models an unresolvable rule 7/8
        /// defect): the planner re-plans to the retry bound and the gate escalates.
        fn always_rejecting(plan_emits: Vec<(String, Value)>) -> Self {
            CritiqueDriver {
                reject_always: true,
                ..Self::new(plan_emits)
            }
        }
        fn count(&self, id: &str) -> usize {
            self.calls
                .lock()
                .unwrap()
                .iter()
                .filter(|c| *c == id)
                .count()
        }
    }
    impl AgentDriver for CritiqueDriver {
        fn spawn(
            &self,
            a: &AgentDef,
            prompt: &str,
            _opts: &SpawnOpts,
            emit: &dyn Fn(&str, Value) -> Result<(), Error>,
        ) -> Result<AgentResult, Error> {
            self.calls.lock().unwrap().push(a.id.clone());
            if a.id == self.planner {
                self.planner_prompts
                    .lock()
                    .unwrap()
                    .push(prompt.to_string());
                for (t, v) in &self.plan_emits {
                    emit(t, v.clone())?;
                }
                return Ok(AgentResult {
                    output: "proposed the DAG".into(),
                    resolved_model: String::new(),
                });
            }
            if a.id == self.adjudicator {
                self.adj_prompts.lock().unwrap().push(prompt.to_string());
                // The verdict models a rule 7/8 JUDGMENT (ownership/disposition), NOT a
                // mechanical blast-radius trip: a rejecting driver rejects the first DAG
                // and approves the planner's revision; otherwise it approves. Blast-radius
                // overlap never drives this - the partitioner handles overlap safely.
                let already_rejected = self
                    .calls
                    .lock()
                    .unwrap()
                    .iter()
                    .filter(|c| c.as_str() == self.adjudicator)
                    .count()
                    > 1;
                let verdict = if self.reject_always || (self.reject_dag && !already_rejected) {
                    "reject"
                } else {
                    "approve"
                };
                return Ok(AgentResult {
                    output: format!("{{\"verdict\":\"{verdict}\"}}"),
                    resolved_model: String::new(),
                });
            }
            // The adversary (or any other reviewer) emits nothing and returns benignly.
            Ok(AgentResult {
                output: format!("{} reviewed the DAG", a.id),
                resolved_model: String::new(),
            })
        }
    }

    #[test]
    fn a_blast_radius_overlap_alone_does_not_reject() {
        // Architecture alignment (2026-07-07): a shared blast radius is NOT a defect. The
        // reference architecture handles overlap with `partition: by-blast-radius` ->
        // disjoint sequential batches ("safe parallelism"), so the plan-critique gate must
        // NOT reject two units merely for touching the same file - it judges cross-unit
        // ownership (rule 7) and open dispositions (rule 8), which the partitioner and
        // per-unit review do not cover.
        let dir = tempfile::tempdir().unwrap();
        let criterion = "the widget renderer is implemented";
        // The one file both units ground to: the grep grounder matches the whole
        // criterion text as a line, so two units citing the SAME criterion resolve to the
        // SAME blast radius - the canonical shared-blast-radius split.
        std::fs::write(
            dir.path().join("feature.rs"),
            format!("// {criterion}\nfn render() {{}}\n"),
        )
        .unwrap();
        let cfg = critique_cfg();
        let st = Store::open(":memory:").unwrap();
        // The planner splits the single criterion into TWO units - both citing it, so
        // both ground to feature.rs and SHARE the entire blast radius. This is NOT a
        // defect: `partition: by-blast-radius` serializes them into sequential batches
        // and per-unit worktree isolation keeps each reviewer on its own diff, so overlap
        // integrates cleanly. The gate (no ownership/disposition defect here) APPROVES and
        // the fan-out releases - the architecture-aligned behavior (overlap != reject).
        let driver = CritiqueDriver::new(vec![
            (
                TYPE_UNIT_PROPOSED.to_string(),
                json!({"id":"u-a","agent":"worker","criterion":criterion,"needs":["plan-critique"]}),
            ),
            (
                TYPE_UNIT_PROPOSED.to_string(),
                json!({"id":"u-b","agent":"worker","criterion":criterion,"needs":["plan-critique"]}),
            ),
        ]);
        let grep = crate::grounder::Grep {
            root: dir.path().to_string_lossy().into_owned(),
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: Some(&grep),
            graph: None,
            criteria: vec![criterion.to_string()],
        };
        let rs = run(&cfg, &deps).unwrap();

        // The gate APPROVED despite the shared blast radius (overlap is not a defect).
        assert_eq!(
            rs.units["plan-critique"].status,
            ledger::Status::Integrated,
            "a shared blast radius alone must NOT reject - the partitioner serializes it"
        );
        // The fan-out released: the overlapping units run (the partitioner serializes them
        // into separate batches, so they integrate cleanly).
        assert!(
            driver.count("worker") >= 1,
            "the fan-out must release on approve; worker ran {}x",
            driver.count("worker")
        );
        // No re-plan: an approve on the first pass means the planner runs exactly once.
        assert_eq!(
            driver.count("planner"),
            1,
            "no reject means no re-plan; planner ran {}x",
            driver.count("planner")
        );
    }

    #[test]
    fn a_rule_7_or_8_defect_rejects_then_releases_on_the_revision() {
        // The gate's REAL value: a cross-unit ownership (rule 7) or open-disposition (rule
        // 8) defect - which per-unit review cannot see and the partitioner does not address
        // - draws a reject that feeds back to the planner; the revised DAG then approves and
        // releases. Modelled with a rejecting adjudicator (rule 7/8 is a judgment, not a
        // mechanical trip), independent of blast radius.
        let dir = tempfile::tempdir().unwrap();
        let crit = "the alpha module is implemented";
        std::fs::write(dir.path().join("alpha.rs"), format!("// {crit}\n")).unwrap();
        let cfg = critique_cfg();
        let st = Store::open(":memory:").unwrap();
        let driver = CritiqueDriver::rejecting(Vec::new());
        let grep = crate::grounder::Grep {
            root: dir.path().to_string_lossy().into_owned(),
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: Some(&grep),
            graph: None,
            criteria: vec![crit.to_string()],
        };
        let rs = run(&cfg, &deps).unwrap();

        // The reject fed back to the planner (re-plan), then the revised DAG approved.
        assert!(
            driver.count("planner") > 1,
            "a rule 7/8 reject must feed back to the planner; planner ran {}x",
            driver.count("planner")
        );
        assert_eq!(
            rs.units["plan-critique"].status,
            ledger::Status::Integrated,
            "the gate approves the revised DAG and releases the fan-out"
        );
    }

    #[test]
    fn a_clean_decomposition_approves_and_releases_the_fan_out() {
        // The approve path: a decomposition whose units have DISJOINT blast radii draws
        // no rule-6 conflict, so the adjudicator approves and the fan-out releases - the
        // implementers run and integrate.
        let dir = tempfile::tempdir().unwrap();
        let crit_a = "the alpha module is implemented";
        let crit_b = "the beta module is implemented";
        // Disjoint files: crit_a -> alpha.rs, crit_b -> beta.rs (no overlap).
        std::fs::write(dir.path().join("alpha.rs"), format!("// {crit_a}\n")).unwrap();
        std::fs::write(dir.path().join("beta.rs"), format!("// {crit_b}\n")).unwrap();
        let cfg = critique_cfg();
        let st = Store::open(":memory:").unwrap();
        // The planner proposes nothing to refine; the conductor's per-criterion baselines
        // (one per criterion, disjoint radii) stand.
        let driver = CritiqueDriver::new(Vec::new());
        let grep = crate::grounder::Grep {
            root: dir.path().to_string_lossy().into_owned(),
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: Some(&grep),
            graph: None,
            criteria: vec![crit_a.to_string(), crit_b.to_string()],
        };
        let rs = run(&cfg, &deps).unwrap();

        // The gate approved (one adjudicator pass, no re-plan) and integrated.
        assert_eq!(
            rs.units["plan-critique"].status,
            ledger::Status::Integrated,
            "a clean DAG approves and the gate integrates (review-only, no artifact)"
        );
        assert_eq!(
            driver.count("planner"),
            1,
            "no reject means no re-plan; the planner runs exactly once"
        );
        // The gate really reviewed the DAG (the adjudicator rendered the approve).
        assert!(
            driver.count("judge") >= 1,
            "the gate must run the adjudicator to render its verdict, not approve trivially"
        );
        // The fan-out released: the implementer ran for each baseline unit.
        assert!(
            driver.count("worker") >= 2,
            "the fan-out releases on approve; worker ran {}x",
            driver.count("worker")
        );
    }

    #[test]
    fn the_gate_critiques_only_not_yet_run_units_and_approves() {
        // The critique excludes already-integrated and terminal units (`dag_unit_blast_radii`):
        // a settled unit is not a decomposition candidate, so it never clutters the critique
        // context. Combined with the architecture alignment (overlap is not a defect - the
        // partitioner serializes it), a run that adopts a prior wave's integrated unit and
        // grounds a fresh pending unit to the SAME file approves cleanly and releases the
        // fan-out (the exact spec-10 resume scenario, now handled at the root).
        let dir = tempfile::tempdir().unwrap();
        let crit_a = "the shared alpha behavior is implemented";
        let crit_b = "the shared beta behavior is implemented";
        // BOTH criteria ground to the SAME file (overlapping blast radius): shared.rs
        // mentions both criterion strings, so the grep grounder returns it for each.
        std::fs::write(
            dir.path().join("shared.rs"),
            format!("// {crit_a}\n// {crit_b}\n"),
        )
        .unwrap();
        let cfg = critique_cfg();
        let st = Store::open(":memory:").unwrap();

        // Seed the run so crit_a's baseline is ALREADY INTEGRATED. The RunStarted carries
        // the same criteria this run drives, so ensure_started ADOPTS it (no new run) and
        // the fold sees the integration in scope.
        let baseline_a = unit_slug(1, crit_a);
        st.append(
            STREAM,
            ExpectedRevision::Any,
            &[
                Event::new(
                    crate::run::TYPE_RUN_STARTED,
                    serde_json::to_vec(&json!({
                        "run": "run-resume-fixture",
                        "criteria": [crit_a, crit_b],
                    }))
                    .unwrap(),
                ),
                Event::new(
                    ledger::TYPE_UNIT_STARTED,
                    serde_json::to_vec(&json!({"id": baseline_a})).unwrap(),
                ),
                Event::new(
                    ledger::TYPE_UNIT_INTEGRATED,
                    serde_json::to_vec(&json!({"id": baseline_a, "commit": "prior-wave"})).unwrap(),
                ),
            ],
        )
        .unwrap();

        let driver = CritiqueDriver::new(Vec::new());
        let grep = crate::grounder::Grep {
            root: dir.path().to_string_lossy().into_owned(),
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: Some(&grep),
            graph: None,
            criteria: vec![crit_a.to_string(), crit_b.to_string()],
        };
        let rs = run(&cfg, &deps).unwrap();

        // The gate APPROVED (integrated, review-only) rather than escalating on a false
        // integrated-vs-pending duplicate.
        assert_eq!(
            rs.units["plan-critique"].status,
            ledger::Status::Integrated,
            "the gate must approve: an integrated unit is not a duplicate it can flag"
        );
        assert_eq!(
            rs.units[&baseline_a].status,
            ledger::Status::Integrated,
            "the seeded prior-wave unit stays integrated, untouched"
        );
    }

    #[test]
    fn the_plan_critique_prompt_names_the_cross_unit_rules() {
        // The gate prompt must NAME its review targets: mitigation ownership (rule 7) and
        // open dispositions (rule 8) as REJECT criteria, plus the shared-blast-radius note
        // (informational - the partitioner serializes overlap; not a reject trigger).
        let dir = tempfile::tempdir().unwrap();
        let criterion = "the widget renderer is implemented";
        std::fs::write(dir.path().join("feature.rs"), format!("// {criterion}\n")).unwrap();
        let cfg = critique_cfg();
        let st = Store::open(":memory:").unwrap();
        let driver = CritiqueDriver::new(vec![(
            TYPE_UNIT_PROPOSED.to_string(),
            json!({"id":"u-a","agent":"worker","criterion":criterion,"needs":["plan-critique"]}),
        )]);
        let grep = crate::grounder::Grep {
            root: dir.path().to_string_lossy().into_owned(),
        };
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: Some(&grep),
            graph: None,
            criteria: vec![criterion.to_string()],
        };
        let _ = run(&cfg, &deps).unwrap();

        let prompts = driver.adj_prompts.lock().unwrap();
        let prompt = prompts
            .first()
            .expect("the adjudicator must have been spawned");
        for target in ["blast radius", "mitigation", "disposition"] {
            assert!(
                prompt.to_lowercase().contains(target),
                "the plan-critique prompt must name rule targets ({target:?}); got:\n{prompt}"
            );
        }
    }

    #[test]
    fn the_critique_gate_never_enters_a_wave_even_when_ready() {
        // Regression pin for the adopted-run crash (lesson-plan-critique-996e0010): a
        // gate left verified-but-not-integrated by an interrupted step satisfies
        // ready_stages (its producer integrated, itself non-terminal), but a wave
        // driving it through run_single_stage's standalone-review path spawns lenses
        // with no worktree. wave_ready must exclude the gate UNCONDITIONALLY - it is
        // the producer prelude's to run, never a wave's.
        let cfg = critique_cfg();
        let stages = cfg.workflow.stages.clone();
        let mut integrated = HashSet::new();
        integrated.insert("plan".to_string());
        let terminal: HashSet<String> = integrated.clone();

        let raw = ready_stages(&stages, &integrated, &terminal);
        assert!(
            raw.iter().any(|n| n == "plan-critique"),
            "precondition: the raw ready set must surface the gate for this pin to bite; got {raw:?}"
        );
        let gate = critique_gate_name(&stages);
        let wave = wave_ready(&stages, &integrated, &terminal, gate.as_deref());
        assert!(
            !wave.iter().any(|n| n == "plan-critique"),
            "the critique gate must never be wave-scheduled; got {wave:?}"
        );
    }

    #[test]
    fn a_resolved_plan_critique_gate_does_not_re_run_on_resume() {
        // Resume-safety: once the gate has RESOLVED (approved + integrated in a prior
        // step), a later step reads that from the log and releases the fan-out directly -
        // it must NOT re-spawn its reviewers or re-emit its integration. Two run() calls
        // over ONE store model the stepwise resume (the second adopts the first's run).
        let dir = tempfile::tempdir().unwrap();
        let crit = "the alpha module is implemented";
        std::fs::write(dir.path().join("alpha.rs"), format!("// {crit}\n")).unwrap();
        let cfg = critique_cfg();
        let st = Store::open(":memory:").unwrap();
        let grep = crate::grounder::Grep {
            root: dir.path().to_string_lossy().into_owned(),
        };

        // First run: the gate approves and the fan-out integrates.
        let d1 = CritiqueDriver::new(Vec::new());
        let deps1 = Deps {
            store: &st,
            driver: &d1,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: Some(&grep),
            graph: None,
            criteria: vec![crit.to_string()],
        };
        let rs1 = run(&cfg, &deps1).unwrap();
        assert_eq!(
            rs1.units["plan-critique"].status,
            ledger::Status::Integrated
        );
        assert!(
            d1.count("judge") >= 1,
            "the first run must run the adjudicator"
        );

        // Second run over the SAME store (a resume): the gate is already resolved.
        let d2 = CritiqueDriver::new(Vec::new());
        let deps2 = Deps {
            store: &st,
            driver: &d2,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: Some(&grep),
            graph: None,
            criteria: vec![crit.to_string()],
        };
        let rs2 = run(&cfg, &deps2).unwrap();
        assert_eq!(
            d2.count("judge"),
            0,
            "a resolved gate must NOT re-spawn its adjudicator on resume"
        );
        assert_eq!(
            d2.count("planner"),
            0,
            "a resumed run over a settled DAG must not re-run the planner"
        );
        assert_eq!(
            rs2.units["plan-critique"].status,
            ledger::Status::Integrated
        );
        // Exactly ONE plan-critique UnitIntegrated across the resume - no duplicate.
        let events = st.read_stream(STREAM, 0, Direction::Forward).unwrap();
        let integrated = events
            .iter()
            .filter(|e| {
                e.type_ == ledger::TYPE_UNIT_INTEGRATED
                    && String::from_utf8_lossy(&e.data).contains("plan-critique")
            })
            .count();
        assert_eq!(
            integrated, 1,
            "the gate must integrate exactly once across the resume, not re-emit"
        );
    }

    #[test]
    fn a_resumed_step_holds_the_fan_out_while_the_plan_critique_gate_is_escalated() {
        // The resume-hold arm the approve-only resume test cannot reach (spec 10,
        // done-when 1: ONLY an approve releases the wave). A real planner follows
        // PLAN_PROTOCOL - its proposed units' `needs` name sibling unit ids, NEVER the
        // gate - so it emits the split with `needs:[]`. Two run() over ONE store model
        // the stepwise resume the production `rigger step` path runs on: run 1 the gate
        // ESCALATES (its adjudicator never approves the shared-blast-radius split); run 2
        // resumes over that settled, TERMINAL-but-not-integrated gate. The fan-out must
        // stay HELD across the resume - a step after an escalation must NOT implement the
        // decomposition three reviews rejected, the exact harm the gate exists to prevent.
        let dir = tempfile::tempdir().unwrap();
        let criterion = "the widget renderer is implemented";
        std::fs::write(
            dir.path().join("feature.rs"),
            format!("// {criterion}\nfn render() {{}}\n"),
        )
        .unwrap();
        let cfg = critique_cfg();
        let st = Store::open(":memory:").unwrap();
        let grep = crate::grounder::Grep {
            root: dir.path().to_string_lossy().into_owned(),
        };
        // PLAN_PROTOCOL shape: the split units carry `needs:[]` (only sibling ids ever
        // appear here, never the gate) - the exact shape that bypassed the pre-gate wave.
        let split = || {
            vec![
                (
                    TYPE_UNIT_PROPOSED.to_string(),
                    json!({"id":"u-a","agent":"worker","criterion":criterion,"needs":[]}),
                ),
                (
                    TYPE_UNIT_PROPOSED.to_string(),
                    json!({"id":"u-b","agent":"worker","criterion":criterion,"needs":[]}),
                ),
            ]
        };

        // Run 1: the gate escalates (an unresolvable rule 7/8 defect - modelled by an
        // always-rejecting adjudicator, since blast-radius overlap no longer rejects); the
        // fan-out is held (no worker runs).
        let d1 = CritiqueDriver::always_rejecting(split());
        let deps1 = Deps {
            store: &st,
            driver: &d1,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: Some(&grep),
            graph: None,
            criteria: vec![criterion.to_string()],
        };
        let rs1 = run(&cfg, &deps1).unwrap();
        assert_eq!(
            rs1.units["plan-critique"].status,
            ledger::Status::Escalated,
            "run 1: an unresolvable rule 7/8 defect must escalate the gate"
        );
        assert_eq!(
            d1.count("worker"),
            0,
            "run 1: no implementer runs while the gate is unresolved; calls: {:?}",
            d1.calls.lock().unwrap()
        );

        // Run 2 over the SAME store (the resume): the gate is terminal-but-not-integrated.
        let d2 = CritiqueDriver::new(split());
        let deps2 = Deps {
            store: &st,
            driver: &d2,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: Some(&grep),
            graph: None,
            criteria: vec![criterion.to_string()],
        };
        let _ = run(&cfg, &deps2).unwrap();
        // The resume short-circuit correctly does NOT re-run the gate...
        assert_eq!(
            d2.count("judge"),
            0,
            "resume: an already-resolved (escalated) gate must not re-spawn its adjudicator"
        );
        // ...and, critically, the pre-gate planning wave must NOT fan the rejected units
        // out. This is the blocker: before the fix, `harvest_proposed` folds the prior
        // window's proposals (needs:[]) as READY and the pre-gate wave runs them BEFORE
        // the terminal-hold arm ever fires.
        assert_eq!(
            d2.count("worker"),
            0,
            "resume: the fan-out must stay HELD over an ESCALATED gate; workers ran: {:?}",
            d2.calls.lock().unwrap()
        );
    }

    #[test]
    fn an_approved_gate_releases_planner_proposed_units_not_only_baselines() {
        // The release direction of the same hold (spec 10, done-when 1: an approve
        // RELEASES the wave). The fix gives PLANNER-proposed units the gate as a
        // dependency; this pins that the dependency is SATISFIED on approve, so a proposed
        // unit (not only a conductor baseline) fans out once the gate integrates. The
        // planner proposes two DISJOINT units (each `needs:[]`, the PLAN_PROTOCOL shape),
        // superseding the baselines; disjoint blast radii draw no rule-6 conflict, the
        // adjudicator approves, and BOTH proposed implementers run.
        let dir = tempfile::tempdir().unwrap();
        let crit_a = "the alpha module is implemented";
        let crit_b = "the beta module is implemented";
        std::fs::write(dir.path().join("alpha.rs"), format!("// {crit_a}\n")).unwrap();
        std::fs::write(dir.path().join("beta.rs"), format!("// {crit_b}\n")).unwrap();
        let cfg = critique_cfg();
        let st = Store::open(":memory:").unwrap();
        let grep = crate::grounder::Grep {
            root: dir.path().to_string_lossy().into_owned(),
        };
        let driver = CritiqueDriver::new(vec![
            (
                TYPE_UNIT_PROPOSED.to_string(),
                json!({"id":"u-a","agent":"worker","criterion":crit_a,"needs":[]}),
            ),
            (
                TYPE_UNIT_PROPOSED.to_string(),
                json!({"id":"u-b","agent":"worker","criterion":crit_b,"needs":[]}),
            ),
        ]);
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: Some(&grep),
            graph: None,
            criteria: vec![crit_a.to_string(), crit_b.to_string()],
        };
        let rs = run(&cfg, &deps).unwrap();

        assert_eq!(
            rs.units["plan-critique"].status,
            ledger::Status::Integrated,
            "a disjoint decomposition approves and the gate integrates"
        );
        assert_eq!(
            driver.count("planner"),
            1,
            "no reject means no re-plan; the planner runs exactly once"
        );
        // The proposed units - held behind the gate by the fix - release on approve.
        assert_eq!(
            driver.count("worker"),
            2,
            "an approve releases the PROPOSED fan-out units; workers ran: {:?}",
            driver.calls.lock().unwrap()
        );
    }

    #[test]
    fn the_re_plan_directive_instructs_reusing_the_existing_unit_id() {
        // Spec 31, done-when 4 (c4): the plan-critique / re-emit prompt the conductor
        // generates must tell the planner to re-emit a REFINEMENT under the EXACT
        // existing unit-id (which now updates that unit in place, spec 31 change 1) and
        // to mint a NEW id only for a genuinely new/split unit. This closes the id-change
        // that made a refine re-emit deterministically fatal (a same-id skip or a
        // duplicate-per-criterion escalation the loop could not clear).
        //
        // We drive the REAL re_plan path (not a hand-copied literal): a rejecting
        // adjudicator forces a plan-critique reject, so the conductor re-plans - spawning
        // the planner a SECOND time with the generated re-emit prompt - then approves the
        // revision. The captured re-plan prompt must carry the id-reuse directive.
        let dir = tempfile::tempdir().unwrap();
        let criterion = "the widget renderer is implemented";
        std::fs::write(dir.path().join("feature.rs"), format!("// {criterion}\n")).unwrap();
        let cfg = critique_cfg();
        let st = Store::open(":memory:").unwrap();
        let grep = crate::grounder::Grep {
            root: dir.path().to_string_lossy().into_owned(),
        };
        // The planner re-emits the SAME id on the re-plan (a refinement, the spec-31
        // path): change 1 folds it in place, so the revised DAG has one unit per
        // criterion and the second critique approves.
        let driver = CritiqueDriver::rejecting(vec![(
            TYPE_UNIT_PROPOSED.to_string(),
            json!({"id":"u-a","agent":"worker","criterion":criterion,"needs":[]}),
        )]);
        let deps = Deps {
            store: &st,
            driver: &driver,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: Some(&grep),
            graph: None,
            criteria: vec![criterion.to_string()],
        };
        let _ = run(&cfg, &deps).unwrap();

        // The reject drove a re-plan: the planner ran twice (initial + re-emit).
        assert_eq!(
            driver.count("planner"),
            2,
            "a plan-critique reject must re-plan; the planner runs its initial + re-emit prompt"
        );
        let planner_prompts = driver.planner_prompts.lock().unwrap();
        let re_plan_prompt = planner_prompts
            .get(1)
            .expect("the conductor must generate a re-plan (re-emit) prompt on a reject");
        // Sanity: this is the re-emit directive, not the initial plan prompt.
        assert!(
            re_plan_prompt.contains("REJECTED your previous decomposition"),
            "the second planner prompt is the plan-critique re-emit directive; got:\n{re_plan_prompt}"
        );
        // The refine directive: re-emit under the EXACT existing id updates in place.
        assert!(
            re_plan_prompt.contains("re-emit it under its EXACT existing unit-id"),
            "the re-emit directive must tell the planner to refine under the existing unit-id; got:\n{re_plan_prompt}"
        );
        assert!(
            re_plan_prompt.contains("in place"),
            "the re-emit directive must state a same-id re-emit UPDATES the unit in place; got:\n{re_plan_prompt}"
        );
        // ...and a NEW id is only for a genuinely new/split unit.
        assert!(
            re_plan_prompt.contains("use a NEW unit-id ONLY for a genuinely"),
            "the re-emit directive must reserve a NEW id for a genuinely new/split unit; got:\n{re_plan_prompt}"
        );
    }

    /// A driver that answers the PLANNER (emitting a shared-blast-radius split in the
    /// real PLAN_PROTOCOL `needs:[]` shape) but PARKS every reviewer, so the plan-critique
    /// gate stays UNRESOLVED (mid-review) across a step boundary - the stepwise shape
    /// where the gate's adversary and adjudicator each take their own `rigger step`. Any
    /// implementer (`worker`) spawn is recorded via `calls` before it parks, so a fan-out
    /// that leaks before the gate resolves is detected even though the worker never runs.
    struct ParkingGateDriver {
        plan_emits: Vec<(String, Value)>,
        calls: Mutex<Vec<String>>,
    }
    impl ParkingGateDriver {
        fn new(plan_emits: Vec<(String, Value)>) -> Self {
            ParkingGateDriver {
                plan_emits,
                calls: Mutex::new(Vec::new()),
            }
        }
        fn count(&self, id: &str) -> usize {
            self.calls
                .lock()
                .unwrap()
                .iter()
                .filter(|c| *c == id)
                .count()
        }
    }
    impl AgentDriver for ParkingGateDriver {
        fn spawn(
            &self,
            a: &AgentDef,
            _prompt: &str,
            opts: &SpawnOpts,
            emit: &dyn Fn(&str, Value) -> Result<(), Error>,
        ) -> Result<AgentResult, Error> {
            self.calls.lock().unwrap().push(a.id.clone());
            if a.id == "planner" {
                for (t, v) in &self.plan_emits {
                    emit(t, v.clone())?;
                }
                return Ok(AgentResult {
                    output: "proposed the DAG".into(),
                    resolved_model: String::new(),
                });
            }
            // Every reviewer (and any leaked implementer) parks: the gate never renders a
            // verdict, so it stays unresolved (mid-review) across the resume.
            Err(parked_spawn(&opts.id))
        }
    }

    #[test]
    fn a_resumed_step_holds_the_fan_out_while_the_plan_critique_gate_is_mid_review() {
        // The OTHER held arm (spec 10, done-when 1): a gate parked MID-REVIEW - the
        // stepwise dogfood shape where plan integrates on step 1 and the gate's reviewers
        // park across later steps. On the resume the gate is neither integrated NOR
        // terminal (its verdict is unrendered), so the fan-out must stay held. Before the
        // fix the pre-gate planning wave folds the prior window's proposals (needs:[]) as
        // ready and runs the implementers BEFORE the gate re-reaches its (still parked)
        // adjudicator - fanning out over a decomposition NO reviewer has approved.
        let dir = tempfile::tempdir().unwrap();
        let criterion = "the widget renderer is implemented";
        std::fs::write(
            dir.path().join("feature.rs"),
            format!("// {criterion}\nfn render() {{}}\n"),
        )
        .unwrap();
        let cfg = critique_cfg();
        let st = Store::open(":memory:").unwrap();
        let grep = crate::grounder::Grep {
            root: dir.path().to_string_lossy().into_owned(),
        };
        let split = || {
            vec![
                (
                    TYPE_UNIT_PROPOSED.to_string(),
                    json!({"id":"u-a","agent":"worker","criterion":criterion,"needs":[]}),
                ),
                (
                    TYPE_UNIT_PROPOSED.to_string(),
                    json!({"id":"u-b","agent":"worker","criterion":criterion,"needs":[]}),
                ),
            ]
        };

        // Run 1: the planner emits the split, then the gate parks mid-review.
        let d1 = ParkingGateDriver::new(split());
        let deps1 = Deps {
            store: &st,
            driver: &d1,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: Some(&grep),
            graph: None,
            criteria: vec![criterion.to_string()],
        };
        run(&cfg, &deps1).unwrap();
        assert_eq!(
            d1.count("worker"),
            0,
            "run 1: no implementer runs while the gate is mid-review; calls: {:?}",
            d1.calls.lock().unwrap()
        );

        // Run 2 over the SAME store (the resume): the gate is STILL unresolved (its
        // verdict was never recorded), so the fan-out must remain held.
        let d2 = ParkingGateDriver::new(split());
        let deps2 = Deps {
            store: &st,
            driver: &d2,
            gates: &ExecRunner,
            repo: String::new(),
            grounder: Some(&grep),
            graph: None,
            criteria: vec![criterion.to_string()],
        };
        run(&cfg, &deps2).unwrap();
        assert_eq!(
            d2.count("worker"),
            0,
            "resume: the fan-out must stay HELD while the gate is mid-review; workers: {:?}",
            d2.calls.lock().unwrap()
        );
    }
